globalThis.__BQ = {"ayristiricilar":{"ilkokul":{"kolay":[{"q":"Ölen bir yaprağı ya da hayvanı toprakta küçük parçalara ayıran canlılara ne denir?","steps":[{"t":"Görevi düşün","a":"çürütme işi","d":"Ölen canlıları parçalayıp yok eden bir işçi gibidir."},{"t":"Adını bul","a":"ayrıştırıcı","d":"Bu işi yapan canlılara <b>ayrıştırıcı</b> denir."}],"ans":"Ölen canlıları parçalayan canlılara ayrıştırıcı denir."},{"q":"Ormanda yere düşen yaprakları çürüten en bilinen iki canlı türü hangisidir?","steps":[{"t":"Toprakta yaşayan küçük canlı","a":"bakteri","d":"Gözle görülmeyen çok küçük bakteriler çürütme yapar."},{"t":"Şapkalı bitki gibi görünen","a":"mantar","d":"Nemli yerlerde biten mantarlar da çürütür."}],"ans":"Yaprakları en çok bakteriler ve mantarlar çürütür."},{"q":"Ayrıştırıcılar doğa için neden yararlıdır?","steps":[{"t":"Ölü maddeler birikir mi","a":"birikmez","d":"Ölen yapraklar ve hayvanlar yerde yığılıp kalmaz."},{"t":"Sonuç","a":"doğa temizlenir","d":"Ayrıştırıcılar onları yiyip yok ederek doğayı temizler."}],"ans":"Ayrıştırıcılar ölü canlıları yok ederek doğanın temizlenmesini sağlar."},{"q":"Bir elma çürüyüp yumuşadığında bunu yapan canlılar kimlerdir?","steps":[{"t":"Çürümeyi yapan","a":"ayrıştırıcı","d":"Elmayı çürüten görünmez küçük canlılar vardır."},{"t":"Hangileri","a":"bakteri ve mantar","d":"Elmanın üzerinde üreyen bakteri ve küfler (mantar) onu çürütür."}],"ans":"Elmayı bakteri ve mantar gibi ayrıştırıcılar çürütür."},{"q":"Ayrıştırıcılar besinini nasıl bulur?","steps":[{"t":"Avlanır mı","a":"avlanmaz","d":"Ayrıştırıcılar canlı hayvan yakalayıp yemez."},{"t":"Neyi yer","a":"ölü maddeler","d":"Ölmüş bitki ve hayvanları parçalayarak beslenir."}],"ans":"Ayrıştırıcılar ölmüş bitki ve hayvanları parçalayarak beslenir."}],"zor":[{"q":"Eğer dünyada hiç ayrıştırıcı olmasaydı ormanlarda ne olurdu?","steps":[{"t":"Ölü maddeler ne olur","a":"çürümez","d":"Ölen yapraklar ve hayvanlar çürümeden olduğu gibi kalırdı."},{"t":"Zamanla birikir","a":"her yer dolar","d":"Yıllar geçtikçe ölü maddeler üst üste yığılırdı."},{"t":"Sonuç","a":"doğa kirlenir","d":"Her yer ölü maddeyle dolar ve doğa temizlenemezdi."}],"ans":"Ayrıştırıcı olmasaydı ölü maddeler çürümez, üst üste birikir ve doğa temizlenemezdi."},{"q":"Ayrıştırıcılar bitkilere nasıl yardım eder?","steps":[{"t":"Neyi parçalar","a":"ölü maddeler","d":"Ölü bitki ve hayvanları parçalayıp toprağa karıştırır."},{"t":"Toprağa ne kazandırır","a":"besin","d":"Bu parçalanma toprağı besinli, verimli hale getirir."},{"t":"Sonuç","a":"bitki büyür","d":"Verimli toprakta bitkiler daha iyi büyür."}],"ans":"Ayrıştırıcılar ölü maddeleri parçalayıp toprağı besinli yapar, böylece bitkiler daha iyi büyür."},{"q":"Bir ekmeğin üzerinde yeşil küf görürsen bu nedir ve nasıl oluşur?","steps":[{"t":"Yeşil tüylü madde","a":"küf mantarı","d":"Ekmekteki yeşil tüylü leke bir mantar çeşidi olan küftür."},{"t":"Neden oluşur","a":"ekmeği yer","d":"Küf, ekmeği besin olarak yer ve üzerinde çoğalır."},{"t":"Ne tür canlı","a":"ayrıştırıcı","d":"Ekmeği çürüttüğü için küf bir ayrıştırıcıdır."}],"ans":"Ekmekteki yeşil küf, ekmeği yiyip çürüten bir mantardır ve ayrıştırıcıdır."},{"q":"Solucanlar ile bakteri ve mantarlar arasında ne fark vardır?","steps":[{"t":"Solucan ne yapar","a":"ölü yaprağı yer","d":"Solucan ölü yaprakları ağzıyla yiyip parçalar."},{"t":"Bakteri-mantar ne yapar","a":"içine girip çürütür","d":"Bakteri ve mantar ölü maddeyi içine sızarak çürütür."},{"t":"Sonuç","a":"ikisi de temizler","d":"İkisi de ölü maddeyi yok eder ama farklı şekilde yapar."}],"ans":"Solucan ölü maddeyi yiyerek, bakteri ve mantar ise içine sızıp çürüterek doğayı temizler."},{"q":"Yere gömülen bir meyve çekirdeği zamanla kaybolup gidiyorsa bunu kim yapmıştır?","steps":[{"t":"Çekirdeği kim parçalar","a":"ayrıştırıcı","d":"Toprakta yaşayan ayrıştırıcılar çekirdeğin kabuğunu çürütür."},{"t":"Hangileri","a":"bakteri ve mantar","d":"Topraktaki bakteri ve mantarlar bunu yapar."},{"t":"Sonuç","a":"toprağa karışır","d":"Çürüyen çekirdek küçük parçalara ayrılıp toprağa karışır."}],"ans":"Topraktaki bakteri ve mantarlar çekirdeği çürütüp toprağa karıştırdığı için kaybolur gibi görünür."}]},"ortaokul":{"kolay":[{"q":"Ayrıştırıcılar ekosistemde hangi gruba girer ve görevleri nedir?","steps":[{"t":"Hangi grup","a":"tüketici grubu","d":"Ayrıştırıcılar hazır besinle beslendiği için tüketicilere dahildir."},{"t":"Görevi","a":"ölü maddeyi parçalar","d":"Ölü bitki ve hayvan kalıntılarını parçalayıp toprağa kazandırır."}],"ans":"Ayrıştırıcılar, ölü organik maddeleri parçalayan özel tüketicilerdir."},{"q":"Ayrıştırıcı görevi gören iki temel canlı grubu nedir?","steps":[{"t":"Mikroskobik grup","a":"bakteriler","d":"Çok küçük tek hücreli bakteriler ölü maddeyi parçalar."},{"t":"Şapkalı/küf grubu","a":"mantarlar","d":"Mantarlar da salgıladıkları maddelerle ölü maddeyi çürütür."}],"ans":"Ayrıştırıcılar başlıca bakteriler ve mantarlardan oluşur."},{"q":"Ayrıştırıcılar ölü maddeyi parçalayınca topraga ne kazandırır?","steps":[{"t":"Açığa çıkan maddeler","a":"mineraller","d":"Çürüme sonucu azot, fosfor gibi mineral maddeler açığa çıkar."},{"t":"Nereye gider","a":"toprağa karışır","d":"Bu mineraller toprağa karışıp bitkilerin kullanımına sunulur."}],"ans":"Ayrıştırıcılar çürütme sırasında mineralleri toprağa geri kazandırır."},{"q":"Ayrıştırıcılara neden ihtiyaç duyarız?","steps":[{"t":"Ölü madde sorunu","a":"birikme","d":"Ayrıştırıcı olmasa ölü canlılar birikir ve madde çevrimi durur."},{"t":"Çözümleri","a":"geri dönüşüm","d":"Ayrıştırıcılar maddeleri parçalayıp tekrar kullanılabilir hale getirir."}],"ans":"Ayrıştırıcılar ölü maddeyi geri dönüştürerek madde döngüsünün sürmesini sağlar."},{"q":"Bitkiler ayrıştırıcıların açığa çıkardığı mineralleri nasıl kullanır?","steps":[{"t":"Mineralleri alma","a":"kökle alır","d":"Bitkiler topraktaki mineralleri kökleriyle emer."},{"t":"Kullanımı","a":"büyüme","d":"Bu mineralleri büyümek ve gelişmek için kullanır."}],"ans":"Bitkiler ayrıştırıcıların toprağa verdiği mineralleri kökleriyle alıp büyümede kullanır."}],"zor":[{"q":"Ayrıştırıcılar madde döngüsünde neden vazgeçilmezdir?","steps":[{"t":"Maddenin bağlı hali","a":"ölü organik madde","d":"Maddeler ölü canlıların bedeninde bağlı (kullanılamaz) durumdadır."},{"t":"Serbest bırakma","a":"mineral salınımı","d":"Ayrıştırıcılar bunları parçalayıp mineralleri serbest bırakır."},{"t":"Döngünün tamamlanması","a":"yeniden kullanım","d":"Serbest mineraller üreticiler tarafından tekrar kullanılır, döngü kapanır."}],"ans":"Ayrıştırıcılar ölü maddedeki mineralleri serbest bırakıp tekrar kullanılır kıldığı için madde döngüsü ancak onlarla tamamlanır."},{"q":"Bir hayvan öldüğünde bedenindeki azotun toprağa geri dönmesini hangi canlılar sağlar?","steps":[{"t":"Azotun bulunduğu yer","a":"proteinlerde","d":"Hayvanın bedeninde azot, protein gibi organik maddelerde bağlıdır."},{"t":"Parçalayan canlı","a":"ayrıştırıcılar","d":"Bakteri ve mantarlar bu proteinleri parçalar."},{"t":"Sonuç","a":"azot toprağa döner","d":"Açığa çıkan azotlu mineraller toprağa karışır."}],"ans":"Bakteri ve mantar gibi ayrıştırıcılar proteinleri parçalayarak azotun toprağa geri dönmesini sağlar."},{"q":"Detritivor (örneğin solucan) ile ayrıştırıcı arasındaki fark nedir?","steps":[{"t":"Detritivorun beslenmesi","a":"yutarak yer","d":"Solucan gibi detritivorlar ölü maddeyi ağzıyla yutup içinde sindirir."},{"t":"Ayrıştırıcının beslenmesi","a":"hücre dışı sindirim","d":"Bakteri ve mantar enzim salgılayıp maddeyi dışarıda sindirir, sonra emer."},{"t":"Sonuç","a":"yöntem farkı","d":"Amaç aynı (ölü maddeyi parçalamak) ama yöntemleri farklıdır."}],"ans":"Detritivorlar ölü maddeyi yutarak içinde sindirir; ayrıştırıcılar ise enzimle dışarıda sindirip emer."},{"q":"Bir orman zemininde her sonbahar dökülen yapraklar neden yıllar içinde birikip dağ olmaz?","steps":[{"t":"Yaprak miktarı","a":"sürekli düşer","d":"Her yıl çok sayıda yaprak orman zeminine dökülür."},{"t":"Devreye giren canlılar","a":"ayrıştırıcılar","d":"Bakteri ve mantarlar dökülen yaprakları sürekli çürütür."},{"t":"Sonuç","a":"denge kurulur","d":"Çürüme, dökülmeye yetiştiği için yapraklar birikip dağ olmaz."}],"ans":"Ayrıştırıcılar dökülen yaprakları sürekli çürüttüğü için yapraklar birikip dağ oluşturmaz."},{"q":"Ayrıştırıcılar olmasaydı üreticiler (bitkiler) neden zarar görürdü?","steps":[{"t":"Bitkinin ihtiyacı","a":"mineraller","d":"Bitkiler büyümek için topraktan mineral almak zorundadır."},{"t":"Minerallerin kaynağı","a":"ayrışma","d":"Bu mineraller büyük oranda ölü maddenin ayrışmasıyla toprağa döner."},{"t":"Sonuç","a":"mineral biter","d":"Ayrıştırıcı olmasa mineraller ölü maddede kilitli kalır, toprak fakirleşir."}],"ans":"Ayrıştırıcı olmasaydı mineraller ölü maddede kilitli kalır, toprak fakirleşir ve bitkiler beslenemezdi."}]},"lise":{"kolay":[{"q":"Ayrıştırıcı (saprofit) kavramını bilimsel olarak tanımlayınız.","steps":[{"t":"Beslenme şekli","a":"saprofit beslenme","d":"Ayrıştırıcılar ölü organik maddeyi parçalayarak beslenen saprofit canlılardır."},{"t":"Ekolojik rol","a":"madde geri dönüşümü","d":"Organik maddeyi inorganik minerallere çevirip ekosisteme geri kazandırır."}],"ans":"Ayrıştırıcılar, ölü organik maddeyi inorganik minerallere parçalayarak beslenen saprofit canlılardır."},{"q":"Ayrıştırıcı olarak görev yapan iki ana canlı grubu nedir?","steps":[{"t":"Prokaryot grup","a":"bakteriler","d":"Saprofit bakteriler organik maddeyi enzimlerle parçalar."},{"t":"Ökaryot grup","a":"funguslar (mantarlar)","d":"Mantarlar hif uçlarından enzim salgılayarak ayrıştırma yapar."}],"ans":"Başlıca ayrıştırıcılar saprofit bakteriler ve mantarlardır (funguslar)."},{"q":"Saprofit beslenmede sindirim nerede gerçekleşir?","steps":[{"t":"Enzim salgısı","a":"hücre dışına","d":"Ayrıştırıcı sindirim enzimlerini doğrudan ortama (besine) salgılar."},{"t":"Sindirim yeri","a":"hücre dışı","d":"Madde hücre dışında küçük moleküllere parçalanır."}],"ans":"Saprofitlerde sindirim hücre dışında (ekstrasellüler) gerçekleşir; enzimler ortama salgılanır."},{"q":"Hücre dışı sindirimden sonra ayrıştırıcı besini nasıl alır?","steps":[{"t":"Parçalanan ürünler","a":"küçük moleküller","d":"Dışarıda sindirilen madde amino asit, şeker gibi küçük moleküllere döner."},{"t":"Alınma şekli","a":"emilim (absorpsiyon)","d":"Bu küçük moleküller hücre zarından emilerek içeri alınır."}],"ans":"Ayrıştırıcı, hücre dışında oluşan küçük molekülleri zardan emerek (absorpsiyon) alır."},{"q":"Ayrıştırıcıların ekosistemdeki en temel ekolojik rolü nedir?","steps":[{"t":"İşlevi","a":"madde döngüsü","d":"Ölü maddedeki elementleri serbest bırakarak madde döngüsünü tamamlar."},{"t":"Sonuç","a":"mineral geri dönüşü","d":"Bu mineraller üreticilerce yeniden kullanılır."}],"ans":"Ayrıştırıcıların temel rolü, ölü maddedeki maddeyi geri dönüştürerek madde döngüsünü tamamlamaktır."},{"q":"Mineralizasyon kavramı ne anlama gelir?","steps":[{"t":"Başlangıç maddesi","a":"organik madde","d":"Mineralizasyonda ölü canlının organik maddesi işlenir."},{"t":"Dönüşüm","a":"inorganik mineral","d":"Organik bileşikler inorganik mineral iyonlarına (NO₃⁻, PO₄³⁻) çevrilir."}],"ans":"Mineralizasyon, ölü organik maddenin ayrıştırıcılarca inorganik minerallere dönüştürülmesidir."},{"q":"Ayrıştırıcılar ile diğer tüketiciler arasındaki temel fark nedir?","steps":[{"t":"Diğer tüketiciler","a":"canlı/parça besinle","d":"Otçul ve etçiller genelde canlı veya yeni avladıkları besinle beslenir."},{"t":"Ayrıştırıcılar","a":"ölü organik madde","d":"Ayrıştırıcılar yalnızca ölü kalıntı ve atıklarla beslenir."}],"ans":"Ayrıştırıcılar diğer tüketicilerden farklı olarak yalnızca ölü organik madde ve atıklarla beslenir."},{"q":"Detritivor ile ayrıştırıcı arasındaki beslenme farkı nedir?","steps":[{"t":"Detritivor","a":"içsel sindirim","d":"Detritivorlar (solucan, gübre böceği) detritusu yutup sindirim sisteminde sindirir."},{"t":"Ayrıştırıcı","a":"hücre dışı sindirim","d":"Ayrıştırıcılar enzimi dışarı salıp sindirilen maddeyi emer."}],"ans":"Detritivorlar besini yutup içeride sindirir; ayrıştırıcılar enzimle dışarıda sindirip emer."},{"q":"Saprofit bakteriler hangi koşullarda daha hızlı çalışır?","steps":[{"t":"Sıcaklık-nem","a":"ılık ve nemli","d":"Ilık, nemli ortam enzim etkinliğini ve üremeyi hızlandırır."},{"t":"Oksijen/besin","a":"oksijen ve organik madde","d":"Yeterli oksijen ve bol organik madde ayrışmayı artırır."}],"ans":"Saprofit bakteriler ılık, nemli, oksijenli ve organik maddece zengin ortamlarda daha hızlı ayrıştırma yapar."},{"q":"Ayrıştırıcılar karbon döngüsüne nasıl katkı sağlar?","steps":[{"t":"Karbonun bağlı hali","a":"ölü organik madde","d":"Karbon, ölü canlıların organik bileşiklerinde bağlıdır."},{"t":"Salınım","a":"CO₂ olarak","d":"Ayrıştırıcılar solunumla bu karbonu CO₂ olarak atmosfere verir."}],"ans":"Ayrıştırıcılar ölü maddedeki karbonu solunumla CO₂'ye çevirerek atmosfere geri verir."},{"q":"Ayrıştırıcılar azot döngüsünde hangi temel adımı gerçekleştirir?","steps":[{"t":"Azotun kaynağı","a":"protein/üre","d":"Ölü canlılarda azot protein ve diğer organik bileşiklerde bağlıdır."},{"t":"Yaptığı işlem","a":"amonifikasyon","d":"Ayrıştırıcılar bu azotu amonyağa (NH₃/NH₄⁺) çevirir."}],"ans":"Ayrıştırıcılar, ölü maddedeki organik azotu amonyağa çevirerek (amonifikasyon) azot döngüsünü besler."},{"q":"Bir ekosistemde ayrıştırıcılar tamamen yok olsaydı ilk gözlenecek sonuç ne olurdu?","steps":[{"t":"Ölü madde durumu","a":"birikir","d":"Ölü bitki ve hayvanlar parçalanmadan birikmeye başlar."},{"t":"Mineral durumu","a":"toprağa dönmez","d":"Mineraller ölü maddede kilitli kalıp toprağa geri dönemez."}],"ans":"Ayrıştırıcılar yok olsaydı ölü madde birikir ve mineraller toprağa geri dönemezdi."},{"q":"Çürükçül (saprofit) mantarların ekolojik önemini bir cümleyle açıklayınız.","steps":[{"t":"Ne parçalar","a":"selüloz, lignin","d":"Mantarlar bitkilerin zor parçalanan selüloz ve ligninini bile sindirebilir."},{"t":"Sonuç","a":"odun çürümesi","d":"Böylece ölü ağaç ve odunsu maddeleri ayrıştırırlar."}],"ans":"Saprofit mantarlar selüloz ve lignin gibi dirençli maddeleri parçalayarak odunsu ölü maddenin ayrışmasını sağlar."},{"q":"Ayrıştırıcılar enerji akışı bakımından besin ağında nereye konumlanır?","steps":[{"t":"Beslendiği kaynak","a":"tüm seviyeler","d":"Ayrıştırıcılar her beslenme düzeyindeki ölü kalıntı ve atıkla beslenir."},{"t":"Konum","a":"tüm zincire bağlı","d":"Bu nedenle belirli bir basamağa değil, tüm besin ağına bağlıdır."}],"ans":"Ayrıştırıcılar her beslenme düzeyinden ölü madde aldığı için besin ağının tümüne bağlanan özel bir konumda yer alır."},{"q":"Ayrıştırıcı faaliyeti ile oluşan humus toprağa ne katar?","steps":[{"t":"Humus nedir","a":"kısmen ayrışmış madde","d":"Humus, ayrışan organik maddeden oluşan koyu renkli verimli kısımdır."},{"t":"Katkısı","a":"verim ve su tutma","d":"Toprağa besin sağlar, su tutma ve havalanmayı artırır."}],"ans":"Ayrıştırma sonucu oluşan humus, toprağa besin kazandırır ve su tutma ile havalanmayı artırarak verimi yükseltir."}],"zor":[{"q":"Mineralizasyon sürecinin madde döngüsünün kapanmasındaki rolünü açıklayınız.","steps":[{"t":"Organik bağlanma","a":"elementler kilitli","d":"Karbon, azot, fosfor gibi elementler ölü canlının organik bileşiklerinde kilitlidir."},{"t":"Mineralizasyon","a":"inorganik salınım","d":"Ayrıştırıcılar bunları inorganik iyonlara (NH₄⁺, PO₄³⁻) çevirir."},{"t":"Döngünün kapanması","a":"üretici kullanır","d":"Serbest mineraller üreticilerce alınınca döngü başa döner."}],"ans":"Mineralizasyon, organik maddede kilitli elementleri inorganik minerallere çevirip üreticilerin kullanımına sunarak madde döngüsünü kapatır."},{"q":"Saprofitlerde hücre dışı sindirimin ekolojik avantajını açıklayınız.","steps":[{"t":"Enzim salgısı","a":"ortama enzim","d":"Saprofit, sindirim enzimlerini doğrudan ölü maddeye salgılar."},{"t":"Büyük maddenin parçalanması","a":"polimer kırılır","d":"Yutamayacağı büyük polimerleri (selüloz, protein) dışarıda parçalar."},{"t":"Sonuç","a":"geniş besin erişimi","d":"Böylece yutma sınırı olmadan büyük ölü kütleleri sömürebilir."}],"ans":"Hücre dışı sindirim sayesinde saprofitler yutamayacakları büyük organik polimerleri dışarıda parçalayıp emebilir, bu da geniş bir ölü madde kaynağına erişim sağlar."},{"q":"Ayrıştırıcıların ekosistem enerji akışındaki rolü üreticilerden nasıl ayrılır?","steps":[{"t":"Üretici","a":"enerji girişi","d":"Üreticiler güneş enerjisini ekosisteme sokar (tek yönlü giriş)."},{"t":"Ayrıştırıcı","a":"madde geri dönüşü","d":"Ayrıştırıcılar enerji değil, asıl olarak maddeyi geri döndürür."},{"t":"Fark","a":"enerji vs madde","d":"Enerji tek yönlü akarken madde ayrıştırıcılarla döngüsel kalır."}],"ans":"Üreticiler ekosisteme enerji girişini sağlar; ayrıştırıcılar ise enerjiyi geri kazandırmaz, asıl olarak maddeyi (mineralleri) döngüye geri verir."},{"q":"Anaerobik (oksijensiz) ortamda ayrışma neden farklı ve yavaş ilerler?","steps":[{"t":"Oksijen durumu","a":"oksijen yok","d":"Bataklık gibi ortamlarda oksijen bulunmaz."},{"t":"Devreye giren canlı","a":"anaerob bakteri","d":"Ayrışmayı oksijensiz solunum yapan anaerob bakteriler yürütür."},{"t":"Sonuç","a":"yavaş + CH₄","d":"Süreç yavaştır ve metan (CH₄) gibi yan ürünler açığa çıkar."}],"ans":"Oksijensiz ortamda ayrışmayı anaerob bakteriler yürütür; süreç yavaştır ve metan gibi ara ürünler oluşur, organik madde tam parçalanmadan turba/birikim oluşabilir."},{"q":"Ayrıştırıcılar azot döngüsünde amonifikasyon adımını nasıl gerçekleştirir?","steps":[{"t":"Azot kaynağı","a":"protein/nükleik asit","d":"Ölü canlıdaki azot protein ve nükleik asitlerde bağlıdır."},{"t":"Parçalama","a":"amino asit → NH₃","d":"Ayrıştırıcılar proteini amino asitlere, sonra amonyağa parçalar."},{"t":"Döngüye katkı","a":"nitrifikasyona zemin","d":"Açığa çıkan NH₄⁺, nitrifikasyon bakterilerince nitrata çevrilebilir."}],"ans":"Ayrıştırıcılar ölü maddedeki proteinleri amino asitlere ve sonra amonyağa (amonifikasyon) parçalar; bu amonyak nitrifikasyonla nitrata dönüşerek azot döngüsünü sürdürür."},{"q":"Bir tropik yağmur ormanında toprağın besince fakir olmasına rağmen bitki örtüsünün gür olması ayrıştırıcılarla nasıl açıklanır?","steps":[{"t":"Ayrışma hızı","a":"çok hızlı","d":"Sıcak ve nemli iklimde ayrıştırıcılar ölü maddeyi çok hızlı parçalar."},{"t":"Mineral akışı","a":"hızlı geri alım","d":"Açığa çıkan mineraller toprakta birikemeden bitkilerce hemen alınır."},{"t":"Sonuç","a":"besin bitkide","d":"Bu yüzden besin toprakta değil, hızlı döngüyle bitki kütlesinde tutulur."}],"ans":"Tropik ormanda ayrıştırıcılar minerali çok hızlı serbest bırakır, bitkiler de hemen alır; besin toprakta birikmeden hızlı döngüyle bitki kütlesinde tutulduğu için toprak fakir görünse de örtü gürdür."},{"q":"Detritivor ve ayrıştırıcıların birlikte çalışmasının ayrışma verimine etkisini açıklayınız.","steps":[{"t":"Detritivorun katkısı","a":"parçalama","d":"Solucan gibi detritivorlar ölü maddeyi çiğneyip küçük parçalara böler."},{"t":"Yüzey artışı","a":"daha çok alan","d":"Parçalanma, ayrıştırıcı enzimlerinin etki edeceği yüzeyi artırır."},{"t":"Sonuç","a":"hızlı ayrışma","d":"Böylece bakteri ve mantar maddeyi çok daha hızlı sindirir."}],"ans":"Detritivorlar ölü maddeyi fiziksel olarak parçalayıp yüzey alanını artırır; bu da ayrıştırıcı enzimlerinin daha hızlı etki etmesini sağlayarak ayrışma verimini yükseltir."},{"q":"Ayrıştırıcı faaliyeti durdurulsaydı atmosferik CO₂ ve enerji akışı uzun vadede nasıl etkilenirdi?","steps":[{"t":"Karbon salınımı","a":"durur","d":"Ölü maddedeki karbon CO₂'ye çevrilemez, atmosfere dönemez."},{"t":"Üretici etkisi","a":"CO₂ azalır","d":"Fotosentez için CO₂ azalır, üretim yavaşlar."},{"t":"Sonuç","a":"döngü çöker","d":"Mineral ve karbon kilitlenir, hem madde hem enerji akışı sekteye uğrar."}],"ans":"Ayrıştırma dursaydı karbon ölü maddede kilitlenir, atmosferik CO₂ azalır, fotosentez yavaşlar ve mineraller döngüye dönemediği için hem madde hem enerji akışı uzun vadede çökerdi."},{"q":"Ayrıştırıcıların C:N oranı yüksek (azotça fakir) maddeleri ayrıştırırken karşılaştığı sınırlama nedir?","steps":[{"t":"Madde örneği","a":"odun, saman","d":"Odun gibi maddeler karbonca zengin, azotça fakirdir (yüksek C:N)."},{"t":"Mikrobun ihtiyacı","a":"azot gerekir","d":"Ayrıştırıcılar üremek için yeterli azota ihtiyaç duyar."},{"t":"Sonuç","a":"yavaş ayrışma","d":"Azot kısıtlı olunca mikrobiyal büyüme ve ayrışma yavaşlar."}],"ans":"C:N oranı yüksek maddelerde azot yetersiz kaldığı için mikrobiyal üreme sınırlanır ve ayrışma yavaşlar; bu maddeler ancak ortamdan ek azot sağlandıkça çürür."},{"q":"Saprofit mantarların hifsel (miselyum) yapısı ayrıştırma verimine nasıl katkıda bulunur?","steps":[{"t":"Hif yapısı","a":"ince iplikler","d":"Mantar gövdesi miselyum denen ince hif ağından oluşur."},{"t":"Yayılma","a":"besine nüfuz","d":"Hifler ölü madde içine sızarak geniş yüzeye yayılır."},{"t":"Sonuç","a":"yoğun enzim teması","d":"Geniş temas yüzeyi bol enzim salınımı ve hızlı emilim sağlar."}],"ans":"Miselyumun ince hif ağı ölü madde içine sızıp geniş bir temas yüzeyi oluşturur; bu sayede bol enzim salgılanır ve sindirilen besin verimli biçimde emilerek ayrışma hızlanır."},{"q":"Ayrıştırıcılar olmadan fosfor gibi bir kara ekosistemi besininin yeniden kullanımı neden mümkün olmazdı?","steps":[{"t":"Fosforun hali","a":"organik bağlı","d":"Fosfor, ölü canlılarda nükleik asit ve fosfolipitlerde organik bağlıdır."},{"t":"Serbest bırakma","a":"ayrışmayla PO₄³⁻","d":"Ayrıştırıcılar bunu inorganik fosfat (PO₄³⁻) olarak serbest bırakır."},{"t":"Sonuç","a":"üretici alır","d":"Bu fosfat olmadan bitkiler topraktan fosfor alamazdı."}],"ans":"Fosfor ölü maddede organik bağlıdır; ayrıştırıcılar onu inorganik fosfata çevirip toprağa salmazsa bitkiler bu fosforu alamaz, dolayısıyla fosforun yeniden kullanımı durur."},{"q":"Bir besin zincirinde enerjinin çoğunun en sonunda ayrıştırıcılara ulaşmasının termodinamik sebebi nedir?","steps":[{"t":"Enerji aktarımı","a":"%10 verim","d":"Her beslenme basamağında enerjinin yalnızca küçük kısmı bir üste geçer."},{"t":"Ölü madde+atık","a":"enerji içerir","d":"Geri kalan organik madde ölü kalıntı ve atık olarak birikir."},{"t":"Sonuç","a":"ayrıştırıcıya gider","d":"Bu kalan organik enerjinin tamamı sonunda ayrıştırıcılarca işlenir."}],"ans":"Beslenme basamakları arasında enerjinin büyük kısmı bir üste geçmeyip ölü madde ve atık olarak kalır; bu birikmiş organik enerji termodinamik olarak sonunda ayrıştırıcılar tarafından işlendiği için enerjinin çoğu onlara ulaşır."},{"q":"Ayrıştırıcıların aşırı çoğalması (örneğin ötrofik bir gölde) ekosistemde nasıl olumsuz sonuç doğurabilir?","steps":[{"t":"Bol organik madde","a":"alg ölümü","d":"Aşırı besinle çoğalan alglerin ölmesi bol ölü madde bırakır."},{"t":"Mikrobiyal patlama","a":"oksijen tüketimi","d":"Ayrıştırıcı bakteriler hızla çoğalıp solunumla oksijeni tüketir."},{"t":"Sonuç","a":"hipoksi/ölüm","d":"Sudaki oksijen düşünce balıklar ve diğer canlılar boğularak ölür."}],"ans":"Ötrofik gölde ölü organik madde artınca ayrıştırıcı bakteriler patlama yaparak solunumla suyun oksijenini tüketir; oluşan oksijensizlik (hipoksi) balıkların ve canlıların ölümüne yol açar."},{"q":"Ayrıştırıcı bakteriler ile mantarların farklı pH ve madde tercihleri ayrışma sürecini nasıl tamamlayıcı kılar?","steps":[{"t":"Bakteri tercihi","a":"nötr-bazik, kolay madde","d":"Bakteriler genelde nötr-hafif bazik ortamda ve kolay parçalanan maddede baskındır."},{"t":"Mantar tercihi","a":"asidik, dirençli madde","d":"Mantarlar asidik ortamda ve lignin/selüloz gibi dirençli maddede etkindir."},{"t":"Sonuç","a":"tam ayrışma","d":"Farklı koşulları üstlenmeleri ölü maddenin baştan sona ayrışmasını sağlar."}],"ans":"Bakteriler nötr-bazik ortamda kolay maddeleri, mantarlar ise asidik ortamda lignin gibi dirençli maddeleri ayrıştırır; bu tamamlayıcı tercihler ölü organik maddenin eksiksiz parçalanmasını sağlar."},{"q":"Toprakta ayrıştırma sonucu oluşan humusun karbon tutulumu (karbon yutağı) açısından önemi nedir?","steps":[{"t":"Kısmi ayrışma","a":"dirençli humus","d":"Ayrışmanın bir kısmı tam tamamlanmaz, dirençli humus olarak kalır."},{"t":"Karbon depolama","a":"toprakta birikir","d":"Humustaki karbon uzun süre toprakta tutulup CO₂'ye dönmez."},{"t":"Sonuç","a":"karbon yutağı","d":"Böylece toprak, atmosferik karbonu bağlayan bir yutak görevi görür."}],"ans":"Ayrışmanın tam tamamlanmayan dirençli kısmı humus olarak toprakta birikir ve içindeki karbon uzun süre CO₂'ye dönmeden tutulur; bu yüzden ayrıştırma sonucu oluşan humus toprağı önemli bir karbon yutağı yapar."}]}},"besinZinciri":{"ilkokul":{"kolay":[{"q":"Besin zinciri nedir? Kısaca açıkla.","steps":[{"t":"Kim kimi yer","a":"sırayla yeme","d":"Doğada bir canlı başka bir canlıyı yer, onu da başkası yer. Bu sıraya zincir denir."},{"t":"Sonuç","a":"besin zinciri","d":"Canlıların birbirini yeme sırasını gösteren zincire <b>besin zinciri</b> denir."}],"ans":"Besin zinciri, canlıların birbirini yeme sırasını gösteren dizidir."},{"q":"Şu zincirde ok hangi yönü gösterir: ot → tavşan → tilki?","steps":[{"t":"Oku oku","a":"besin yönü","d":"Ok, besinin (enerjinin) kime gittiğini gösterir."},{"t":"Sonuç","a":"yenenden yiyene","d":"Ok her zaman yenen canlıdan onu yiyen canlıya doğru gider."}],"ans":"Ok, yenen canlıdan onu yiyene doğru gider (ot tavşana, tavşan tilkiye yem olur)."},{"q":"ot → tavşan → tilki zincirinde tavşan ne ile beslenir?","steps":[{"t":"Tavşanın önündeki ok","a":"ottan tavşana","d":"Zincirde ottan tavşana ok gider, yani tavşan otu yer."},{"t":"Sonuç","a":"ot","d":"Tavşan bitki olan otla beslenir."}],"ans":"Tavşan ot (bitki) ile beslenir."},{"q":"Her besin zinciri en başta neyle başlar?","steps":[{"t":"Kendi besinini yapan","a":"bitkiler","d":"Bitkiler güneşle kendi besinini yapar, kimseyi yemez."},{"t":"Sonuç","a":"bitki ile","d":"Bu yüzden besin zinciri en başta bitki (ot, ağaç) ile başlar."}],"ans":"Besin zinciri en başta kendi besinini yapan bitkiyle başlar."},{"q":"ot → çekirge → kurbağa zincirinde kurbağa ne yer?","steps":[{"t":"Kurbağaya giden ok","a":"çekirgeden kurbağaya","d":"Zincirde çekirgeden kurbağaya ok vardır."},{"t":"Sonuç","a":"çekirge","d":"Demek ki kurbağa çekirgeyi yer."}],"ans":"Kurbağa çekirgeyi yiyerek beslenir."}],"zor":[{"q":"ot → tavşan → tilki zincirinde tilkiler birden yok olursa tavşanlara ne olur?","steps":[{"t":"Tavşanı kim yiyordu","a":"tilki","d":"Tilki tavşanları yiyerek sayılarını dengede tutuyordu."},{"t":"Tilki gidince","a":"avcı kalmaz","d":"Tilki olmayınca tavşanları yiyen kimse kalmaz."},{"t":"Sonuç","a":"tavşan çoğalır","d":"Avcısı olmadığı için tavşanların sayısı çok artar."}],"ans":"Tilki yok olunca avcısı kalmayan tavşanların sayısı hızla artar."},{"q":"ot → tavşan → tilki zincirinde otlar kuruyup biterse ne olur?","steps":[{"t":"Tavşanın yemi","a":"ot","d":"Tavşan otla beslenir; ot biterse yiyecek bulamaz."},{"t":"Tavşana etkisi","a":"tavşan azalır","d":"Yemi olmayan tavşanlar açlıktan azalır."},{"t":"Tilkiye etkisi","a":"tilki de azalır","d":"Tavşan azalınca onu yiyen tilki de aç kalır ve azalır."}],"ans":"Ot biterse tavşanlar azalır, onları yiyen tilkiler de azalır; tüm zincir etkilenir."},{"q":"Neden bir besin zinciri hep bitkiyle başlar, aslanla başlamaz?","steps":[{"t":"Bitkinin işi","a":"besin üretir","d":"Bitkiler güneşle kendi besinini üretir, dışarıdan yemek yemez."},{"t":"Aslanın durumu","a":"başkasını yer","d":"Aslan kendi besinini yapamaz, başka hayvanları yiyerek yaşar."},{"t":"Sonuç","a":"bitki en başta","d":"Besin önce bitkide üretildiği için zincir bitkiyle başlamak zorundadır."}],"ans":"Bitkiler besini kendi ürettiği için zincir bitkiyle başlar; aslan besinini üretemediği için en başta olamaz."},{"q":"ot → fare → yılan → kartal zincirinde kartal en çok kimi yer?","steps":[{"t":"Kartala giden ok","a":"yılandan kartala","d":"Zincirde yılandan kartala ok gider."},{"t":"Anlamı","a":"yılanı yer","d":"Ok yönüne göre kartal yılanı yiyerek beslenir."},{"t":"Sonuç","a":"yılan","d":"Bu zincirde kartalın besini yılandır."}],"ans":"Bu zincirde kartal, kendinden önceki canlı olan yılanı yer."},{"q":"Bir bahçede bütün kurbağalar yok olursa çekirgelere ne olur (ot → çekirge → kurbağa)?","steps":[{"t":"Çekirgeyi kim yiyordu","a":"kurbağa","d":"Kurbağa çekirgeleri yiyerek sayısını dengede tutuyordu."},{"t":"Kurbağa gidince","a":"avcı yok","d":"Kurbağa olmayınca çekirgeyi yiyen kalmaz."},{"t":"Sonuç","a":"çekirge çoğalır, ot azalır","d":"Çekirgeler çok çoğalır ve otları aşırı yiyerek bitirir."}],"ans":"Kurbağa yok olunca çekirgeler çoğalır ve otları aşırı tüketir, denge bozulur."}]},"ortaokul":{"kolay":[{"q":"Besin zincirinde üretici, tüketici ve ayrıştırıcı nedir?","steps":[{"t":"Üretici","a":"bitkiler","d":"Kendi besinini fotosentezle üreten yeşil bitkilere üretici denir."},{"t":"Tüketici","a":"hayvanlar","d":"Besinini hazır alan, başka canlıları yiyen hayvanlara tüketici denir."},{"t":"Ayrıştırıcı","a":"mantar, bakteri","d":"Ölü canlıları çürütüp toprağa katan canlılara ayrıştırıcı denir."}],"ans":"Üreticiler besinini üretir, tüketiciler hazır alır, ayrıştırıcılar ölüleri çürütür."},{"q":"Besin zincirindeki oklar neyin yönünü gösterir?","steps":[{"t":"Okun anlamı","a":"enerji akışı","d":"Ok, besinle taşınan enerjinin hangi yöne aktığını gösterir."},{"t":"Yönü","a":"yenenden yiyene","d":"Enerji, yenen canlıdan onu yiyen canlıya doğru akar."}],"ans":"Oklar enerjinin yenen canlıdan onu yiyen canlıya doğru akışını gösterir."},{"q":"Otçul (herbivor) ve etçil (karnivor) tüketici ne demektir?","steps":[{"t":"Otçul","a":"bitki yer","d":"Sadece bitkilerle beslenen hayvanlara otçul (herbivor) denir; örnek tavşan."},{"t":"Etçil","a":"et yer","d":"Başka hayvanları yiyerek beslenen hayvanlara etçil (karnivor) denir; örnek tilki."}],"ans":"Otçullar bitkilerle, etçiller başka hayvanlarla (etle) beslenir."},{"q":"Besin zinciri ile besin ağı arasındaki fark nedir?","steps":[{"t":"Besin zinciri","a":"tek sıra","d":"Besin zinciri canlıların tek bir beslenme sırasını gösterir."},{"t":"Besin ağı","a":"çok zincir","d":"Besin ağı, birbiriyle bağlantılı birçok besin zincirinin birleşimidir."}],"ans":"Besin zinciri tek bir beslenme sırasıdır; besin ağı ise birçok zincirin birleştiği geniş bir ağdır."},{"q":"ot → çekirge → kurbağa → yılan zincirinde kaç canlı vardır ve üretici hangisidir?","steps":[{"t":"Canlıları say","a":"4 canlı","d":"Zincirde ot, çekirge, kurbağa ve yılan olmak üzere dört canlı vardır."},{"t":"Üreticiyi bul","a":"ot","d":"Kendi besinini üreten ot, zincirin üreticisidir."}],"ans":"Zincirde 4 canlı vardır; üretici olan canlı ottur."}],"zor":[{"q":"Bir besin ağında bir tür kaybolursa neden tek bir tür değil birçok tür etkilenir?","steps":[{"t":"Ağdaki bağlar","a":"çok bağlantı","d":"Besin ağında her tür birden fazla türle beslenme ilişkisi içindedir."},{"t":"Etkinin yayılması","a":"zincirler bağlı","d":"Bir tür gidince ona bağlı tüm zincirler aynı anda sarsılır."},{"t":"Sonuç","a":"birçok tür etkilenir","d":"Bağlantılar yüzünden etki yayılır ve çok sayıda tür etkilenir."}],"ans":"Besin ağındaki türler çok sayıda bağlantıyla birbirine bağlı olduğundan, bir türün kaybı bu bağlar üzerinden birçok türe yayılır."},{"q":"Besin ağı, basit bir besin zincirine göre neden daha kararlı (dayanıklı) bir yapıdır?","steps":[{"t":"Alternatif besin","a":"çok seçenek","d":"Ağda bir tüketicinin yiyebileceği birden fazla besin türü vardır."},{"t":"Bir tür azalırsa","a":"başka türe geçer","d":"Bir besin türü azalınca tüketici başka bir türle beslenebilir."},{"t":"Sonuç","a":"daha kararlı","d":"Yedek bağlantılar olduğu için ağ kolay kolay çökmez, kararlıdır."}],"ans":"Besin ağında alternatif besin yolları bulunduğundan bir tür azalsa bile tüketiciler başka türlere geçebilir; bu nedenle ağ tek bir zincirden daha kararlıdır."},{"q":"Çekirge → kuş → şahin sıralamasında enerji neden her basamakta azalır?","steps":[{"t":"Enerjinin kaynağı","a":"yenen besin","d":"Her canlı enerjiyi bir önceki basamağı yiyerek alır."},{"t":"Enerji kaybı","a":"ısı ve hareket","d":"Alınan enerjinin çoğu solunum, hareket ve ısı olarak harcanır."},{"t":"Sonuç","a":"üst basamağa az kalır","d":"Geriye az enerji kaldığı için her üst basamakta enerji azalır."}],"ans":"Her canlı aldığı enerjinin çoğunu yaşamsal işlerde harcadığından bir üst basamağa daha az enerji aktarılır, böylece enerji giderek azalır."},{"q":"Bir tarladaki tüm baykuşlar avlanırsa fare ve buğday nasıl etkilenir (buğday → fare → baykuş)?","steps":[{"t":"Fareyi kim yiyordu","a":"baykuş","d":"Baykuş fareleri avlayarak sayısını dengeliyordu."},{"t":"Baykuş gidince","a":"fare çoğalır","d":"Avcısı kalmayan fareler hızla çoğalır."},{"t":"Buğdaya etkisi","a":"buğday azalır","d":"Çoğalan fareler buğdayı aşırı yer, ürün azalır."}],"ans":"Baykuş yok olunca fareler çoğalır, çoğalan fareler buğdayı aşırı tükettiği için buğday miktarı azalır."},{"q":"Bir besin ağında ayrıştırıcılar çalışmazsa madde döngüsü nasıl etkilenir?","steps":[{"t":"Ayrıştırıcının görevi","a":"ölüleri çürütür","d":"Ayrıştırıcılar ölü canlıları ve atıkları parçalayıp toprağa katar."},{"t":"Çalışmazlarsa","a":"madde dönmez","d":"Ölü canlılar çürümez, içlerindeki madde toprağa geri dönemez."},{"t":"Sonuç","a":"üretici beslenemez","d":"Toprak besin maddesi açısından fakirleşir, bitkiler zorlanır."}],"ans":"Ayrıştırıcılar çalışmazsa ölü canlılardaki maddeler toprağa geri dönmez, toprak fakirleşir ve üreticiler yeterli besin bulamaz."}]},"lise":{"kolay":[{"q":"Besin zinciri ile besin ağı arasındaki temel fark nedir?","steps":[{"t":"Besin zinciri","a":"doğrusal sıra","d":"Besin zinciri, enerjinin tek bir doğrultuda aktarıldığı doğrusal bir beslenme dizisidir."},{"t":"Besin ağı","a":"bağlantılı zincirler","d":"Besin ağı, bir ekosistemdeki çok sayıda besin zincirinin kesiştiği karmaşık bir yapıdır."}],"ans":"Besin zinciri doğrusal tek bir beslenme sırası, besin ağı ise birçok zincirin kesiştiği karmaşık beslenme ilişkileri bütünüdür."},{"q":"Besin zincirinde 'trofik düzey' (beslenme basamağı) ne anlama gelir?","steps":[{"t":"Tanım","a":"beslenme konumu","d":"Trofik düzey, bir canlının besin zincirinde işgal ettiği beslenme basamağıdır."},{"t":"Örnek sıralama","a":"üretici→tüketici","d":"1. düzey üretici, 2. düzey otçul, 3. düzey birincil etçildir."}],"ans":"Trofik düzey, bir canlının besin zincirindeki beslenme basamağıdır (üretici, otçul, etçil gibi)."},{"q":"Birincil, ikincil ve üçüncül tüketici nasıl ayırt edilir?","steps":[{"t":"Birincil tüketici","a":"otçul","d":"Doğrudan üreticiyi (bitkiyi) yiyen otçul, birincil tüketicidir."},{"t":"İkincil ve üçüncül","a":"etçiller","d":"Otçulu yiyen etçil ikincil, ikincil tüketiciyi yiyen ise üçüncül tüketicidir."}],"ans":"Üreticiyi yiyen birincil, onu yiyen ikincil, ikinciyi yiyen üçüncül tüketicidir."},{"q":"Besin ağında okların yönü neyin akış yönünü temsil eder?","steps":[{"t":"Okun anlamı","a":"madde-enerji akışı","d":"Her ok, besin yoluyla aktarılan madde ve enerjinin yönünü gösterir."},{"t":"Yön","a":"yenenden yiyene","d":"Ok daima av/besinden onu tüketen canlıya, yani enerjinin aktığı yöne çizilir."}],"ans":"Oklar, besinle taşınan madde ve enerjinin yenen canlıdan onu tüketen canlıya doğru akış yönünü gösterir."},{"q":"Anahtar tür (keystone species) kavramı ne anlama gelir?","steps":[{"t":"Tanım","a":"belirleyici tür","d":"Anahtar tür, sayısı az olsa bile ekosistemin yapısını orantısız biçimde belirleyen türdür."},{"t":"Etkisi","a":"denge tutucu","d":"Bu tür çıkarılırsa besin ağının yapısı kökten değişir."}],"ans":"Anahtar tür, az sayıda olsa bile besin ağının yapısını ve dengesini orantısız biçimde belirleyen türdür."},{"q":"Otçul (herbivor) ve etçil (karnivor) beslenme arasındaki bağlantı besin ağında nasıl görünür?","steps":[{"t":"Otçul bağlantısı","a":"üreticiye bağlı","d":"Otçullar ağda doğrudan üreticilere ok ile bağlanır."},{"t":"Etçil bağlantısı","a":"otçula bağlı","d":"Etçiller ise otçullara veya başka etçillere ok ile bağlanır."}],"ans":"Besin ağında otçullar üreticilere, etçiller ise otçullara veya diğer etçillere oklarla bağlanarak beslenme ilişkisini gösterir."},{"q":"Hem bitki hem hayvan yiyen canlılara ne ad verilir ve besin ağındaki rolü nedir?","steps":[{"t":"Tanım","a":"omnivor","d":"Hem bitki hem hayvanla beslenen canlılara omnivor (hepçil) denir."},{"t":"Ağdaki rolü","a":"çok bağlantı","d":"Birden fazla trofik düzeyle bağlantı kurarak ağı daha karmaşık hale getirir."}],"ans":"Hem bitki hem hayvan yiyen canlılar omnivordur; birden çok trofik düzeyle bağ kurarak besin ağını daha karmaşık kılar."},{"q":"Besin zincirinin uzunluğu neden genellikle 4-5 basamakla sınırlıdır?","steps":[{"t":"Enerji kaybı","a":"%90 kayıp","d":"Her trofik düzeyde enerjinin yaklaşık onda dokuzu ısı ve metabolizmayla kaybolur."},{"t":"Üst basamak","a":"enerji yetmez","d":"Üst basamaklarda canlıyı doyuracak enerji kalmadığı için zincir kısa kalır."}],"ans":"Her basamakta enerjinin büyük kısmı kaybolduğundan üst basamaklara yeterli enerji ulaşamaz; bu yüzden zincir genelde 4-5 basamakla sınırlıdır."},{"q":"Besin ağının karmaşıklığı (tür ve bağlantı sayısı) ile kararlılığı arasında nasıl bir ilişki vardır?","steps":[{"t":"Çok bağlantı","a":"alternatif yollar","d":"Tür ve bağlantı arttıkça tüketiciler için alternatif besin yolları çoğalır."},{"t":"Sonuç","a":"daha kararlı","d":"Bir bağlantı koptuğunda diğerleri devreye girdiği için ağ daha dayanıklı olur."}],"ans":"Bağlantısı bol, türce zengin besin ağları alternatif beslenme yolları sunduğundan genelde daha kararlı ve dış etkilere dayanıklıdır."},{"q":"Detritivor (artıkçıl) ve ayrıştırıcılar besin ağında hangi konumda yer alır?","steps":[{"t":"Beslendikleri madde","a":"ölü organik madde","d":"Bunlar ölü canlıları, dışkı ve artıkları tüketir."},{"t":"Ağdaki konum","a":"madde döngüsü","d":"Tüm trofik düzeylerden gelen ölü maddeyi parçalayıp inorganiğe çevirir."}],"ans":"Detritivor ve ayrıştırıcılar, tüm trofik düzeylerden gelen ölü organik maddeyi parçalayarak madde döngüsünü tamamlayan konumda yer alır."},{"q":"Bir besin ağında 'üst yırtıcı' (apeks yırtıcı) nedir?","steps":[{"t":"Tanım","a":"en üst basamak","d":"Üst yırtıcı, besin ağında doğal bir avcısı bulunmayan en üst tüketicidir."},{"t":"Örnek","a":"aslan, kartal","d":"Aslan, kartal, köpekbalığı gibi türler kendi ortamlarında üst yırtıcıdır."}],"ans":"Üst yırtıcı, besin ağının tepesinde yer alan ve doğal avcısı bulunmayan tüketicidir (aslan, kartal gibi)."},{"q":"Besin zincirinde enerjinin yönü ile maddenin (besinin) yönü aynı mıdır?","steps":[{"t":"Enerji yönü","a":"tek yönlü","d":"Enerji üreticiden tüketiciye doğru tek yönlü akar ve geri dönmez."},{"t":"Madde yönü","a":"döngüsel","d":"Madde ise ayrıştırıcılarla tekrar üreticilere döndüğü için döngüseldir."}],"ans":"Besin zincirinde enerji tek yönlü akarken madde, ayrıştırıcılar sayesinde döngüsel olarak yeniden kullanılır."},{"q":"Bir besin ağında okların başlangıç noktasının hep üretici olmasının nedeni nedir?","steps":[{"t":"Enerji girişi","a":"üreticiden","d":"Güneş enerjisi ekosisteme yalnızca üreticilerin fotosenteziyle girer."},{"t":"Akışın başı","a":"üretici","d":"Bu nedenle tüm beslenme okları doğrudan veya dolaylı üreticiden başlar."}],"ans":"Ekosisteme enerji yalnızca üreticilerin fotosenteziyle girdiğinden, besin ağındaki tüm oklar köken olarak üreticilerden başlar."},{"q":"Aynı türün besin ağında birden fazla trofik düzeyde yer alması mümkün müdür?","steps":[{"t":"Çeşitli beslenme","a":"farklı besinler","d":"Bir tür hem otçul hem de başka hayvanları yiyen bir besinle beslenebilir."},{"t":"Sonuç","a":"birden çok düzey","d":"Bu durumda tür birden fazla trofik düzeyde aynı anda yer alır (omnivor)."}],"ans":"Evet; bir omnivor hem bitkiyle hem hayvanla beslenerek aynı anda birden fazla trofik düzeyde yer alabilir."},{"q":"Besin ağında 'rekabet' (besin için yarışma) nasıl ortaya çıkar?","steps":[{"t":"Ortak besin","a":"aynı avı yer","d":"İki farklı tür aynı besin kaynağına ok ile bağlıysa o besni paylaşmak zorundadır."},{"t":"Sonuç","a":"rekabet","d":"Sınırlı besin için bu türler arasında rekabet (yarışma) doğar."}],"ans":"İki tür besin ağında aynı besin kaynağına bağlı olduğunda o sınırlı kaynak için aralarında rekabet ortaya çıkar."}],"zor":[{"q":"Bir besin ağında anahtar bir yırtıcının (örneğin kurt) ortadan kalkması neden 'trofik kaskad' (basamaklı etki) ile sonuçlanır?","steps":[{"t":"Doğrudan etki","a":"otçul artar","d":"Kurt yok olunca avladığı otçul (geyik) sayısı denetimsiz artar."},{"t":"Dolaylı etki","a":"bitki azalır","d":"Aşırı artan geyikler bitki örtüsünü aşırı tüketir, üreticiler azalır."},{"t":"Kaskad","a":"basamaklar boyu yayılır","d":"Etki bir trofik düzeyden diğerine basamak basamak yayılarak tüm ağı değiştirir."}],"ans":"Anahtar yırtıcı kalkınca avı denetimsiz artar, bu da bir alt düzeydeki üreticileri azaltır; etki düzeyler boyunca basamaklı yayıldığı için buna trofik kaskad denir."},{"q":"Besin ağında bir türün kaybının 'dolaylı etkileri' doğrudan etkilerden neden daha öngörülmesi zor olabilir?","steps":[{"t":"Doğrudan etki","a":"komşu türler","d":"Doğrudan etki, kaybolan türle bağlantılı komşu türlerde hemen görülür."},{"t":"Dolaylı etki","a":"uzak türler","d":"Dolaylı etki, birkaç bağlantı ötedeki türlere rekabet ve avlanma değişimiyle ulaşır."},{"t":"Öngörü güçlüğü","a":"çok değişkenli","d":"Çok sayıda dolaylı bağ üzerinden yayıldığı için sonuç tahmin edilmesi güç olur."}],"ans":"Dolaylı etkiler, doğrudan bağlı olmayan uzak türlere çok sayıda ara bağlantı üzerinden ulaştığından, doğrudan etkilere göre çok daha değişken ve öngörülmesi zordur."},{"q":"Bir besin ağında bağlantı sayısının (connectance) yüksek olması ağın direncini (resilience) nasıl etkiler?","steps":[{"t":"Yüksek bağlantı","a":"yedek yollar","d":"Bağlantı yoğunluğu yüksekse her tüketicinin birden çok alternatif besin yolu vardır."},{"t":"Bir bağ koparsa","a":"telafi edilir","d":"Bir besin yolu kaybolsa bile tüketici başka bağlantılarla beslenmeyi sürdürür."},{"t":"Sonuç","a":"direnç artar","d":"Bu telafi yeteneği ağın bozulmaya karşı direncini (resilience) yükseltir."}],"ans":"Yüksek bağlantı sayısı, tüketicilere yedek beslenme yolları sağladığından bir bağ koptuğunda telafi edilebilir; bu da besin ağının dış bozulmalara karşı direncini artırır."},{"q":"Aynı kaynağı paylaşan iki tür arasındaki 'görünür rekabet' (apparent competition) ortak bir yırtıcı üzerinden nasıl oluşur?","steps":[{"t":"Ortak yırtıcı","a":"iki avı da yer","d":"Bir yırtıcı, A ve B türlerinin ikisini de avlıyorsa bu türler bir avcıyı paylaşır."},{"t":"Bir av artarsa","a":"yırtıcı çoğalır","d":"A türü artınca yırtıcı bollaşır ve dolaylı olarak B türünü de daha çok avlar."},{"t":"Sonuç","a":"B baskılanır","d":"İki tür doğrudan aynı besni yemese de ortak avcı üzerinden birbirini baskılar."}],"ans":"İki tür ortak bir yırtıcı tarafından avlandığında, birinin artması yırtıcıyı çoğaltıp diğerinin daha çok avlanmasına yol açar; bu dolaylı baskılamaya görünür rekabet denir."},{"q":"Besin ağında 'trofik düzeyler arası enerji aktarım verimi' neden ortalama %10 kabul edilir ve bu, üst yırtıcı sayısını nasıl sınırlar?","steps":[{"t":"Aktarım verimi","a":"yaklaşık %10","d":"Bir trofik düzeydeki enerjinin ortalama %10'u bir üst düzeye aktarılır."},{"t":"Kayıp nedeni","a":"solunum, ısı, sindirilemeyen","d":"Enerjinin geri kalanı solunum, ısı ve sindirilemeyen madde olarak kaybolur."},{"t":"Sonuç","a":"üst yırtıcı az","d":"Üst basamaklarda enerji çok azaldığı için üst yırtıcılar az sayıda ve büyük alana yayılır."}],"ans":"Her düzeyde enerjinin yalnızca yaklaşık %10'u üst düzeye aktarıldığından, tepedeki yırtıcılara çok az enerji ulaşır; bu da üst yırtıcı popülasyonlarını sayıca düşük ve geniş alana yayılmış tutar."},{"q":"Omnivorların (birden çok trofik düzeyde beslenenlerin) besin ağı kararlılığına katkısı nasıl açıklanır?","steps":[{"t":"Çoklu bağ","a":"farklı düzeyler","d":"Omnivor hem otçul hem etçil olarak farklı trofik düzeylere bağlanır."},{"t":"Esneklik","a":"besin değiştirir","d":"Bir besin kaynağı azalınca omnivor diğer düzeydeki kaynağa yönelir."},{"t":"Sonuç","a":"dalgalanma azalır","d":"Bu esneklik popülasyon dalgalanmalarını yumuşatarak ağı dengeler."}],"ans":"Omnivorlar farklı trofik düzeylere bağlandığından bir kaynak azaldığında diğerine geçebilir; bu esneklik popülasyon dalgalanmalarını yumuşatarak besin ağının kararlılığını artırır."},{"q":"Bir besin ağında 'aşağıdan yukarıya' (bottom-up) ve 'yukarıdan aşağıya' (top-down) denetim nasıl ayrılır?","steps":[{"t":"Aşağıdan yukarıya","a":"üretici denetler","d":"Üretici/besin miktarı, üst düzeylerin sayısını belirliyorsa denetim aşağıdan yukarıyadır."},{"t":"Yukarıdan aşağıya","a":"yırtıcı denetler","d":"Üst yırtıcı, alt düzeylerin sayısını avlanmayla belirliyorsa denetim yukarıdan aşağıyadır."},{"t":"Belirleyici","a":"hangi uç","d":"Hangi uçtaki değişimin ağı yönlendirdiği denetim tipini belirler."}],"ans":"Aşağıdan yukarıya denetimde besin/üretici miktarı üst düzeyleri belirler; yukarıdan aşağıya denetimde ise üst yırtıcılar avlanmayla alt düzeyleri belirler."},{"q":"Bir besin ağında üreticinin biyokütlesi neden tüm tüketicilerin toplam biyokütlesinden fazladır?","steps":[{"t":"Enerji tabanı","a":"üreticide en çok","d":"En fazla enerji ve biyokütle üretici düzeyinde toplanır."},{"t":"Aktarım kaybı","a":"%90 kaybolur","d":"Üst düzeylere geçerken enerjinin ve dolayısıyla biyokütlenin çoğu kaybolur."},{"t":"Sonuç","a":"piramit tabanı geniş","d":"Bu yüzden biyokütle piramidinde taban (üretici) en geniştir."}],"ans":"Enerji üst düzeylere geçerken büyük oranda kaybolduğundan, en çok biyokütle üretici düzeyinde birikir; bu nedenle üreticinin biyokütlesi tüm tüketicilerin toplamından fazladır."},{"q":"Yabancı (istilacı) bir yırtıcının besin ağına girmesi yerel türleri neden hızla çökertebilir?","steps":[{"t":"Ortak evrim yokluğu","a":"savunmasız av","d":"Yerel avlar bu yeni yırtıcıya karşı savunma ya da kaçınma davranışı geliştirmemiştir."},{"t":"Denetimsiz avlanma","a":"av hızla azalır","d":"Yırtıcının doğal düşmanı da olmadığından avını sınırsızca avlar."},{"t":"Sonuç","a":"ağ çöker","d":"Avın hızlı azalması bağlı türleri de etkileyerek ağı çökertir."}],"ans":"İstilacı yırtıcıya karşı yerel avlar savunma geliştirmediği ve yırtıcının yerel düşmanı bulunmadığı için avlanma denetimsiz olur; av popülasyonları hızla çöker ve etki ağa yayılır."},{"q":"Besin ağında 'işlevsel rolü aynı' (redundant) türlerin bulunması ekosisteme ne kazandırır?","steps":[{"t":"Benzer rol","a":"aynı işi yapan türler","d":"Birden fazla tür aynı trofik işlevi (örn. aynı avı yeme) görebilir."},{"t":"Biri kaybolursa","a":"diğeri yerini alır","d":"Bir tür yok olduğunda işlevsel olarak benzer tür onun rolünü üstlenir."},{"t":"Sonuç","a":"işlev korunur","d":"Bu işlevsel yedeklilik ekosistemin işleyişini tür kayıplarına karşı korur."}],"ans":"İşlevsel olarak benzer (redundant) türler bir tür kaybedildiğinde onun rolünü üstlenir; bu işlevsel yedeklilik, besin ağının işleyişini tür kayıplarına karşı tampon görevi görerek korur."},{"q":"Bir göl besin ağında besin (azot-fosfor) zenginleşmesi (ötrofikasyon) trofik düzeyleri nasıl etkiler?","steps":[{"t":"Aşırı besin","a":"alg patlaması","d":"Fazla azot ve fosfor üretici alglerin aşırı çoğalmasına yol açar."},{"t":"Oksijen azalması","a":"alglerin ölümü","d":"Ölen algleri ayrıştıran bakteriler suyun oksijenini tüketir."},{"t":"Sonuç","a":"tüketiciler ölür","d":"Oksijen düşünce balık gibi üst tüketiciler ölür, ağ çöker."}],"ans":"Ötrofikasyon önce üretici algleri patlatır; ölen alglerin ayrışması oksijeni tükettiği için balık gibi üst tüketiciler ölür ve besin ağı çöker."},{"q":"Besin ağında bir türün kaldırılmasının etkisinin büyüklüğü neden o türün 'bağlantı derecesine' (degree) bağlıdır?","steps":[{"t":"Bağlantı derecesi","a":"ok sayısı","d":"Bir türün bağlantı derecesi, ona gelen ve giden ok (beslenme bağı) sayısıdır."},{"t":"Çok bağlı tür","a":"geniş etki","d":"Çok sayıda türle bağlı bir tür kaldırılınca etki birçok türe aynı anda yansır."},{"t":"Az bağlı tür","a":"sınırlı etki","d":"Az bağlantılı bir türün kaybı ise yalnızca birkaç türü etkiler."}],"ans":"Bir türün bağlantı derecesi ne kadar yüksekse o tür o kadar çok türle ilişkilidir; bu nedenle çok bağlantılı bir türün kaybı etkiyi çok daha geniş bir alana yayar."},{"q":"Deniz besin ağında deniz su samurunun (anahtar tür) avlanması kelp ormanlarını neden yok eder?","steps":[{"t":"Samurun avı","a":"deniz kestanesi","d":"Su samuru, kelple beslenen deniz kestanelerini avlayarak sayısını sınırlar."},{"t":"Samur gidince","a":"kestane patlar","d":"Su samuru avlanınca deniz kestaneleri denetimsiz çoğalır."},{"t":"Sonuç","a":"kelp tükenir","d":"Aşırı çoğalan kestaneler kelpleri aşırı otlayarak kelp ormanlarını yok eder."}],"ans":"Su samuru, kelp yiyen deniz kestanelerini denetlediğinden, samur avlanınca kestaneler patlar ve kelp ormanlarını aşırı otlayarak yok eder; bu, anahtar türün trofik kaskad etkisidir."},{"q":"Besin ağı modellerinde 'döngüsel beslenme bağı' (örneğin A, B'yi; B de A'nın yavrusunu yer) kararlılığı nasıl etkileyebilir?","steps":[{"t":"Karşılıklı avlanma","a":"iki yönlü bağ","d":"İki tür birbirini farklı evrelerde avladığında ağda çift yönlü bağ oluşur."},{"t":"Geri besleme","a":"dengeleyici/bozucu","d":"Bu döngü, koşullara göre popülasyonları dengeleyen veya salınıma sokan geri besleme yaratır."},{"t":"Sonuç","a":"karmaşık dinamik","d":"Sonuçta tahmin edilmesi güç, salınımlı bir popülasyon dinamiği doğabilir."}],"ans":"Karşılıklı (döngüsel) avlanma bağları çift yönlü geri besleme yarattığından, koşullara göre popülasyonları dengeleyebilir ya da salınıma sokarak karmaşık ve öngörülmesi güç bir dinamik oluşturabilir."},{"q":"Bir kara besin ağında üst yırtıcının korunmasının (koruma biyolojisi) tüm ekosistem sağlığı için neden öncelikli görüldüğünü açıklayınız.","steps":[{"t":"Düzenleyici rol","a":"av sayısını tutar","d":"Üst yırtıcı, otçul ve orta düzey avcıların sayısını denetleyerek dengeyi korur."},{"t":"Kaskad koruması","a":"alt düzeyler korunur","d":"Yırtıcı korunursa aşırı otlanma ve mezopredatör patlaması engellenir, bitki örtüsü korunur."},{"t":"Sonuç","a":"ağ bütünlüğü","d":"Tek bir üst türün korunması basamaklı etkiyle tüm ağın bütünlüğünü güvence altına alır."}],"ans":"Üst yırtıcı, alt trofik düzeyleri trofik kaskad yoluyla düzenlediğinden, onun korunması aşırı otlanmayı ve mezopredatör patlamasını önler; böylece tek türün korunması tüm besin ağının sağlığını ve bütünlüğünü güvence altına alır."}]}},"biyotikAbiyotik":{"ilkokul":{"kolay":[{"q":"Bir göldeki balıklar canlı mıdır, yoksa cansız mıdır? Bu bir biyotik faktör müdür?","steps":[{"t":"Balık canlı mı?","a":"Canlı","d":"Balıklar nefes alan, büyüyen ve üreyen <b>canlı</b> varlıklardır."},{"t":"Biyotik mi?","a":"Evet, biyotik","d":"Bir ortamdaki canlı varlıklara <b>biyotik faktör</b> denir; balık da bir biyotik faktördür."}],"ans":"Balıklar canlıdır; bu yüzden gölde bir biyotik faktördür."},{"q":"Bir ormandaki güneş ışığı, taşlar ve su canlı mıdır? Bunlara ne ad verilir?","steps":[{"t":"Bunlar canlı mı?","a":"Cansız","d":"Güneş ışığı, taşlar ve su nefes almaz, büyümez; bunlar <b>cansızdır</b>."},{"t":"Ne denir?","a":"Abiyotik faktör","d":"Bir ortamdaki cansız varlıklara <b>abiyotik faktör</b> denir."}],"ans":"Bunlar cansızdır; ortamdaki cansız varlıklara abiyotik faktör denir."},{"q":"Bir saksı bitkisinin yaşaması için ışık gerekli midir?","steps":[{"t":"Bitki ışığı ne yapar?","a":"Besin üretir","d":"Bitkiler <b>ışık</b> yardımıyla kendi besinini yapar."},{"t":"Işık olmazsa?","a":"Yaşayamaz","d":"Yeterli ışık olmayınca bitki besin üretemez ve solar."}],"ans":"Evet; ışık abiyotik bir faktördür ve bitkinin yaşaması için gereklidir."},{"q":"Kurbağa böcek yer. Kurbağa ve böcek birer biyotik faktör müdür?","steps":[{"t":"İkisi de canlı mı?","a":"Evet","d":"Hem kurbağa hem böcek <b>canlıdır</b>."},{"t":"Biyotik mi?","a":"Evet","d":"Canlı varlıklar biyotik faktördür; birbirini etkileyen kurbağa ve böcek de biyotiktir."}],"ans":"Evet; kurbağa ve böcek canlı oldukları için ikisi de biyotik faktördür."},{"q":"Çölde hava çok sıcaktır. Sıcaklık biyotik mi yoksa abiyotik bir faktör müdür?","steps":[{"t":"Sıcaklık canlı mı?","a":"Cansız","d":"Sıcaklık bir canlı değildir; havanın bir <b>özelliğidir</b>."},{"t":"Hangi grup?","a":"Abiyotik","d":"Cansız faktörler abiyotik grubuna girer; sıcaklık da abiyotiktir."}],"ans":"Sıcaklık cansızdır; bu yüzden abiyotik bir faktördür."}],"zor":[{"q":"Bir kuş ağaçta yuva yapıyor. Bu olayda biyotik faktörleri ve abiyotik faktörleri ayırabilir misin?","steps":[{"t":"Canlılar hangisi?","a":"Kuş ve ağaç","d":"Kuş bir hayvandır, ağaç bir bitkidir; ikisi de <b>canlıdır</b> (biyotik)."},{"t":"Cansızlar hangisi?","a":"Hava, ışık, ısı","d":"Yuvanın çevresindeki hava, güneş ışığı ve sıcaklık <b>cansızdır</b> (abiyotik)."}],"ans":"Kuş ve ağaç biyotik; çevresindeki hava, ışık ve sıcaklık abiyotik faktörlerdir."},{"q":"Hiç su olmayan kuru bir toprağa ekilen tohum neden filizlenmez?","steps":[{"t":"Tohuma ne gerekli?","a":"Su","d":"Tohumun uyanıp büyümesi için <b>su</b> gerekir."},{"t":"Su yoksa?","a":"Filizlenmez","d":"Kuru toprakta su olmadığı için tohum çimlenemez."}],"ans":"Su abiyotik bir faktördür; olmayınca tohum filizlenemez."},{"q":"Solucanlar toprağı havalandırıp besler. Solucan toprak için neden önemli bir biyotik faktördür?","steps":[{"t":"Solucan canlı mı?","a":"Evet, canlı","d":"Solucan bir <b>canlıdır</b>, yani biyotik faktördür."},{"t":"Ne yapar?","a":"Toprağı iyileştirir","d":"Toprağı kazıp havalandırır ve bitkilere yarayan madde bırakır."}],"ans":"Solucan canlı bir biyotik faktördür; toprağı havalandırıp besleyerek bitkilere yardım eder."},{"q":"İki bahçeden biri güneşli, diğeri sürekli gölgede. Hangisindeki bitkiler daha iyi büyür ve neden?","steps":[{"t":"Hangisi ışık alır?","a":"Güneşli bahçe","d":"Güneşli bahçedeki bitkiler bol <b>ışık</b> alır."},{"t":"Sonuç","a":"Güneşli olan","d":"Bol ışıkta bitkiler daha çok besin üretip daha iyi büyür."}],"ans":"Güneşli bahçedeki bitkiler daha iyi büyür; çünkü ışık (abiyotik faktör) boldur."},{"q":"Bir kutup ayısının çölde, bir devenin kutupta yaşaması zordur. Bunun nedeni hangi cansız faktördür?","steps":[{"t":"Fark eden ne?","a":"Sıcaklık","d":"Çöl çok sıcak, kutup çok soğuktur; aralarındaki fark <b>sıcaklıktır</b>."},{"t":"Hangi grup?","a":"Abiyotik","d":"Sıcaklık cansız bir faktördür; her canlı kendi sıcaklığına uygun yerde yaşar."}],"ans":"Sıcaklık abiyotik bir faktördür; her hayvan kendine uygun sıcaklıktaki ortamda yaşar."}]},"ortaokul":{"kolay":[{"q":"Biyotik ve abiyotik faktör ne demektir? Aralarındaki fark nedir?","steps":[{"t":"Biyotik","a":"Canlı faktörler","d":"Bir ekosistemdeki tüm <b>canlılar</b> (bitki, hayvan, mantar, bakteri) biyotik faktördür."},{"t":"Abiyotik","a":"Cansız faktörler","d":"Işık, sıcaklık, su, toprak, mineral gibi <b>cansız</b> ögeler abiyotik faktördür."}],"ans":"Biyotik faktörler canlı, abiyotik faktörler cansız ögelerdir; fark canlı olup olmamalarıdır."},{"q":"Üretici, tüketici ve ayrıştırıcı nedir? Hepsi biyotik faktör müdür?","steps":[{"t":"Görevleri","a":"Besin yapma/kullanma/ayrıştırma","d":"Üretici besin yapar, tüketici hazır besin alır, ayrıştırıcı ölü maddeyi <b>parçalar</b>."},{"t":"Biyotik mi?","a":"Evet, hepsi","d":"Üçü de canlı olduğu için tamamı biyotik faktördür."}],"ans":"Üretici, tüketici ve ayrıştırıcının üçü de canlı olduğu için biyotik faktördür."},{"q":"Sıcaklığın canlılar üzerindeki etkisine bir örnek veriniz.","steps":[{"t":"Sıcaklık neyi etkiler?","a":"Yaşam etkinliği","d":"Sıcaklık, canlıların büyüme, üreme ve <b>aktivite</b> hızını etkiler."},{"t":"Örnek","a":"Kış uykusu","d":"Soğukta bazı hayvanlar kış uykusuna yatar, bitkiler yapraklarını döker."}],"ans":"Sıcaklık abiyotik bir faktördür; örneğin soğukta hayvanlar kış uykusuna yatabilir."},{"q":"Toprağın pH değeri bitkiler için neden önemli bir abiyotik faktördür?","steps":[{"t":"pH nedir?","a":"Asit-baz ölçüsü","d":"pH, toprağın <b>asitlik</b> veya bazlık derecesini gösterir."},{"t":"Bitkiye etkisi","a":"Mineral alımı","d":"Her bitki belli bir pH aralığında topraktan minerali iyi alabilir; uygun değilse iyi gelişemez."}],"ans":"pH abiyotik bir faktördür; toprağın asitliğini belirler ve bitkinin mineral alımını etkiler."},{"q":"Su, canlılar için neden vazgeçilmez bir abiyotik faktördür?","steps":[{"t":"Su nerede kullanılır?","a":"Tüm yaşam olayları","d":"Su, hücre içindeki <b>tepkimeler</b>, taşıma ve sıcaklık dengesi için gereklidir."},{"t":"Su yoksa?","a":"Yaşam durur","d":"Su olmadan hücreler çalışamaz; bu yüzden su yaşam için zorunludur."}],"ans":"Su abiyotik bir faktördür; tüm yaşam olayları için gerekli olduğundan vazgeçilmezdir."}],"zor":[{"q":"Bir gölde balık sayısı azalınca onunla beslenen kuşların da azalması hangi tür faktörle açıklanır?","steps":[{"t":"Balık ve kuş ne?","a":"Canlı","d":"Balık ve kuş <b>canlı</b> olduğu için biyotik faktördür."},{"t":"Etkileşim","a":"Beslenme ilişkisi","d":"Kuşlar balıkla beslendiği için besin azalınca kuş sayısı da düşer."}],"ans":"Bu, biyotik faktörlerin (beslenme ilişkisinin) birbirini etkilemesiyle açıklanır."},{"q":"Sınırlayıcı faktör nedir? Çölde bir bitki için hangi faktör sınırlayıcı olabilir?","steps":[{"t":"Tanım","a":"En yetersiz faktör","d":"Bir canlının yaşamasını ya da çoğalmasını en çok kısıtlayan, ortamda <b>en yetersiz</b> faktördür."},{"t":"Çölde","a":"Su","d":"Çölde su çok az olduğundan bitki için sınırlayıcı faktör genellikle sudur."}],"ans":"Sınırlayıcı faktör, yaşamı en çok kısıtlayan yetersiz faktördür; çölde bu genellikle sudur."},{"q":"Ayrıştırıcılar olmasaydı bir ormanda ne olurdu? Bunların biyotik önemi nedir?","steps":[{"t":"Ayrıştırıcı görevi","a":"Ölüyü parçalar","d":"Bakteri ve mantar gibi ayrıştırıcılar ölü canlıları ve atıkları <b>parçalar</b>."},{"t":"Olmasaydı","a":"Madde birikir","d":"Ölü maddeler ayrışmaz, mineraller toprağa dönmez ve üreticiler bunları kullanamazdı."}],"ans":"Ayrıştırıcılar biyotik faktördür; olmasaydı ölü madde birikir, mineraller toprağa dönmez ve döngü bozulurdu."},{"q":"Işık miktarı bir gölde derinliğe inildikçe azalır. Bu durum üreticilerin dağılımını nasıl etkiler?","steps":[{"t":"Üretici neye muhtaç?","a":"Işık","d":"Su bitkileri ve algler üretici olarak fotosentez için <b>ışığa</b> ihtiyaç duyar."},{"t":"Derinde","a":"Işık az","d":"Derinlere ışık az ulaştığı için üreticiler çoğunlukla yüzeye yakın bölgede yaşar."}],"ans":"Işık abiyotik bir sınırlayıcı faktördür; az ışık nedeniyle üreticiler gölün yüzeye yakın kısmında yoğunlaşır."},{"q":"Toprakta azot ve fosfor gibi minerallerin azalması bitkileri neden olumsuz etkiler?","steps":[{"t":"Mineral ne için gerekli?","a":"Yapı maddesi","d":"Azot ve fosfor, protein ve <b>DNA</b> gibi temel yapı maddelerinin üretiminde kullanılır."},{"t":"Eksik olursa","a":"Gelişim bozulur","d":"Mineral yetersizliğinde bitki yeterince büyüyemez, yaprakları sararır ve verim düşer."}],"ans":"Mineraller abiyotik faktördür; azlığında bitki yapı maddesi üretemez, gelişimi ve verimi düşer."}]},"lise":{"kolay":[{"q":"Biyotik ve abiyotik faktörler ekosistemde nasıl tanımlanır?","steps":[{"t":"Biyotik","a":"Canlı bileşenler","d":"Bir ekosistemdeki üreticiler, tüketiciler ve ayrıştırıcılar gibi tüm <b>canlı</b> bileşenlerdir."},{"t":"Abiyotik","a":"Cansız bileşenler","d":"Işık, sıcaklık, su, toprak, pH, mineral, nem gibi <b>cansız</b> çevre bileşenleridir."}],"ans":"Biyotik faktörler ekosistemin canlı, abiyotik faktörler ise cansız bileşenleridir."},{"q":"Üretici, tüketici ve ayrıştırıcıların ekosistemdeki rolleri nedir?","steps":[{"t":"Üretici","a":"Besin sentezler","d":"Fotosentez ya da kemosentezle inorganik maddeden <b>organik besin</b> üretir."},{"t":"Tüketici ve ayrıştırıcı","a":"Tüketir ve parçalar","d":"Tüketiciler hazır organik besinle beslenir; ayrıştırıcılar ölü maddeyi parçalayıp mineralleri toprağa döndürür."}],"ans":"Üreticiler besin üretir, tüketiciler bu besinle beslenir, ayrıştırıcılar ölü maddeyi parçalayıp madde döngüsünü sürdürür."},{"q":"Sınırlayıcı faktör kavramını ve Liebig'in Minimum Yasası'nı açıklayınız.","steps":[{"t":"Sınırlayıcı faktör","a":"En yetersiz faktör","d":"Bir canlının ya da popülasyonun gelişimini en çok kısıtlayan, gereksinime göre <b>en yetersiz</b> bulunan faktördür."},{"t":"Liebig yasası","a":"Minimum belirler","d":"Liebig'in Minimum Yasası'na göre verimi, miktarı ihtiyaca göre en az olan kaynak belirler."}],"ans":"Sınırlayıcı faktör gelişimi en çok kısıtlayan yetersiz faktördür; Liebig'in Minimum Yasası'na göre verimi en az bulunan kaynak belirler."},{"q":"Sıcaklığın canlı metabolizması üzerindeki etkisi nasıl açıklanır?","steps":[{"t":"Metabolizmayı kim yürütür?","a":"Enzimler","d":"Metabolik tepkimeleri <b>enzimler</b> katalizler ve enzim hızı sıcaklığa bağlıdır."},{"t":"Sıcaklık etkisi","a":"Optimuma kadar artar","d":"Belli bir optimuma kadar sıcaklık arttıkça metabolizma hızlanır; çok yüksek sıcaklıkta enzimler denatüre olur."}],"ans":"Sıcaklık enzim aktivitesini etkiler; optimuma kadar metabolizmayı hızlandırır, aşırı sıcakta enzim denatürasyonuyla yavaşlatır."},{"q":"Suyun bir abiyotik faktör olarak canlılar için önemi nelerdir?","steps":[{"t":"Hücresel rol","a":"Çözücü ve ortam","d":"Su, hücredeki tepkimeler için <b>çözücü</b> ve taşıma ortamıdır; pek çok tepkimeye doğrudan katılır."},{"t":"Dağılıma etki","a":"Yayılışı sınırlar","d":"Suyun bol veya kıt olması, canlıların hangi bölgede yaşayabileceğini belirleyen önemli bir etkendir."}],"ans":"Su hücresel tepkimeler için çözücü ve ham maddedir; ayrıca miktarı canlıların yayılışını belirleyen sınırlayıcı bir abiyotik faktördür."},{"q":"Toprak pH'sının bitki beslenmesi üzerindeki etkisi nedir?","steps":[{"t":"pH neyi belirler?","a":"Mineral çözünürlüğü","d":"Toprak pH'sı, minerallerin suda <b>çözünüp</b> bitki köküne alınabilirliğini belirler."},{"t":"Uygun olmazsa","a":"Mineral alınamaz","d":"Çok asidik ya da çok bazik toprakta bazı mineraller bitkiye erişilemez hale gelir, beslenme bozulur."}],"ans":"Toprak pH'sı minerallerin çözünürlüğünü ve bitki tarafından alınabilirliğini etkiler; uygun olmayan pH'da beslenme bozulur."},{"q":"Işık şiddeti ve süresinin (fotoperiyot) canlılar üzerindeki etkisine örnek veriniz.","steps":[{"t":"Işık şiddeti","a":"Fotosentezi etkiler","d":"Işık şiddeti üreticilerin <b>fotosentez</b> hızını ve dolayısıyla besin üretimini belirler."},{"t":"Fotoperiyot","a":"Mevsimsel davranış","d":"Gece-gündüz süresi (fotoperiyot), bitkilerde çiçeklenmeyi, hayvanlarda göç ve üremeyi tetikler."}],"ans":"Işık şiddeti fotosentezi belirler; fotoperiyot ise çiçeklenme, göç ve üreme gibi mevsimsel olayları düzenler."},{"q":"Nem (atmosferik su buharı) karasal canlılar için neden önemli bir abiyotik faktördür?","steps":[{"t":"Nem neyi etkiler?","a":"Su kaybı","d":"Havadaki nem oranı, canlıların terleme ve <b>su kaybı</b> hızını belirler."},{"t":"Düşük nemde","a":"Hızlı su kaybı","d":"Nem düşükse karasal canlılar daha hızlı su kaybeder; bu yüzden kurak bölge canlıları su tutma uyumları geliştirir."}],"ans":"Nem, canlıların su kaybı hızını etkiler; düşük nemde su kaybı arttığından kurak ortam canlıları su tutma uyumları geliştirir."},{"q":"Bir ekosistemde abiyotik faktörler biyotik faktörlerin dağılımını nasıl belirler?","steps":[{"t":"Abiyotik belirleyici","a":"Yaşam koşulu","d":"Sıcaklık, su, ışık ve toprak gibi <b>abiyotik</b> koşullar bir bölgede hangi canlıların yaşayabileceğini sınırlar."},{"t":"Sonuç","a":"Tür dağılımı","d":"Her tür kendine uygun abiyotik koşulların bulunduğu yerde yaşar; böylece türlerin coğrafi dağılımı şekillenir."}],"ans":"Abiyotik faktörler bir bölgenin yaşam koşullarını belirler; her tür kendine uygun koşulların olduğu yerde bulunduğundan tür dağılımını şekillendirir."},{"q":"Ototrof (üretici) ve heterotrof (tüketici) canlılar arasındaki temel fark nedir?","steps":[{"t":"Ototrof","a":"Kendi besinini yapar","d":"Ototroflar inorganik maddeden organik besin <b>sentezler</b> (fotosentez veya kemosentez)."},{"t":"Heterotrof","a":"Hazır besin alır","d":"Heterotroflar besinini kendileri üretemez; doğrudan ya da dolaylı olarak üreticilerden alır."}],"ans":"Ototroflar kendi organik besinini sentezleyen üreticilerdir; heterotroflar besinini dışarıdan alan tüketicilerdir."},{"q":"Tolerans aralığı ve optimum aralık kavramları bir abiyotik faktör için neyi ifade eder?","steps":[{"t":"Tolerans aralığı","a":"Yaşanabilir sınırlar","d":"Bir türün belirli bir faktörün (ör. sıcaklık) hangi <b>alt ve üst sınırları</b> arasında yaşayabildiğidir."},{"t":"Optimum aralık","a":"En iyi gelişim","d":"Bu aralığın içinde türün en hızlı büyüyüp ürediği, en verimli olduğu daha dar bölge optimum aralıktır."}],"ans":"Tolerans aralığı türün bir faktöre dayanabildiği alt-üst sınırlar; optimum aralık ise bu aralık içinde en iyi geliştiği dar bölgedir."},{"q":"Kemosentetik üreticiler ışıksız ortamda nasıl üretici olabilir?","steps":[{"t":"Enerji kaynağı","a":"Kimyasal enerji","d":"Kemosentetik bakteriler ışık yerine inorganik maddelerin <b>oksitlenmesinden</b> açığa çıkan kimyasal enerjiyi kullanır."},{"t":"Sonuç","a":"Organik besin üretimi","d":"Bu enerjiyle inorganik maddelerden organik besin üretir; bu yüzden ışıksız (ör. derin deniz) ortamlarda üretici olabilirler."}],"ans":"Kemosentetik bakteriler ışık yerine inorganik maddelerin oksitlenmesinden elde ettikleri kimyasal enerjiyle besin üretip ışıksız ortamlarda üretici olur."},{"q":"Mineral maddelerin (azot, fosfor, magnezyum) canlılar için biyolojik önemi nedir?","steps":[{"t":"Yapısal rol","a":"Molekül yapısı","d":"Azot proteinlerin ve nükleik asitlerin, fosfor ATP ve DNA'nın, magnezyum klorofilin <b>yapısına</b> katılır."},{"t":"Eksiklikte","a":"İşlev bozulur","d":"Bu mineraller yetersiz olduğunda ilgili moleküller üretilemez ve metabolizma ile büyüme bozulur."}],"ans":"Azot, fosfor ve magnezyum protein, nükleik asit, ATP ve klorofil gibi temel moleküllerin yapısına katılır; eksikliklerinde metabolizma ve büyüme bozulur."},{"q":"Karasal bir ekosistemde sıcaklık ve yağış miktarının birlikte değerlendirilmesi neden önemlidir?","steps":[{"t":"İki faktör birlikte","a":"İklim tipini belirler","d":"Sıcaklık ve yağış birlikte bir bölgenin <b>iklimini</b> ve toprak nemini belirler."},{"t":"Sonuç","a":"Biyom tipi","d":"Bu iki abiyotik faktörün birleşimi, çöl, orman veya tundra gibi hangi biyomun oluşacağını belirler."}],"ans":"Sıcaklık ve yağış birlikte iklimi belirler; bu abiyotik birleşim bir bölgede oluşacak biyom tipini (çöl, orman, tundra) tayin eder."},{"q":"Sınırlayıcı faktör, bir popülasyonun taşıma kapasitesini nasıl belirler?","steps":[{"t":"Taşıma kapasitesi","a":"En çok birey sayısı","d":"Bir ortamın sürekli barındırabileceği <b>en yüksek birey</b> sayısıdır."},{"t":"Sınırlayıcının rolü","a":"Tavanı belirler","d":"Su, besin veya alan gibi en yetersiz (sınırlayıcı) kaynak, bu sayının üst sınırını belirler."}],"ans":"Taşıma kapasitesi bir ortamın barındırabileceği en yüksek birey sayısıdır; en yetersiz sınırlayıcı kaynak bu sayının üst sınırını belirler."}],"zor":[{"q":"Liebig'in Minimum Yasası ile Shelford'un Tolerans Yasası'nı karşılaştırarak sınırlayıcı faktörü açıklayınız.","steps":[{"t":"Liebig yasası","a":"Yetersizlik sınırlar","d":"Liebig'e göre verimi, ihtiyaca göre <b>en az</b> bulunan tek bir kaynak (ör. mineral) sınırlar."},{"t":"Shelford yasası","a":"Hem azlık hem çokluk","d":"Shelford'a göre bir faktör yalnız yetersizliğiyle değil, <b>fazlalığıyla</b> da (tolerans sınırlarının dışına çıkınca) sınırlayıcı olabilir."},{"t":"Birleşik bakış","a":"Geniş sınırlayıcı kavramı","d":"Birlikte değerlendirildiğinde sınırlayıcı faktör, hem alttan hem üstten tolerans sınırlarını aşan herhangi bir faktör olabilir."}],"ans":"Liebig sadece yetersizliğe, Shelford hem yetersizlik hem aşırılığa odaklanır; birlikte sınırlayıcı faktörün hem az hem çok olduğunda gelişimi kısıtlayabildiğini gösterir."},{"q":"Bir tür için sıcaklık tolerans eğrisinin çan şeklinde olmasını alt sınır, optimum ve üst sınır bölgeleriyle açıklayınız.","steps":[{"t":"Alt sınır","a":"Metabolizma yavaş","d":"Düşük sıcaklıkta enzim aktivitesi <b>düşüktür</b>; metabolizma yavaşladığı için yaşamsal etkinlik azalır."},{"t":"Optimum","a":"En yüksek verim","d":"Optimum sıcaklıkta enzimler en verimli çalışır, büyüme ve üreme en yüksektir."},{"t":"Üst sınır","a":"Denatürasyon","d":"Yüksek sıcaklıkta proteinler denatüre olur, hücre işlevi bozulur ve birey ölebilir."}],"ans":"Çan eğrisi; alt sınırda yavaş metabolizma, optimumda en yüksek verim, üst sınırda enzim denatürasyonuyla işlev kaybını yansıtır."},{"q":"Bir gölde besin (azot-fosfor) artışının ötrofikasyona yol açıp oksijeni düşürmesini biyotik ve abiyotik etkileşimle açıklayınız.","steps":[{"t":"Mineral artışı","a":"Alg patlaması","d":"Azot ve fosfor artınca üretici algler aşırı çoğalır; bu <b>alg patlaması</b> (su çiçeklenmesi) olarak görülür."},{"t":"Ayrışma","a":"Oksijen tüketimi","d":"Ölen alglerin bol organik maddesi ayrıştırıcı bakterilerce parçalanırken çok miktarda <b>oksijen</b> tüketilir."},{"t":"Sonuç","a":"Oksijensizlik","d":"Suda oksijen düşer; balık ve diğer canlılar ölür, ekosistem dengesi bozulur."}],"ans":"Mineral artışı abiyotik tetikleyicidir; algler çoğalır, ölen alglerin ayrıştırıcılarca parçalanması oksijeni tüketir ve su canlıları zarar görür (ötrofikasyon)."},{"q":"Kurak bölge bitkilerinin (kserofitler) düşük su ve yüksek sıcaklığa karşı geliştirdiği uyumları sınırlayıcı faktör açısından değerlendiriniz.","steps":[{"t":"Sınırlayıcı faktör","a":"Su","d":"Kurak bölgede en yetersiz, yani <b>sınırlayıcı</b> abiyotik faktör sudur."},{"t":"Uyumlar","a":"Su tutma yapıları","d":"Kalın kütiküla, az ve batık stoma, etli gövde ve derin kök su kaybını azaltıp depolamayı artırır."},{"t":"Sonuç","a":"Sınırlamayı hafifletme","d":"Bu uyumlar suyu verimli kullanarak sınırlayıcı faktörün baskısını azaltır ve hayatta kalmayı sağlar."}],"ans":"Kserofitlerde su sınırlayıcı faktördür; kalın kütiküla, batık stoma ve su depolayan yapılar su kaybını azaltarak bu sınırlamanın baskısını hafifletir."},{"q":"Aynı türden iki popülasyondan biri optimum, diğeri tolerans sınırına yakın sıcaklıkta yaşıyor. Hangisi çevresel strese daha dayanıksızdır ve neden?","steps":[{"t":"Optimumdaki","a":"Geniş tampon","d":"Optimumdaki popülasyonun sınırlara kadar geniş bir <b>tolerans payı</b> vardır."},{"t":"Sınıra yakın","a":"Dar tampon","d":"Tolerans sınırına yakın yaşayan popülasyonun payı azdır; küçük bir sıcaklık artışı bile sınırı aşabilir."},{"t":"Sonuç","a":"Sınırdaki dayanıksız","d":"Bu yüzden tolerans sınırına yakın popülasyon çevresel strese daha dayanıksızdır."}],"ans":"Tolerans sınırına yakın yaşayan popülasyon daha dayanıksızdır; tampon payı dar olduğundan küçük bir sıcaklık değişimi bile onu sınırın dışına itebilir."},{"q":"Derin deniz hidrotermal bacalarındaki ekosistemin ışıksız ortamda kemosentetik üreticilere dayanmasını biyotik-abiyotik ilişkiyle açıklayınız.","steps":[{"t":"Abiyotik koşul","a":"Işık yok, kimyasal var","d":"Derin denizde ışık yoktur; ancak bacalardan <b>hidrojen sülfür</b> gibi inorganik maddeler çıkar."},{"t":"Üretici","a":"Kemosentetik bakteri","d":"Kemosentetik bakteriler bu inorganik maddeleri oksitleyerek elde ettikleri enerjiyle organik besin üretir."},{"t":"Biyotik zincir","a":"Tüketiciler beslenir","d":"Bu üreticiler besin zincirinin temelidir; midye ve tüp solucanları gibi tüketiciler onlara dayanır."}],"ans":"Işıksız bacalarda inorganik maddeler abiyotik enerji kaynağıdır; kemosentetik bakteriler bunları kullanarak üretici olur ve tüm tüketici topluluğu bu biyotik temele dayanır."},{"q":"Toprak pH'sının çok asidik olması bitkilerde hem mineral eksikliğine hem de toksisiteye yol açabilir. Bu çift etkiyi açıklayınız.","steps":[{"t":"Eksiklik yönü","a":"Bazı mineraller bağlanır","d":"Düşük pH'da fosfor gibi bazı mineraller toprakta çözünmez bileşik yaparak bitkiye <b>erişilemez</b> hale gelir."},{"t":"Toksisite yönü","a":"Alüminyum çözünür","d":"Asidik toprakta alüminyum ve manganez gibi iyonların çözünürlüğü artar ve <b>toksik</b> düzeylere ulaşır."},{"t":"Sonuç","a":"Çift baskı","d":"Bitki hem gerekli minerali alamaz hem de zehirli iyonlara maruz kalır; bu yüzden gelişimi ciddi biçimde bozulur."}],"ans":"Asidik toprakta fosfor gibi mineraller bağlanıp alınamaz hale gelirken alüminyum gibi iyonlar çözünüp toksik düzeye ulaşır; bitki hem eksiklik hem zehirlenme baskısı yaşar."},{"q":"Bir kara biyomunda yıllık sıcaklık ve yağış değerlerinin biyom tipini belirlemesini örneklerle açıklayınız.","steps":[{"t":"Yüksek sıcaklık-düşük yağış","a":"Çöl","d":"Sıcak ve <b>kurak</b> bölgelerde su sınırlayıcı olduğundan seyrek, su tutan bitkilerin olduğu çöl oluşur."},{"t":"Ilıman-bol yağış","a":"Orman","d":"Ilıman sıcaklık ve bol yağış, yoğun ağaç örtüsüne sahip ormanların gelişmesine olanak tanır."},{"t":"Düşük sıcaklık","a":"Tundra","d":"Çok soğuk ve kısa yetişme mevsiminde ağaç yetişemez; bodur bitkilerin olduğu tundra oluşur."}],"ans":"Sıcaklık ve yağış birleşimi biyomu belirler: sıcak-kurak çölü, ılıman-yağışlı ormanı, soğuk bölge tundrayı oluşturur."},{"q":"Etkileşen iki sınırlayıcı faktör (su ve mineral) bulunan bir tarlada yalnız birini gidermenin verimi neden tam artırmadığını açıklayınız.","steps":[{"t":"İlk sınırlayıcı","a":"Örneğin su","d":"Su giderilirse, su sınırlayıcı olmaktan çıkar ve verim bir miktar <b>artar</b>."},{"t":"İkinci sınırlayıcı","a":"Mineral devreye girer","d":"Su yeterli olunca bu kez mineral eksikliği yeni sınırlayıcı faktör hâline gelir."},{"t":"Sonuç","a":"İkisi birlikte gerekir","d":"Tam verim için her iki faktörün de giderilmesi gerekir; tek başına biri giderilince diğeri tavanı belirler."}],"ans":"Tek faktörü gidermek diğerinin sınırlayıcı olmasına yol açar; su giderilse de mineral eksikse verim sınırlanır, tam artış için her iki faktör birlikte giderilmelidir."},{"q":"İklim değişikliğiyle ortalama sıcaklığın artması bir türün coğrafi dağılımını neden kutuplara veya yükseklere doğru kaydırabilir?","steps":[{"t":"Tolerans aralığı","a":"Belirli sıcaklık","d":"Her türün yaşayabildiği bir <b>sıcaklık tolerans aralığı</b> vardır."},{"t":"Sıcaklık artışı","a":"Eski alan ısınır","d":"Mevcut yaşam alanı tolerans üst sınırını aşacak kadar ısınınca tür burada zorlanır."},{"t":"Sonuç","a":"Serin alana göç","d":"Tür, kendi tolerans aralığına uyan daha serin bölgelere (kutuplara ya da yüksek rakımlara) doğru yayılır."}],"ans":"Isınma türün yaşadığı alanı tolerans üst sınırının üstüne çıkarınca tür, sıcaklık toleransına uyan daha serin kutup veya yüksek rakım bölgelerine kayar."},{"q":"Ayrıştırıcı bakteri ve mantarların abiyotik mineral döngüsündeki rolünü bir besin döngüsü örneğiyle açıklayınız.","steps":[{"t":"Başlangıç","a":"Ölü organik madde","d":"Ölen bitki ve hayvanların gövdesinde azot, fosfor gibi mineraller <b>organik</b> bileşiklerde bağlıdır."},{"t":"Ayrıştırma","a":"Minerale dönüştürme","d":"Ayrıştırıcılar bu organik maddeyi parçalayarak içindeki mineralleri inorganik (abiyotik) forma çevirir."},{"t":"Geri dönüş","a":"Üreticiye sunma","d":"Toprağa dönen bu mineralleri üreticiler tekrar alır; böylece madde döngüsü kapanır."}],"ans":"Ayrıştırıcılar biyotik faktör olarak ölü organik maddedeki mineralleri inorganik forma çevirir; bu mineraller toprağa dönüp üreticilerce yeniden kullanılarak madde döngüsünü tamamlar."},{"q":"Bir akarsuda sıcaklık artışının (termal kirlilik) sudaki oksijen ve canlılar üzerindeki çift etkisini açıklayınız.","steps":[{"t":"Çözünmüş oksijen","a":"Sıcakta azalır","d":"Suyun sıcaklığı artınca içinde <b>çözünebilen oksijen</b> miktarı azalır."},{"t":"Metabolizma","a":"Oksijen ihtiyacı artar","d":"Aynı anda yüksek sıcaklık canlıların metabolizmasını hızlandırır, oksijen ihtiyaçlarını <b>artırır</b>."},{"t":"Sonuç","a":"Çift baskı","d":"Oksijen azalırken ihtiyaç arttığı için duyarlı türler (ör. alabalık) zorlanır ya da ölür."}],"ans":"Sıcaklık artışı suda çözünen oksijeni azaltırken canlıların oksijen ihtiyacını artırır; bu çift etki duyarlı su canlılarının yaşamını tehdit eder."},{"q":"Çoğalan bir popülasyonda artan birey sayısının bizzat sınırlayıcı bir biyotik faktöre dönüşmesini (yoğunluğa bağlı faktörler) açıklayınız.","steps":[{"t":"Düşük yoğunlukta","a":"Kaynak bol","d":"Birey sayısı azken besin, su ve alan gibi kaynaklar <b>bol</b> olduğundan popülasyon hızla büyür."},{"t":"Yoğunluk artınca","a":"Rekabet artar","d":"Birey sayısı arttıkça besin ve alan için <b>rekabet</b>, hastalık ve avlanma baskısı artar."},{"t":"Sonuç","a":"Büyüme yavaşlar","d":"Bu yoğunluğa bağlı biyotik faktörler doğum oranını düşürüp ölüm oranını artırır; popülasyon taşıma kapasitesinde dengelenir."}],"ans":"Yoğunluk arttıkça besin-alan rekabeti, hastalık ve avlanma gibi yoğunluğa bağlı biyotik faktörler artar; bunlar büyümeyi yavaşlatıp popülasyonu taşıma kapasitesinde dengeler."},{"q":"Yüksek dağ ortamında düşük sıcaklık, yüksek UV ışını ve ince toprak gibi birden çok abiyotik faktörün bitki örtüsünü birlikte sınırlamasını açıklayınız.","steps":[{"t":"Düşük sıcaklık","a":"Kısa yetişme","d":"Soğuk ve kısa yetişme mevsimi, bitkilerin büyüme süresini ve boyunu <b>kısıtlar</b>."},{"t":"Yüksek UV ve rüzgâr","a":"Doku hasarı","d":"Yoğun UV ışını ve sert rüzgâr bitki dokusunu yıpratır; bitkiler bodur ve yastık formlu olur."},{"t":"İnce toprak","a":"Az su-mineral","d":"İnce ve fakir toprak az su ile mineral tutar, kök gelişimini sınırlar; faktörler birlikte alpin bodur örtüyü oluşturur."}],"ans":"Yüksek dağda düşük sıcaklık yetişme süresini, yoğun UV ve rüzgâr dokuyu, ince toprak su-mineralı sınırlar; bu abiyotik faktörler birlikte bodur, yastık formlu alpin bitki örtüsünü oluşturur."},{"q":"Bir serada üretici verimini artırmak için ışık, sıcaklık, CO₂ ve mineralin birlikte optimize edilmesini sınırlayıcı faktör ilkesiyle açıklayınız.","steps":[{"t":"Tek faktör","a":"Diğeri sınırlar","d":"Yalnız ışık artırılırsa bir süre sonra <b>CO₂ veya mineral</b> sınırlayıcı olur ve verim sabitlenir."},{"t":"Birlikte optimize","a":"Tüm sınırlamalar gevşer","d":"Işık, sıcaklık, CO₂ ve mineral birlikte uygun düzeye getirilince hiçbiri tek başına sınırlayıcı kalmaz."},{"t":"Sonuç","a":"En yüksek verim","d":"Sınırlayıcı faktör ilkesine göre bütün gereksinimler optimumda karşılandığında üretici verimi en yüksek değerine ulaşır."}],"ans":"Tek faktörü artırmak diğerini sınırlayıcı yapar; ışık, sıcaklık, CO₂ ve mineral birlikte optimize edilirse hiçbiri sınırlayıcı kalmaz ve sınırlayıcı faktör ilkesine göre üretici verimi en üst düzeye çıkar."}]}},"enerjiPiramidi":{"ilkokul":{"kolay":[{"q":"Enerji piramidi nedir? Kısaca açıkla.","steps":[{"t":"Piramidin şekli","a":"alttan geniş","d":"Enerji piramidi, altı geniş üstü dar olan üçgene benzer bir şekildir."},{"t":"Ne gösterir","a":"besindeki enerji","d":"Her basamakta canlılardaki enerjinin ne kadar olduğunu gösterir."}],"ans":"Enerji piramidi, besin basamaklarındaki canlıların enerjisini gösteren, alttan geniş üstten dar bir şekildir."},{"q":"Enerji piramidinin en altında hangi canlılar bulunur?","steps":[{"t":"Besini kim üretir","a":"bitkiler","d":"Bitkiler güneş ışığıyla kendi besinini üretir."},{"t":"En alt basamak","a":"üreticiler","d":"Besini üreten bitkiler piramidin en altında, en geniş yerde bulunur."}],"ans":"Enerji piramidinin en altında besin üreten bitkiler (üreticiler) bulunur."},{"q":"Enerji piramidinde yukarı çıktıkça enerji nasıl değişir?","steps":[{"t":"Alt basamak","a":"çok enerji","d":"En altta, bitkilerde en çok enerji vardır."},{"t":"Yukarı çıkınca","a":"enerji azalır","d":"Bir üst basamağa çıkıldıkça enerji azalır."}],"ans":"Enerji piramidinde yukarı çıkıldıkça enerji azalır."},{"q":"Çimen → çekirge → kuş sıralamasında en çok enerji hangisindedir?","steps":[{"t":"En alttaki canlı","a":"çimen","d":"Çimen bitkidir ve kendi besinini üretir, en altta bulunur."},{"t":"En çok enerji","a":"çimende","d":"En alttaki canlıda en çok enerji olur, o da çimendir."}],"ans":"Bu sıralamada en çok enerji en alttaki çimende bulunur."},{"q":"Neden enerji piramidinin üstüne doğru daha az hayvan olur?","steps":[{"t":"Yukarıda enerji","a":"az enerji","d":"Yukarı çıkınca besindeki enerji azalır."},{"t":"Sonuç","a":"az hayvan beslenir","d":"Az enerji, daha az hayvanı doyurabilir, bu yüzden üstte az canlı olur."}],"ans":"Yukarıda enerji az olduğu için daha az hayvanı doyurur, bu yüzden üstte canlı sayısı azdır."}],"zor":[{"q":"Bir enerji piramidinde aslan neden en üstte, az sayıda bulunur?","steps":[{"t":"Aslan ne yer","a":"başka hayvan","d":"Aslan etçildir, başka hayvanları yiyerek beslenir."},{"t":"Yukarıdaki enerji","a":"çok azalmış","d":"En üste gelene kadar enerji basamak basamak azalır."},{"t":"Sonuç","a":"az aslan","d":"Az enerji olduğu için çok az aslan beslenebilir."}],"ans":"En üste çıkana kadar enerji çok azaldığı için aslan en üstte ve az sayıda bulunur."},{"q":"Bir bitkinin enerjisinin tamamı onu yiyen tavşana geçer mi?","steps":[{"t":"Bitkinin enerjisi","a":"çok enerji","d":"Bitkide güneşten gelen bol enerji vardır."},{"t":"Tavşana geçen","a":"az kısmı","d":"Tavşan bitkiyi yer ama enerjinin sadece küçük bir kısmını alabilir."},{"t":"Kaybolan enerji","a":"ısı olarak","d":"Enerjinin çoğu hareket ve ısı olarak kaybolur."}],"ans":"Hayır; bitkinin enerjisinin sadece küçük bir kısmı tavşana geçer, çoğu kaybolur."},{"q":"Neden çok uzun bir besin zinciri (10 basamaklı) doğada zor görülür?","steps":[{"t":"Her basamakta","a":"enerji azalır","d":"Her yukarı basamakta enerjinin çoğu kaybolur."},{"t":"Çok basamak sonra","a":"enerji biter","d":"Çok basamak çıkılırsa en üstte beslenecek enerji kalmaz."},{"t":"Sonuç","a":"zincir kısadır","d":"Bu yüzden besin zincirleri genelde kısadır."}],"ans":"Her basamakta enerji azaldığı için çok uzun zincirde üstte enerji kalmaz, bu yüzden zincir kısa olur."},{"q":"Çayırdaki otların enerjisi nereden gelir ve sonra nereye gider?","steps":[{"t":"Otların enerjisi","a":"güneşten","d":"Otlar güneş ışığını kullanarak enerji elde eder."},{"t":"Otu yiyen","a":"otçul hayvan","d":"Otları inek veya tavşan gibi otçul hayvanlar yer."},{"t":"Enerjinin yönü","a":"yukarı taşınır","d":"Enerji otçuldan onu yiyen etçile doğru taşınır."}],"ans":"Otların enerjisi güneşten gelir, sonra otu yiyen hayvanlara ve onları yiyen hayvanlara taşınır."},{"q":"Enerji piramidinde en üstteki canlı ölünce enerjisi tamamen yok mu olur?","steps":[{"t":"Ölen canlı","a":"çürür","d":"Ölen canlının bedeni toprakta çürür."},{"t":"Çürütücüler","a":"ayrıştırıcılar","d":"Bakteri ve mantarlar bedeni parçalayıp enerjisinden yararlanır."},{"t":"Sonuç","a":"yok olmaz","d":"Enerji yok olmaz, çürütücülere ve toprağa geçer."}],"ans":"Hayır; ölen canlının enerjisi çürütücülere (ayrıştırıcılara) ve toprağa geçer, tamamen yok olmaz."}]},"ortaokul":{"kolay":[{"q":"Enerji piramidinde her basamağa ne ad verilir?","steps":[{"t":"Basamağın adı","a":"trofik düzey","d":"Besin piramidindeki her bir beslenme basamağına trofik düzey denir."},{"t":"Sıralama","a":"üretici en altta","d":"En alt trofik düzey üreticiler, üstte ise tüketicilerdir."}],"ans":"Enerji piramidindeki her beslenme basamağına trofik düzey denir."},{"q":"Enerji piramidinde üreticiler hangi trofik düzeydedir?","steps":[{"t":"Üreticiler","a":"bitkiler","d":"Üreticiler fotosentez yapan bitkilerdir."},{"t":"Düzeyi","a":"birinci trofik","d":"Besini üretip zinciri başlattıkları için ilk (birinci) trofik düzeydedir."}],"ans":"Üreticiler enerji piramidinin birinci (en alt) trofik düzeyinde yer alır."},{"q":"Bir trofik düzeyden diğerine geçerken enerjinin yaklaşık ne kadarı aktarılır?","steps":[{"t":"Aktarım oranı","a":"yaklaşık %10","d":"Bir basamaktan üstüne enerjinin yaklaşık %10'u aktarılır."},{"t":"Kalan kısım","a":"%90 kaybolur","d":"Geri kalan yaklaşık %90'lık enerji kaybolur."}],"ans":"Bir trofik düzeyden bir üstüne enerjinin yaklaşık %10'u aktarılır."},{"q":"Enerji piramidinde kaybolan enerji çoğunlukla hangi şekilde dışarı atılır?","steps":[{"t":"Solunum ve hareket","a":"enerji harcanır","d":"Canlılar solunum ve hareket için enerji harcar."},{"t":"Dışarı atılan biçim","a":"ısı","d":"Harcanan bu enerjinin büyük kısmı ısı olarak ortama yayılır."}],"ans":"Trofik düzeyler arasında kaybolan enerji çoğunlukla ısı olarak dışarı atılır."},{"q":"Neden enerji piramidi yukarı doğru daralan bir şekle sahiptir?","steps":[{"t":"Alt basamak","a":"çok enerji","d":"En altta üreticilerde en fazla enerji bulunur."},{"t":"Yukarı çıkınca","a":"enerji azalır","d":"Her basamakta enerji azaldığı için üst basamaklar daha küçük çizilir."}],"ans":"Her trofik düzeyde enerji azaldığı için piramit yukarı doğru daralan bir şekle sahiptir."}],"zor":[{"q":"Bir üreticide 10000 birim enerji varsa, birincil tüketiciye yaklaşık ne kadarı geçer?","steps":[{"t":"Aktarım kuralı","a":"%10 kuralı","d":"Bir üst düzeye enerjinin yaklaşık %10'u aktarılır."},{"t":"Hesap","a":"10000 × 0,10","d":"10000 biriminin %10'u: 10000 × 0,10 = 1000 birim."},{"t":"Sonuç","a":"1000 birim","d":"Birincil tüketiciye yaklaşık 1000 birim enerji geçer."}],"ans":"Üreticideki 10000 birim enerjinin %10'u, yani yaklaşık 1000 birim birincil tüketiciye geçer."},{"q":"%10 kuralına göre üç basamak çıkıldığında enerji kaç katına iner? (üretici 1000 birim)","steps":[{"t":"1. tüketici","a":"100 birim","d":"1000 biriminin %10'u: 1000 × 0,10 = 100 birim."},{"t":"2. tüketici","a":"10 birim","d":"100 biriminin %10'u: 100 × 0,10 = 10 birim."},{"t":"3. tüketici","a":"1 birim","d":"10 biriminin %10'u: 10 × 0,10 = 1 birim."}],"ans":"Üç basamak çıkıldığında 1000 birim enerji 1 birime, yani binde birine iner."},{"q":"Biyokütle piramidi nedir ve neyi gösterir?","steps":[{"t":"Biyokütle anlamı","a":"canlı kütlesi","d":"Biyokütle, bir trofik düzeydeki canlıların toplam ağırlığıdır."},{"t":"Piramidin gösterdiği","a":"kütle azalması","d":"Yukarı çıktıkça toplam canlı kütlesinin azaldığını gösterir."}],"ans":"Biyokütle piramidi, her trofik düzeydeki canlıların toplam kütlesini gösterir ve yukarı çıkınca bu kütle azalır."},{"q":"Sayı piramidi ile enerji piramidi arasındaki fark nedir?","steps":[{"t":"Sayı piramidi","a":"birey sayısı","d":"Sayı piramidi her düzeydeki canlı sayısını gösterir."},{"t":"Enerji piramidi","a":"enerji miktarı","d":"Enerji piramidi her düzeydeki enerji miktarını gösterir."},{"t":"Fark","a":"farklı ölçüm","d":"Biri canlı sayısını, diğeri enerjiyi ölçer; sayı bazen yanıltabilir."}],"ans":"Sayı piramidi canlı sayısını, enerji piramidi ise enerji miktarını gösterir; ikisi farklı şeyler ölçer."},{"q":"Bir besin zinciri neden genellikle 4-5 basamaktan uzun olmaz?","steps":[{"t":"Her basamakta kayıp","a":"%90 kaybolur","d":"Her trofik düzeyde enerjinin yaklaşık %90'ı kaybolur."},{"t":"Üst basamaklarda","a":"çok az enerji","d":"4-5 basamak sonra geriye yetecek enerji kalmaz."},{"t":"Sonuç","a":"zincir kısalır","d":"Beslenecek enerji bulunmadığı için zincir daha fazla uzayamaz."}],"ans":"Her basamakta enerjinin çoğu kaybolduğu için 4-5 basamak sonra yetecek enerji kalmaz; bu yüzden zincir kısa olur."}]},"lise":{"kolay":[{"q":"Ekolojik piramit kavramını tanımlayınız.","steps":[{"t":"Tanım","a":"grafiksel gösterim","d":"Ekolojik piramit, trofik düzeyler arasındaki enerji, biyokütle veya birey sayısının grafiksel gösterimidir."},{"t":"Genel şekil","a":"yukarı daralan","d":"Çoğunlukla üreticiden üst tüketiciye doğru daralan bir biçim alır."}],"ans":"Ekolojik piramit, trofik düzeylerdeki enerji, biyokütle ya da birey sayısını gösteren ve genelde yukarı daralan grafiksel gösterimdir."},{"q":"Trofik düzey nedir ve nasıl numaralandırılır?","steps":[{"t":"Tanım","a":"beslenme basamağı","d":"Trofik düzey, bir canlının besin zincirindeki beslenme konumudur."},{"t":"Numaralandırma","a":"üreticiden başlar","d":"Üreticiler 1. düzey, otçullar 2., birincil etçiller 3. düzeydir."}],"ans":"Trofik düzey, bir canlının besin zincirindeki beslenme basamağıdır; üreticiden (1. düzey) başlayarak numaralanır."},{"q":"%10 enerji aktarım kuralının (Lindeman kuralı) içeriği nedir?","steps":[{"t":"Kural","a":"yaklaşık %10 aktarım","d":"Bir trofik düzeydeki enerjinin yalnızca yaklaşık %10'u bir üst düzeye aktarılır."},{"t":"Kayıp","a":"%90 kayıp","d":"Geri kalan %90, solunum, hareket ve ısı yoluyla kaybolur."}],"ans":"%10 kuralına göre bir trofik düzeydeki enerjinin yalnızca yaklaşık %10'u bir üst düzeye aktarılır, kalanı kaybolur."},{"q":"Enerji piramidi neden her zaman düz (yukarı daralan) bir şekildedir?","steps":[{"t":"Termodinamik kayıp","a":"enerji azalır","d":"Her trofik düzeyde enerjinin büyük kısmı ısı olarak kaybolduğu için enerji azalır."},{"t":"Tersine dönemez","a":"alt > üst","d":"Üst düzey alttan fazla enerjiye sahip olamaz, bu yüzden piramit ters dönmez."}],"ans":"Enerji her basamakta azaldığı ve üst düzey alttakinden fazla enerji içeremeyeceği için enerji piramidi daima yukarı daralan biçimdedir."},{"q":"Birincil üretici, birincil tüketici ve ikincil tüketici terimlerini açıklayınız.","steps":[{"t":"Birincil üretici","a":"ototrof","d":"Fotosentezle besin üreten canlılardır (1. trofik düzey)."},{"t":"Birincil tüketici","a":"otçul","d":"Üreticilerle beslenen otçul canlılardır (2. trofik düzey)."},{"t":"İkincil tüketici","a":"etçil","d":"Otçulları yiyen etçil canlılardır (3. trofik düzey)."}],"ans":"Birincil üretici fotosentez yapan ototrof, birincil tüketici otçul, ikincil tüketici ise otçulla beslenen etçildir."},{"q":"Brüt birincil üretim (GPP) ile net birincil üretim (NPP) arasındaki fark nedir?","steps":[{"t":"GPP","a":"toplam üretim","d":"Brüt birincil üretim, üreticilerin fotosentezle ürettiği toplam organik maddedir."},{"t":"NPP","a":"GPP − solunum","d":"Net birincil üretim, GPP'den üreticinin solunum kaybı çıkarılınca kalan miktardır."}],"ans":"GPP üreticinin toplam organik üretimi, NPP ise bundan solunum kaybı çıkarıldıktan sonra kalan, üst düzeylere aktarılabilen üretimdir."},{"q":"Biyokütle piramidi neyi ölçer ve hangi birimlerle ifade edilir?","steps":[{"t":"Ölçtüğü","a":"kuru kütle","d":"Her trofik düzeydeki canlıların birim alandaki toplam (genellikle kuru) kütlesini ölçer."},{"t":"Birim","a":"g/m² gibi","d":"Genellikle g/m² veya kg/hektar gibi birim alan başına kütle olarak verilir."}],"ans":"Biyokütle piramidi her trofik düzeydeki canlıların birim alandaki toplam kütlesini ölçer ve g/m² gibi birimlerle ifade edilir."},{"q":"Sayı piramidi nedir ve hangi durumda yanıltıcı olabilir?","steps":[{"t":"Tanım","a":"birey sayısı","d":"Sayı piramidi her trofik düzeydeki birey sayısını gösterir."},{"t":"Yanıltıcı durum","a":"büyük üretici","d":"Tek bir büyük ağaç çok sayıda böceği beslerse alt basamak dar görünebilir."}],"ans":"Sayı piramidi her düzeydeki birey sayısını gösterir; tek bir büyük üreticinin çok tüketiciyi beslediği durumda ters/yanıltıcı görünebilir."},{"q":"Enerji piramidinde enerjinin tek yönlü aktığını söylemek ne demektir?","steps":[{"t":"Akış yönü","a":"alttan üste","d":"Enerji üreticiden tüketicilere doğru tek yönde akar."},{"t":"Geri dönmez","a":"döngü yok","d":"Madde gibi geri dönüştürülmez; ısı olarak kaybolup sisteme yeniden girmez."}],"ans":"Enerjinin tek yönlü akması, enerjinin üreticiden üst düzeylere doğru aktığını ve ısı olarak kaybolup geri dönmediğini ifade eder."},{"q":"Ayrıştırıcılar enerji piramidinde nasıl bir rol oynar?","steps":[{"t":"Beslenme","a":"ölü organik madde","d":"Ayrıştırıcılar her trofik düzeydeki ölü canlı ve atıkları parçalar."},{"t":"Enerji geri kazanımı","a":"kalan enerjiyi alır","d":"Üst düzeylere geçmeyen enerjinin bir kısmından ayrıştırıcılar yararlanır."}],"ans":"Ayrıştırıcılar ölü organik maddeyi parçalayarak diğer düzeylerden artan enerjiyi kullanır ve maddenin döngüye dönmesini sağlar."},{"q":"Bir besin ağı ile bir besin zinciri arasındaki fark enerji aktarımı açısından nedir?","steps":[{"t":"Besin zinciri","a":"tek yol","d":"Besin zinciri enerjinin tek bir doğrusal yolunu gösterir."},{"t":"Besin ağı","a":"çok yol","d":"Besin ağı, birbirine bağlı birçok zinciri ve alternatif enerji yollarını gösterir."}],"ans":"Besin zinciri enerjinin tek bir yolunu, besin ağı ise birçok birbirine bağlı zincirle alternatif enerji aktarım yollarını gösterir."},{"q":"Neden bir ekosistemde etçiller otçullardan daha az sayıda bulunur?","steps":[{"t":"Üst düzey","a":"daha az enerji","d":"Etçiller daha üst trofik düzeyde olduğu için onlara daha az enerji ulaşır."},{"t":"Sonuç","a":"az birey","d":"Az enerji daha az bireyi destekleyebilir, bu yüzden etçil sayısı azdır."}],"ans":"Etçiller daha üst trofik düzeyde olup daha az enerji aldıkları için otçullardan daha az sayıda bulunur."},{"q":"Enerji piramidi ile biyokütle piramidi her zaman aynı biçimde mi olur?","steps":[{"t":"Enerji piramidi","a":"daima düz","d":"Enerji piramidi termodinamik nedenle her zaman yukarı daralır."},{"t":"Biyokütle piramidi","a":"ters olabilir","d":"Bazı sucul sistemlerde anlık biyokütle ters dönebilir."}],"ans":"Hayır; enerji piramidi her zaman düzdür, fakat biyokütle piramidi bazı sucul ekosistemlerde ters dönebilir."},{"q":"Üst düzey tüketicilerin beslenmesi neden geniş bir alan gerektirir?","steps":[{"t":"Enerji ihtiyacı","a":"çok besin","d":"Üst tüketiciye az enerji ulaştığı için ihtiyacını karşılamak çok av gerektirir."},{"t":"Alan","a":"geniş habitat","d":"Yeterli avı bulmak için geniş bir avlanma alanına ihtiyaç duyarlar."}],"ans":"Üst düzey tüketicilere az enerji ulaştığı için ihtiyaçlarını karşılayacak çok sayıda avı bulmaları gerekir, bu da geniş alan gerektirir."},{"q":"Trofik düzeyler arasındaki enerji aktarım verimi neye bağlıdır?","steps":[{"t":"Sindirim verimi","a":"yenenin oranı","d":"Avın ne kadarının yenip sindirilebildiği verimi etkiler."},{"t":"Metabolik kayıp","a":"solunum/ısı","d":"Canlının solunum ve ısı kaybı ne kadar yüksekse aktarılan enerji o kadar azalır."}],"ans":"Aktarım verimi, besinin sindirilebilen oranına ve canlının solunum/ısı gibi metabolik enerji kayıplarına bağlıdır."}],"zor":[{"q":"Üreticide 50000 kJ enerji varsa, %10 kuralına göre üçüncül tüketiciye (4. trofik düzey) ulaşan enerji kaç kJ olur?","steps":[{"t":"2. düzey","a":"5000 kJ","d":"50000 × 0,10 = 5000 kJ (birincil tüketici)."},{"t":"3. düzey","a":"500 kJ","d":"5000 × 0,10 = 500 kJ (ikincil tüketici)."},{"t":"4. düzey","a":"50 kJ","d":"500 × 0,10 = 50 kJ (üçüncül tüketici)."}],"ans":"50000 kJ enerji üç basamak aktarılınca üçüncül tüketiciye 50 kJ ulaşır."},{"q":"Bir ikincil tüketiciye 80 kJ enerji ulaşmışsa, %10 kuralına göre üreticideki enerji yaklaşık ne kadardı?","steps":[{"t":"Düzeyler arası","a":"iki basamak","d":"Üreticiden ikincil tüketiciye iki basamak çıkılır, her basamakta ÷0,10."},{"t":"1. tüketici","a":"800 kJ","d":"İkincil tüketiciye gelen 80 kJ için birincil tüketicide 80 ÷ 0,10 = 800 kJ olmalı."},{"t":"Üretici","a":"8000 kJ","d":"Üreticide ise 800 ÷ 0,10 = 8000 kJ enerji bulunmalı."}],"ans":"%10 kuralına göre ikincil tüketiciye 80 kJ ulaşması için üreticide yaklaşık 8000 kJ enerji bulunmalıdır."},{"q":"Enerji piramidinde her basamakta enerjinin yaklaşık %90'ı neden ve nasıl kaybolur?","steps":[{"t":"Solunum","a":"ATP üretimi","d":"Enerjinin büyük kısmı hücresel solunumda harcanıp ısı olarak yayılır."},{"t":"Yenmeyen/sindirilemeyen","a":"dışkı, atık","d":"Avın bir kısmı yenmez ya da sindirilemeden dışkıyla atılır."},{"t":"Hareket ve ısı","a":"metabolik kayıp","d":"Hareket, ısınma ve diğer yaşamsal etkinlikler de enerji tüketir."}],"ans":"Enerjinin yaklaşık %90'ı; solunumda ısıya dönüşme, sindirilemeyen kısmın atılması ve hareket/metabolik etkinlikler nedeniyle kaybolur."},{"q":"Çayır → çekirge → kurbağa → yılan zincirinde üretici 100000 kJ ise yılana ulaşan enerjiyi hesaplayınız.","steps":[{"t":"Çekirge (2.)","a":"10000 kJ","d":"100000 × 0,10 = 10000 kJ çekirgeye geçer."},{"t":"Kurbağa (3.)","a":"1000 kJ","d":"10000 × 0,10 = 1000 kJ kurbağaya geçer."},{"t":"Yılan (4.)","a":"100 kJ","d":"1000 × 0,10 = 100 kJ yılana geçer."}],"ans":"Üreticideki 100000 kJ enerjinin yalnızca 100 kJ'ü dördüncü düzeydeki yılana ulaşır."},{"q":"Sucul ekosistemde biyokütle piramidinin ters dönebilmesinin nedeni nedir?","steps":[{"t":"Üretici tipi","a":"fitoplankton","d":"Üreticiler hızlı üreyip hızlı tüketilen küçük fitoplanktonlardır."},{"t":"Anlık kütle","a":"düşük durağan kütle","d":"Belirli bir anda mevcut fitoplankton kütlesi tüketicilerden az olabilir."},{"t":"Üretim hızı","a":"yüksek devir","d":"Yüksek üreme hızı sayesinde toplam enerji akışı yine de yeterlidir."}],"ans":"Fitoplankton gibi üreticilerin hızlı üreyip hızla tüketilmesi nedeniyle anlık biyokütleleri tüketicilerden az olabilir, bu da biyokütle piramidini ters çevirir."},{"q":"Enerji piramidinin neden hiçbir koşulda ters dönemeyeceğini termodinamik açıdan açıklayınız.","steps":[{"t":"Enerji kaynağı","a":"alttan gelir","d":"Tüm enerji üreticiden başlar; üst düzey ancak alttan aldığı kadar enerjiye sahip olur."},{"t":"Kayıp zorunlu","a":"ısı kaybı","d":"Termodinamiğin 2. yasası gereği her aktarımda bir kısım enerji ısı olarak kaybolur."},{"t":"Sonuç","a":"üst < alt","d":"Üst düzey daima alttan az enerji içerir, bu yüzden piramit ters dönemez."}],"ans":"Termodinamiğin 2. yasası gereği her aktarımda enerji ısı olarak kaybolduğundan üst düzey daima alttan az enerji içerir; bu nedenle enerji piramidi ters dönemez."},{"q":"Bir zincirde besin (toplam) verimi %15 ise, üreticideki 20000 kJ enerjinin 3. trofik düzeye ulaşan miktarı kaç kJ olur?","steps":[{"t":"2. düzey","a":"3000 kJ","d":"20000 × 0,15 = 3000 kJ birincil tüketiciye geçer."},{"t":"3. düzey","a":"450 kJ","d":"3000 × 0,15 = 450 kJ ikincil tüketiciye geçer."},{"t":"Sonuç","a":"450 kJ","d":"İki basamak %15 verimle aktarılınca 3. düzeye 450 kJ ulaşır."}],"ans":"Verim %15 olduğunda 20000 kJ enerji iki basamak aktarılarak 3. trofik düzeye 450 kJ olarak ulaşır."},{"q":"İnsanların et yerine doğrudan bitkisel besinle beslenmesi enerji açısından neden daha verimlidir?","steps":[{"t":"Bitkisel beslenme","a":"2. düzey","d":"Bitki yiyen insan birincil tüketici (2. düzey) olur, üreticiye yakın beslenir."},{"t":"Etle beslenme","a":"3. düzey","d":"Et yiyen insan üst düzeye çıkar, arada bir basamak daha enerji kaybı olur."},{"t":"Sonuç","a":"daha az kayıp","d":"Üreticiye yakın beslenmek daha az enerji kaybı, yani daha çok beslenebilen insan demektir."}],"ans":"Bitkisel beslenmede insan üreticiye bir basamak daha yakın olduğundan arada daha az enerji kaybolur; bu yüzden aynı arazi daha çok insanı besleyebilir."},{"q":"Bir enerji piramidinde 4. trofik düzeye 25 kJ ulaşıyorsa, %10 kuralına göre üreticideki enerjiyi bulunuz.","steps":[{"t":"3. düzey","a":"250 kJ","d":"4. düzeye 25 kJ ulaşması için 3. düzeyde 25 ÷ 0,10 = 250 kJ olmalı."},{"t":"2. düzey","a":"2500 kJ","d":"3. düzey için 250 ÷ 0,10 = 2500 kJ gerekir."},{"t":"Üretici","a":"25000 kJ","d":"Üreticide 2500 ÷ 0,10 = 25000 kJ enerji bulunmalıdır."}],"ans":"4. düzeye 25 kJ ulaşması için üreticide yaklaşık 25000 kJ enerji bulunması gerekir."},{"q":"Trofik düzey sayısının artması en üst yırtıcının popülasyon büyüklüğünü nasıl etkiler?","steps":[{"t":"Her basamak","a":"%90 kayıp","d":"Eklenen her trofik düzeyde enerjinin yaklaşık %90'ı daha kaybolur."},{"t":"Üst yırtıcıya","a":"çok az enerji","d":"Daha fazla basamak, en üst yırtıcıya ulaşan enerjiyi daha da azaltır."},{"t":"Popülasyon","a":"küçük kalır","d":"Az enerji yalnızca küçük bir popülasyonu destekleyebilir."}],"ans":"Trofik düzey sayısı arttıkça en üst yırtıcıya ulaşan enerji katlanarak azalır, bu da yırtıcının popülasyonunu küçük tutar."},{"q":"Net birincil üretim (NPP) bir ekosistemin taşıyabileceği canlı miktarını neden belirler?","steps":[{"t":"NPP anlamı","a":"kullanılabilir enerji","d":"NPP, tüketicilere aktarılabilen toplam organik madde/enerjidir."},{"t":"Aktarım","a":"%10 ile üst düzeye","d":"Bu enerji %10 kuralıyla üst düzeylere aktarılır."},{"t":"Sınır","a":"taşıma kapasitesi","d":"Az NPP az enerji demektir; bu da beslenebilecek canlı sayısını sınırlar."}],"ans":"NPP, tüketicilere aktarılabilen toplam enerjiyi belirler; bu enerji sınırlı olduğundan ekosistemin besleyebileceği canlı miktarını (taşıma kapasitesini) doğrudan sınırlar."},{"q":"Aynı miktarda araziden elde edilen tahıl ile sığır eti karşılaştırıldığında neden tahıl daha çok insanı besler?","steps":[{"t":"Tahıl yolu","a":"doğrudan üretici","d":"Tahıl üreticidir; insan onu yiyince enerjinin büyük kısmını alır."},{"t":"Et yolu","a":"araya hayvan","d":"Sığır önce tahılı yer, enerjinin %90'ını kaybeder, insana azı kalır."},{"t":"Sonuç","a":"tahıl verimli","d":"Arada basamak olmadığı için tahıl çok daha fazla insanı besler."}],"ans":"Tahıl doğrudan tüketildiğinde enerji kaybı az olur; sığır arada bir trofik basamak ekleyip enerjinin %90'ını kaybettiğinden, aynı arazi tahılla çok daha fazla insanı besler."},{"q":"Enerji piramidinde 'ekolojik verimlilik' kavramı ne anlama gelir ve nasıl hesaplanır?","steps":[{"t":"Tanım","a":"aktarılan oran","d":"Ekolojik verimlilik, bir düzeydeki enerjinin üst düzeye aktarılan yüzdesidir."},{"t":"Hesap","a":"(üst ÷ alt)×100","d":"Üst düzey enerjisinin alt düzey enerjisine bölünüp 100 ile çarpılmasıyla bulunur."},{"t":"Tipik değer","a":"~%10","d":"Çoğu ekosistemde bu değer ortalama %10 civarındadır."}],"ans":"Ekolojik verimlilik, bir trofik düzeyden üstüne aktarılan enerji oranıdır; (üst düzey enerjisi ÷ alt düzey enerjisi)×100 ile hesaplanır ve genelde %10 dolayındadır."},{"q":"Bir piramitte 1. düzey 10000 kJ, 2. düzey 1200 kJ ise bu basamaktaki ekolojik verimlilik kaçtır?","steps":[{"t":"Formül","a":"(üst÷alt)×100","d":"Ekolojik verimlilik = (2. düzey ÷ 1. düzey) × 100."},{"t":"Yerine koy","a":"(1200÷10000)×100","d":"(1200 ÷ 10000) × 100 = 0,12 × 100."},{"t":"Sonuç","a":"%12","d":"Bu basamaktaki ekolojik verimlilik %12'dir."}],"ans":"Ekolojik verimlilik (1200 ÷ 10000) × 100 = %12 olarak bulunur."},{"q":"Toksik maddelerin (örneğin DDT) üst trofik düzeylerde yoğunlaşması (biyobirikim) enerji piramidiyle nasıl ilişkilidir?","steps":[{"t":"Enerji azalır","a":"madde değil","d":"Yukarı çıkıldıkça enerji azalır ama parçalanmayan toksik madde vücutta kalır."},{"t":"Daha çok av","a":"çok birikim","d":"Üst düzey, ihtiyacını karşılamak için çok sayıda av yiyip toksini biriktirir."},{"t":"Sonuç","a":"en üstte zirve","d":"Toksin her basamakta yoğunlaşır ve en üst yırtıcıda en yüksek düzeye ulaşır."}],"ans":"Enerji yukarı çıkınca azalırken parçalanmayan toksik madde azalmaz; üst düzey çok sayıda av tükettiği için toksin her basamakta yoğunlaşarak en üst yırtıcıda zirve yapar (biyomagnifikasyon)."}]}},"genelBakis":{"ilkokul":{"kolay":[{"q":"Ekosistem ne demektir? Kısaca açıkla.","steps":[{"t":"Birlikte yaşam","a":"canlılar ve çevre","d":"Bir yerde yaşayan canlılar ile onların çevresi birlikte bulunur."},{"t":"Hepsi birlikte","a":"ekosistem","d":"Canlılar ve cansız çevre birlikte bir ekosistem oluşturur."}],"ans":"Ekosistem, bir bölgedeki canlıların cansız çevresiyle birlikte oluşturduğu yaşam ortamıdır."},{"q":"Bir ormanda hangi canlılar yaşar? Örnek ver.","steps":[{"t":"Bitkileri düşün","a":"ağaçlar, çiçekler","d":"Ormanda ağaçlar, otlar ve çiçekler gibi bitkiler bulunur."},{"t":"Hayvanları düşün","a":"kuşlar, sincaplar","d":"Ormanda kuşlar, sincaplar ve böcekler gibi hayvanlar yaşar."}],"ans":"Ormanda ağaçlar, çiçekler, kuşlar, sincaplar ve böcekler gibi birçok canlı yaşar."},{"q":"Bir gölet ekosisteminde cansız varlıklar nelerdir?","steps":[{"t":"Suyu düşün","a":"su","d":"Gölette en çok bulunan cansız varlık sudur."},{"t":"Başka cansızlar","a":"taş, toprak, güneş","d":"Suyun yanında taş, toprak ve güneş ışığı da cansız varlıktır."}],"ans":"Gölette su, taş, toprak ve güneş ışığı gibi cansız varlıklar bulunur."},{"q":"Bir bitkinin yaşaması için cansız çevreden neye ihtiyacı vardır?","steps":[{"t":"Topraktan alır","a":"su","d":"Bitki kökleriyle topraktaki suyu içine çeker."},{"t":"Gökyüzünden alır","a":"güneş ışığı","d":"Bitki büyümek için güneş ışığına da ihtiyaç duyar."}],"ans":"Bir bitkinin yaşaması için su, toprak ve güneş ışığı gibi cansız varlıklar gerekir."},{"q":"Aynı çevrede yaşayan tavşanlar bir araya gelince ne oluşturur?","steps":[{"t":"Aynı tür canlılar","a":"tavşanlar","d":"Bir bölgede yaşayan tavşanların hepsi aynı tür canlılardır."},{"t":"Hepsine verilen ad","a":"topluluk (grup)","d":"Aynı türden canlıların oluşturduğu gruba o canlıların grubu denir."}],"ans":"Aynı çevrede yaşayan tavşanlar bir araya gelince bir tavşan grubu (popülasyon) oluşturur."}],"zor":[{"q":"Bir ekosistemdeki canlı ve cansız varlıkları ayırınız: kelebek, taş, ağaç, güneş.","steps":[{"t":"Canlıları seç","a":"kelebek, ağaç","d":"Kelebek ve ağaç yaşar, büyür ve beslenir; bu yüzden canlıdır."},{"t":"Cansızları seç","a":"taş, güneş","d":"Taş ve güneş yaşamaz, büyümez ve beslenmez; bu yüzden cansızdır."}],"ans":"Canlılar: kelebek ve ağaç; cansızlar: taş ve güneştir."},{"q":"Bir bahçedeki canlılar ile cansızlar birbirine neden ihtiyaç duyar?","steps":[{"t":"Canlının ihtiyacı","a":"su ve ışık","d":"Bitkiler büyümek için cansız olan su ve güneş ışığını kullanır."},{"t":"Birlikte yaşam","a":"birbirine bağlı","d":"Canlılar cansız çevre olmadan yaşayamaz, bu yüzden birbirine bağlıdır."}],"ans":"Canlılar yaşamak için cansız çevredeki su, ışık ve toprağa ihtiyaç duyduğu için ikisi birbirine bağlıdır."},{"q":"Çöl ve orman neden farklı ekosistemlerdir?","steps":[{"t":"Çölü düşün","a":"çok sıcak, az su","d":"Çölde su azdır ve hava çok sıcaktır, az bitki bulunur."},{"t":"Ormanı düşün","a":"yağmurlu, çok ağaç","d":"Ormanda su boldur ve çok sayıda ağaç yetişir."}],"ans":"Çöl ve orman farklı su, sıcaklık ve canlılara sahip olduğu için ayrı ekosistemlerdir."},{"q":"Bir gölde yaşayan balıklar suyu kirletilirse ne olur?","steps":[{"t":"Suyun önemi","a":"balığın yaşam yeri","d":"Balıklar yaşamak için temiz suya ihtiyaç duyar."},{"t":"Su kirlenirse","a":"balıklar zarar görür","d":"Su kirlenirse balıklar nefes alamaz ve zarar görür."}],"ans":"Suları kirlenirse balıklar yaşayamaz, çünkü cansız çevre canlılar için çok önemlidir."},{"q":"Bir tarladaki buğdaylar, fareler ve toprak nasıl bir bütün oluşturur?","steps":[{"t":"Canlıları bul","a":"buğday, fare","d":"Buğdaylar ve fareler tarlada yaşayan canlılardır."},{"t":"Cansızı bul","a":"toprak","d":"Toprak cansızdır ama bitkilerin yetişmesi için gereklidir."}],"ans":"Buğday, fare ve toprak birlikte küçük bir tarla ekosistemi oluşturur."}]},"ortaokul":{"kolay":[{"q":"Ekosistemi oluşturan iki ana bileşen nedir?","steps":[{"t":"Yaşayan kısım","a":"canlı (biyotik)","d":"Bitkiler, hayvanlar ve mikroorganizmalar ekosistemin canlı bileşenidir."},{"t":"Yaşamayan kısım","a":"cansız (abiyotik)","d":"Su, hava, toprak, ışık ve sıcaklık ekosistemin cansız bileşenidir."}],"ans":"Ekosistem, canlı (biyotik) ve cansız (abiyotik) olmak üzere iki ana bileşenden oluşur."},{"q":"Canlıların çevreleriyle ilişkilerini inceleyen bilim dalı nedir?","steps":[{"t":"Bilim dalının adı","a":"ekoloji","d":"Canlıların hem birbiriyle hem de çevresiyle ilişkisini ekoloji inceler."},{"t":"Konusu","a":"canlı-çevre ilişkisi","d":"Ekoloji, ekosistemlerin yapısını ve işleyişini araştırır."}],"ans":"Canlıların birbiriyle ve çevreyle ilişkisini inceleyen bilim dalı ekolojidir."},{"q":"Popülasyon nedir? Bir örnekle açıklayınız.","steps":[{"t":"Tanımı","a":"aynı tür bireyler","d":"Aynı türden olan ve aynı bölgede yaşayan bireylerin tümüdür."},{"t":"Örnek","a":"bir göldeki sazanlar","d":"Bir göldeki tüm sazan balıkları bir popülasyon oluşturur."}],"ans":"Popülasyon, belirli bir alanda yaşayan aynı türe ait bireylerin tümüdür; örneğin bir göldeki tüm sazanlar."},{"q":"Komünite (tür topluluğu) neyi ifade eder?","steps":[{"t":"Farklı popülasyonlar","a":"birden çok tür","d":"Bir alanda yaşayan farklı türlerin popülasyonları bir aradadır."},{"t":"Hepsi birlikte","a":"komünite","d":"Bu farklı popülasyonların tümü birlikte komüniteyi oluşturur."}],"ans":"Komünite, belirli bir alanda yaşayan farklı türlere ait popülasyonların tümüdür."},{"q":"Ekosistemler kara ve su olarak nasıl ayrılır?","steps":[{"t":"Kara ekosistemleri","a":"orman, çöl, çayır","d":"Karada bulunan orman, çöl ve çayır gibi ortamlardır."},{"t":"Su ekosistemleri","a":"göl, deniz, akarsu","d":"Suda bulunan göl, deniz ve akarsu gibi ortamlardır."}],"ans":"Ekosistemler karasal (orman, çöl) ve sucul (göl, deniz) olmak üzere iki büyük gruba ayrılır."}],"zor":[{"q":"Canlı organizasyon basamaklarını küçükten büyüğe sıralayınız.","steps":[{"t":"En küçük basamak","a":"birey","d":"Tek bir canlı varlık bireydir; örneğin bir geyik."},{"t":"Artan basamaklar","a":"popülasyon, komünite","d":"Aynı türler popülasyonu, farklı türler komüniteyi oluşturur."},{"t":"En büyük basamaklar","a":"ekosistem, biyosfer","d":"Komünite ve cansız çevre ekosistemi; tüm ekosistemler biyosferi oluşturur."}],"ans":"Sıralama: birey → popülasyon → komünite → ekosistem → biyosfer şeklindedir."},{"q":"Komünite ile ekosistem arasındaki temel fark nedir?","steps":[{"t":"Komünite","a":"sadece canlılar","d":"Komünite yalnızca bir alandaki canlı türlerinin tümünü kapsar."},{"t":"Ekosistem","a":"canlı + cansız","d":"Ekosistem ise komüniteye cansız çevreyi de ekler."}],"ans":"Komünite sadece canlıları kapsarken ekosistem, canlılarla birlikte cansız çevreyi de içerir."},{"q":"Biyosfer nedir ve neden en geniş basamaktır?","steps":[{"t":"Tanımı","a":"canlı yaşamı küresi","d":"Biyosfer, Dünya üzerinde canlıların yaşadığı tüm bölgeleri kapsar."},{"t":"Kapsamı","a":"tüm ekosistemler","d":"Karada, suda ve havadaki bütün ekosistemleri içine alır."}],"ans":"Biyosfer, Dünya'daki canlı yaşamın bulunduğu tüm ekosistemleri kapsadığı için en geniş organizasyon basamağıdır."},{"q":"Bir çöl ekosisteminde abiyotik faktörler canlıları nasıl etkiler?","steps":[{"t":"Çöl koşulları","a":"sıcak ve kurak","d":"Çölde sıcaklık yüksek, su (nem) ise çok azdır."},{"t":"Canlıya etkisi","a":"uyum sağlama","d":"Canlılar az suyla yaşamaya ve sıcağa dayanmaya uyum sağlar."}],"ans":"Çöldeki yüksek sıcaklık ve su azlığı gibi abiyotik faktörler, canlıları bu koşullara uyum sağlamaya zorlar."},{"q":"Bir göl ekosisteminde canlı ve cansız bileşenlere üçer örnek veriniz.","steps":[{"t":"Canlı bileşenler","a":"balık, yosun, kurbağa","d":"Gölde balıklar, su yosunları ve kurbağalar gibi canlılar yaşar."},{"t":"Cansız bileşenler","a":"su, ışık, sıcaklık","d":"Su, güneş ışığı ve sıcaklık gölün cansız bileşenleridir."}],"ans":"Canlı bileşenler: balık, yosun ve kurbağa; cansız bileşenler: su, ışık ve sıcaklıktır."}]},"lise":{"kolay":[{"q":"Ekosistem kavramını bilimsel olarak tanımlayınız.","steps":[{"t":"Bileşenler","a":"biyotik ve abiyotik","d":"Ekosistem, canlı (biyotik) ve cansız (abiyotik) bileşenleri kapsar."},{"t":"Etkileşim","a":"madde ve enerji akışı","d":"Bu bileşenler arasında sürekli madde döngüsü ve enerji akışı vardır."}],"ans":"Ekosistem, belirli bir alandaki canlı ve cansız bileşenlerin madde döngüsü ve enerji akışıyla etkileştiği sistemdir."},{"q":"Ekoloji biliminin temel inceleme alanı nedir?","steps":[{"t":"İlişki türleri","a":"canlı-canlı, canlı-çevre","d":"Ekoloji, canlıların birbiriyle ve cansız çevreyle olan ilişkisini inceler."},{"t":"Düzeyleri","a":"popülasyondan biyosfere","d":"Bu incelemeyi popülasyon, komünite, ekosistem ve biyosfer düzeyinde yapar."}],"ans":"Ekoloji, canlıların birbiriyle ve çevreleriyle olan ilişkilerini popülasyondan biyosfere kadar inceleyen bilim dalıdır."},{"q":"Abiyotik faktörlere dört örnek veriniz.","steps":[{"t":"Fiziksel faktörler","a":"ışık, sıcaklık","d":"Güneş ışığı ve sıcaklık ekosistemi etkileyen fiziksel faktörlerdir."},{"t":"Kimyasal faktörler","a":"su, mineral, pH","d":"Su, topraktaki mineraller ve pH değeri kimyasal abiyotik faktörlerdir."}],"ans":"Abiyotik faktörlere ışık, sıcaklık, su ve mineraller örnek verilebilir."},{"q":"Biyotik faktörler hangi canlı gruplarını kapsar?","steps":[{"t":"Üreticiler","a":"ototroflar","d":"Fotosentez veya kemosentezle besin üreten bitki ve bakterilerdir."},{"t":"Tüketici ve ayrıştırıcılar","a":"heterotroflar","d":"Hazır besinle beslenen hayvanlar ile ölü maddeyi parçalayan ayrıştırıcılardır."}],"ans":"Biyotik faktörler üreticiler, tüketiciler ve ayrıştırıcılar olmak üzere tüm canlı bileşenleri kapsar."},{"q":"Birey ve popülasyon kavramlarını ayırt ediniz.","steps":[{"t":"Birey","a":"tek canlı","d":"Birey, kendi başına yaşayan tek bir canlı organizmadır."},{"t":"Popülasyon","a":"aynı tür bireyler","d":"Aynı türe ait bireylerin belirli alandaki tümü popülasyondur."}],"ans":"Birey tek bir canlıyı, popülasyon ise aynı türe ait bireylerin tümünü ifade eder."},{"q":"Habitat kavramı neyi ifade eder?","steps":[{"t":"Tanımı","a":"yaşam adresi","d":"Habitat, bir canlının doğal olarak yaşadığı, bulunduğu yerdir."},{"t":"Örnek","a":"alabalık-akarsu","d":"Alabalığın habitatı soğuk ve oksijence zengin akarsulardır."}],"ans":"Habitat, bir canlı ya da popülasyonun doğal olarak yaşadığı çevredir; canlının yaşam adresidir."},{"q":"Karasal ve sucul ekosistemleri ayırt eden temel faktör nedir?","steps":[{"t":"Karasal","a":"toprak temelli","d":"Karasal ekosistemlerde yaşam toprak ve hava üzerinde sürer."},{"t":"Sucul","a":"su temelli","d":"Sucul ekosistemlerde yaşam tatlı su veya tuzlu su içinde sürer."}],"ans":"Karasal ekosistemler toprak temelliyken sucul ekosistemler su ortamına dayanır; ayırt edici faktör yaşamın geçtiği ortamdır."},{"q":"Sucul ekosistemler tuzluluğa göre nasıl ikiye ayrılır?","steps":[{"t":"Tatlı su","a":"göl, akarsu","d":"Tuz oranı çok düşük olan göller, akarsular ve göletlerdir."},{"t":"Tuzlu su","a":"deniz, okyanus","d":"Yüksek tuz oranına sahip deniz ve okyanuslardır."}],"ans":"Sucul ekosistemler tatlı su (göl, akarsu) ve tuzlu su (deniz, okyanus) olarak ikiye ayrılır."},{"q":"Ekosistemde enerjinin temel kaynağı nedir?","steps":[{"t":"Enerji girişi","a":"Güneş","d":"Ekosisteme giren enerjinin neredeyse tamamı Güneş'ten gelir."},{"t":"Dönüşüm","a":"üreticilerce yakalanır","d":"Üreticiler güneş enerjisini fotosentezle kimyasal enerjiye çevirir."}],"ans":"Ekosistemde enerjinin temel kaynağı Güneş'tir ve bu enerji üreticiler tarafından kimyasal enerjiye dönüştürülür."},{"q":"Tür kavramı biyolojide nasıl tanımlanır?","steps":[{"t":"Ortak özellikler","a":"benzer bireyler","d":"Yapısal ve kalıtsal olarak benzer bireyler aynı türden sayılır."},{"t":"Üreme ölçütü","a":"verimli döl","d":"Çiftleştiğinde kısır olmayan verimli yavru veren bireyler aynı türdür."}],"ans":"Tür, ortak özellikler taşıyan ve aralarında çiftleşip verimli döl verebilen bireyler topluluğudur."},{"q":"Organizasyon basamaklarında ekosistemden sonra gelen basamak nedir?","steps":[{"t":"Ekosistem sonrası","a":"biyosfer","d":"Ekosistemden sonraki ve en geniş basamak biyosferdir."},{"t":"Kapsamı","a":"tüm yaşam alanları","d":"Biyosfer, Dünya üzerindeki tüm ekosistemleri kapsar."}],"ans":"Ekosistemden sonra gelen ve en geniş organizasyon basamağı biyosferdir."},{"q":"Ekolojik niş (görev) kavramı neyi ifade eder?","steps":[{"t":"Tanımı","a":"canlının görevi","d":"Niş, bir canlının ekosistemdeki rolü ve yaşam biçimidir."},{"t":"Habitattan farkı","a":"adres değil meslek","d":"Habitat canlının adresi, niş ise canlının yaptığı 'iş'tir."}],"ans":"Ekolojik niş, bir canlının ekosistemdeki görevini ve yaşam biçimini ifade eder; habitat adres ise niş meslektir."},{"q":"Bir ekosistemin sürdürülebilir olması için neye ihtiyaç vardır?","steps":[{"t":"Enerji girişi","a":"sürekli güneş enerjisi","d":"Sistemin işlemesi için dışarıdan sürekli güneş enerjisi girmelidir."},{"t":"Madde döngüsü","a":"geri dönüşüm","d":"Su, karbon ve azot gibi maddelerin döngüyle yeniden kullanılması gerekir."}],"ans":"Bir ekosistemin sürdürülebilirliği için sürekli enerji girişi ve maddelerin döngüsel olarak yeniden kullanılması gerekir."},{"q":"Karasal ekosistemleri belirleyen başlıca abiyotik faktörler nelerdir?","steps":[{"t":"İklim faktörleri","a":"sıcaklık, yağış","d":"Bir bölgenin sıcaklığı ve yağış miktarı ekosistem tipini belirler."},{"t":"Toprak faktörü","a":"toprak yapısı","d":"Toprağın yapısı ve mineral içeriği de yetişen bitkileri etkiler."}],"ans":"Karasal ekosistemleri başlıca sıcaklık, yağış ve toprak yapısı gibi abiyotik faktörler belirler."},{"q":"Üretici, tüketici ve ayrıştırıcıların ekosistemdeki rolünü kısaca açıklayınız.","steps":[{"t":"Üretici ve tüketici","a":"besin üretir / tüketir","d":"Üreticiler besin üretir, tüketiciler ise bu besinle beslenir."},{"t":"Ayrıştırıcı","a":"maddeyi döndürür","d":"Ayrıştırıcılar ölü canlıları parçalayıp mineralleri toprağa kazandırır."}],"ans":"Üreticiler besin üretir, tüketiciler tüketir, ayrıştırıcılar ölü maddeyi parçalayarak madde döngüsünü tamamlar."}],"zor":[{"q":"Canlı organizasyon basamaklarını biyosfere kadar sıralayıp her birini tanımlayınız.","steps":[{"t":"Birey ve popülasyon","a":"tek canlı, aynı tür","d":"Birey tek canlıdır; aynı türün bireyleri popülasyonu oluşturur."},{"t":"Komünite ve ekosistem","a":"farklı türler + cansız","d":"Farklı popülasyonlar komüniteyi; komünite + cansız çevre ekosistemi oluşturur."},{"t":"Biyosfer","a":"tüm ekosistemler","d":"Tüm ekosistemlerin toplamı biyosferi meydana getirir."}],"ans":"Birey → popülasyon (aynı tür) → komünite (farklı türler) → ekosistem (komünite + cansız çevre) → biyosfer (tüm ekosistemler)."},{"q":"Aynı habitatta yaşayan iki farklı tür neden farklı nişlere sahip olmak zorundadır?","steps":[{"t":"Rekabet ilkesi","a":"kaynak yarışı","d":"Aynı kaynağı kullanan türler arasında şiddetli rekabet oluşur."},{"t":"Rekabetçi dışlama","a":"biri elenir","d":"Nişleri tam aynı olursa biri diğerini ortamdan dışlar."},{"t":"Sonuç","a":"niş farklılaşması","d":"Bir arada kalabilmek için türler kaynak kullanımını farklılaştırır."}],"ans":"Tam aynı nişi paylaşan türlerden biri rekabetle elenir; bir arada yaşayabilmek için nişlerini farklılaştırmak zorundadırlar."},{"q":"Bir popülasyonun yoğunluğunu sınırlayan yoğunluğa bağlı ve bağsız faktörlere örnek veriniz.","steps":[{"t":"Yoğunluğa bağlı","a":"besin, hastalık","d":"Birey sayısı arttıkça etkisi artan besin yetersizliği ve hastalıklardır."},{"t":"Yoğunluğa bağsız","a":"sel, don, yangın","d":"Birey sayısından bağımsız etki eden sel, don ve yangın gibi olaylardır."},{"t":"Karşılaştırma","a":"biyotik / abiyotik","d":"Bağlı faktörler genelde biyotik, bağsızlar genelde abiyotik kökenlidir."}],"ans":"Yoğunluğa bağlı faktörler besin ve hastalık (biyotik); yoğunluğa bağsız faktörler sel, don ve yangın (abiyotik) gibi etmenlerdir."},{"q":"Ekosistemde enerji 'akarken' maddenin 'döndüğü' neden söylenir?","steps":[{"t":"Enerjinin yolu","a":"tek yönlü kayıp","d":"Güneş enerjisi sistemden geçer ve sonunda ısı olarak kaybolur, geri dönmez."},{"t":"Maddenin yolu","a":"döngüsel kullanım","d":"Karbon, azot ve su gibi maddeler tekrar tekrar kullanılır."},{"t":"Sonuç","a":"akış vs döngü","d":"Enerji tek yönlü aktığı için akar, madde yeniden kullanıldığı için döner."}],"ans":"Enerji güneşten girip ısı olarak kaybolduğu için tek yönlü akar; madde ise döngülerle sürekli yeniden kullanıldığı için döner."},{"q":"Tatlı su ve tuzlu su ekosistemlerinde yaşayan canlıların osmotik dengeyi sağlamadaki farkını açıklayınız.","steps":[{"t":"Tatlı su ortamı","a":"hücreye su girer","d":"Tatlı suda ortam hipotonik olduğu için canlıya sürekli su girer."},{"t":"Tuzlu su ortamı","a":"hücreden su çıkar","d":"Deniz hipertonik olduğu için canlının vücudundan su dışarı kaçar."},{"t":"Uyum","a":"farklı stratejiler","d":"Tatlı su canlısı fazla suyu atar, deniz canlısı suyu tutup tuzu atar."}],"ans":"Tatlı su canlıları fazla suyu vücuttan atarken, tuzlu su canlıları su kaybını önler ve fazla tuzu dışarı atarak osmotik dengeyi sağlar."},{"q":"İki bölgede aynı türden geyikler yaşıyorsa neden tek popülasyon sayılmayabilir?","steps":[{"t":"Popülasyon ölçütü","a":"aynı alan + gen alışverişi","d":"Bir popülasyonun bireyleri aynı alanda yaşar ve birbiriyle üreyebilir."},{"t":"Coğrafi engel","a":"izolasyon","d":"Dağ veya nehir gibi engeller iki grubu birbirinden ayırabilir."},{"t":"Sonuç","a":"ayrı popülasyonlar","d":"Aralarında gen alışverişi olmadığı için ayrı popülasyon kabul edilir."}],"ans":"İki grup coğrafi engelle ayrılıp aralarında gen alışverişi olmuyorsa, aynı tür olsalar da ayrı popülasyonlar sayılır."},{"q":"Bir ekosistemde tür çeşitliliğinin yüksek olması neden istikrarı (dengeyi) artırır?","steps":[{"t":"Besin ağı","a":"çok bağlantılı","d":"Çok türlü ekosistemde besin ağı karmaşık ve çok bağlantılıdır."},{"t":"Yedek yollar","a":"alternatif besin","d":"Bir tür azalsa bile başka türler boşluğu doldurabilir."},{"t":"Sonuç","a":"dirençli sistem","d":"Bu nedenle sistem dış etkilere karşı daha dayanıklı ve dengeli olur."}],"ans":"Tür çeşitliliği yüksek ekosistemde besin ağı çok bağlantılıdır; bir tür azalsa yerini başka tür doldurabildiği için sistem daha dengeli ve dirençlidir."},{"q":"Komünite içinde 'baskın tür' ve 'anahtar tür' kavramlarını ayırt ediniz.","steps":[{"t":"Baskın tür","a":"en bol/yaygın","d":"Baskın tür, sayı veya biyokütle bakımından en fazla olan türdür."},{"t":"Anahtar tür","a":"dengeyi tutan","d":"Anahtar tür, sayısı az olsa bile ekosistem dengesi için kritik öneme sahiptir."},{"t":"Karşılaştırma","a":"bolluk vs etki","d":"Baskın tür bollukla, anahtar tür ise etkisiyle öne çıkar."}],"ans":"Baskın tür bolluk ve biyokütle bakımından öne çıkarken, anahtar tür sayısı az olsa bile ekosistem dengesini koruyan kritik türdür."},{"q":"Karasal ekosistemlerin (biyomların) dağılımını esas olarak hangi iki abiyotik faktör belirler?","steps":[{"t":"İlk faktör","a":"sıcaklık","d":"Ortalama sıcaklık, hangi bitki ve hayvanların yaşayabileceğini sınırlar."},{"t":"İkinci faktör","a":"yağış miktarı","d":"Yıllık yağış, su bulunabilirliğini ve bitki örtüsünü belirler."},{"t":"Sonuç","a":"biyom tipi","d":"Sıcaklık ve yağışın birleşimi orman, çöl, tundra gibi biyomları oluşturur."}],"ans":"Karasal biyomların dağılımını esas olarak sıcaklık ve yağış miktarı belirler; bu ikisinin birleşimi orman, çöl, tundra gibi tipleri oluşturur."},{"q":"Bir göl ekosisteminde derinliğe inildikçe ışık ve oksijen nasıl değişir, bunun canlılara etkisi nedir?","steps":[{"t":"Işık değişimi","a":"derinde azalır","d":"Güneş ışığı suya battıkça soğurulur, derinde fotosentez azalır."},{"t":"Oksijen değişimi","a":"derinde düşer","d":"Fotosentez azaldığı için üst tabakaya göre dipte oksijen daha azdır."},{"t":"Canlıya etkisi","a":"katmanlı dağılım","d":"Üreticiler yüzeyde, oksijene az ihtiyaç duyan canlılar derinde yaşar."}],"ans":"Derinlik arttıkça ışık ve oksijen azalır; bu yüzden üreticiler ve çoğu canlı üst tabakada, az oksijene dayanıklı canlılar ise derinde yoğunlaşır."},{"q":"Bir ekosistemde ayrıştırıcılar ortadan kalksa madde döngüsü nasıl etkilenir?","steps":[{"t":"Ayrıştırıcının görevi","a":"ölüyü parçalar","d":"Ayrıştırıcılar ölü canlı ve atıkları parçalayıp mineralleri açığa çıkarır."},{"t":"Kaybolunca","a":"mineral hapsolur","d":"Onlar olmayınca besin maddeleri ölü gövdelerde hapsolup kalır."},{"t":"Sonuç","a":"döngü durur","d":"Üreticiler mineral bulamaz, madde döngüsü kesintiye uğrar."}],"ans":"Ayrıştırıcılar olmasaydı ölü maddedeki mineraller toprağa dönemez, üreticiler bunları kullanamaz ve madde döngüsü durarak ekosistem çökerdi."},{"q":"Aynı ekosistemde yaşayan iki popülasyon arasında rekabet, av-avcı ve simbiyoz ilişkilerinin temel farkını açıklayınız.","steps":[{"t":"Rekabet","a":"ortak kaynak","d":"İki tür aynı kaynak için yarışır, her ikisi de bir miktar zarar görür."},{"t":"Av-avcı","a":"biri yer biri yenir","d":"Avcı avı yiyerek beslenir; biri kazanır, diğeri ölür."},{"t":"Simbiyoz","a":"birlikte yaşam","d":"İki tür yakın yaşar; ortak yaşamda en az biri yarar görür."}],"ans":"Rekabette iki tür aynı kaynak için yarışıp zarar görür; av-avcıda biri diğerini yer; simbiyozda türler birlikte yaşar ve en az biri yarar sağlar."},{"q":"Bir popülasyonun büyüme grafiği başlangıçta J şeklinde sonra S şekline döner; bunun nedeni nedir?","steps":[{"t":"J evresi","a":"sınırsız üreme","d":"Kaynak bolken popülasyon hızlı ve üstel (J) artar."},{"t":"Direnç devreye girer","a":"çevresel direnç","d":"Besin azalması, rekabet ve hastalık gibi etkenler büyümeyi yavaşlatır."},{"t":"S evresi","a":"taşıma kapasitesi","d":"Popülasyon ortamın taşıma kapasitesinde dengelenip S şeklini alır."}],"ans":"Başlangıçta kaynak bolken üstel (J) artan popülasyon, çevresel direnç devreye girince yavaşlar ve taşıma kapasitesinde dengelenerek S şekline döner."},{"q":"Aynı türün karada ve suda yaşayan akrabaları neden farklı vücut yapılarına sahiptir? Adaptasyon açısından açıklayınız.","steps":[{"t":"Farklı abiyotik baskı","a":"su vs kara","d":"Su ortamı kaldırma kuvveti, oksijen ve hareket bakımından karadan farklıdır."},{"t":"Doğal seçilim","a":"uygun olan kalır","d":"Her ortamda o koşula en uygun bireyler hayatta kalıp ürer."},{"t":"Sonuç","a":"adaptasyon","d":"Zamanla suda yüzme, karada yürüme için farklı yapılar gelişir."}],"ans":"Su ve kara farklı abiyotik baskılar uygular; doğal seçilim her ortamda uygun bireyleri koruduğu için zamanla farklı vücut yapıları (adaptasyonlar) gelişir."},{"q":"Biyosfer, litosfer, hidrosfer ve atmosfer arasındaki ilişki ekosistemler açısından nasıl açıklanır?","steps":[{"t":"Cansız küreler","a":"toprak, su, hava","d":"Litosfer kara/toprağı, hidrosfer suyu, atmosfer havayı kapsar."},{"t":"Biyosferin konumu","a":"kesişim bölgesi","d":"Biyosfer, bu üç cansız kürenin canlı barındıran kesişim alanıdır."},{"t":"Ekosistem bağı","a":"etkileşim alanı","d":"Ekosistemler, canlıların bu üç küreyle alışveriş yaptığı yerlerde kurulur."}],"ans":"Biyosfer, litosfer (kara), hidrosfer (su) ve atmosferin (hava) kesiştiği canlı barındıran bölgedir; ekosistemler bu cansız kürelerle canlıların etkileştiği alanlarda oluşur."}]}},"habitatNiche":{"ilkokul":{"kolay":[{"q":"Bir canlının yaşadığı yere ne ad verilir?","steps":[{"t":"Yaşanılan yer","a":"yuva gibi düşün","d":"Her canlının yaşadığı, beslendiği ve barındığı bir yer vardır. Bu yer onun adresi gibidir."},{"t":"Bilimsel ad","a":"habitat","d":"Canlının yaşadığı bu yere <b>habitat</b> denir. Örneğin balığın habitatı sudur."}],"ans":"Bir canlının yaşadığı yere <b>habitat</b> (yaşama alanı) denir."},{"q":"Habitatı su olan bir canlıya örnek ver.","steps":[{"t":"Suda yaşayanlar","a":"sucul canlılar","d":"Bazı canlılar yaşamlarını suda geçirir; suyun içinde yüzer ve beslenirler."},{"t":"Örnek","a":"balık","d":"Balığın habitatı sudur. Balık suyun dışında uzun süre yaşayamaz."}],"ans":"Balığın habitatı (yaşama alanı) sudur."},{"q":"Solucanın yaşama alanı (habitatı) neresidir?","steps":[{"t":"Nerede görürüz?","a":"toprakta","d":"Solucanı çoğu zaman nemli toprağı kazınca görürüz. Toprağın içinde dolaşır."},{"t":"Habitat","a":"toprak","d":"Solucanın <b>habitatı</b> nemli topraktır. Orada beslenir ve barınır."}],"ans":"Solucanın habitatı (yaşama alanı) nemli topraktır."},{"q":"Bir canlının habitatı, onun günlük yaşamında neyi sağlar?","steps":[{"t":"İhtiyaçlar","a":"yiyecek, su, barınak","d":"Her canlının yaşamak için yiyeceğe, suya ve saklanacak bir yere ihtiyacı vardır."},{"t":"Habitatın görevi","a":"ihtiyaçları karşılar","d":"<b>Habitat</b>, canlıya bu ihtiyaçları sağlayan yaşama alanıdır."}],"ans":"Habitat, canlıya yiyecek, su ve barınak gibi ihtiyaçlarını sağlayan yaşama alanıdır."},{"q":"Kutup ayısının habitatı nasıl bir yerdir?","steps":[{"t":"Nerede yaşar?","a":"soğuk yerler","d":"Kutup ayısı çok soğuk, karlı ve buzlu bölgelerde yaşar."},{"t":"Habitat","a":"buzul/kutup bölgesi","d":"Kalın kürkü sayesinde soğuk <b>habitatına</b> uyum sağlamıştır."}],"ans":"Kutup ayısının habitatı soğuk, karlı ve buzlu kutup bölgeleridir."}],"zor":[{"q":"Habitat 'adres' ise, ekolojik niş neye benzer?","steps":[{"t":"Adres ne demek?","a":"yaşadığı yer","d":"Bir canlının habitatı, onun yaşadığı yer yani adresidir."},{"t":"Niş ne demek?","a":"yaptığı iş/meslek","d":"<b>Ekolojik niş</b>, canlının doğada yaptığı iştir; yani onun mesleği gibidir."}],"ans":"Habitat canlının adresi (yaşadığı yer), ekolojik niş ise onun mesleği (yaptığı iş) gibidir."},{"q":"Bir arının ekolojik nişi (doğadaki işi) nedir?","steps":[{"t":"Arı ne yapar?","a":"çiçek tozu taşır","d":"Arı çiçekten çiçeğe gezerken çiçek tozlarını taşır ve bal yapar."},{"t":"Doğadaki işi","a":"tozlaşmayı sağlar","d":"Arının <b>nişi</b>, çiçeklerin tozlaşmasına yardım etmektir. Bu onun doğadaki işidir."}],"ans":"Arının ekolojik nişi, çiçekten çiçeğe gezerek tozlaşmayı sağlamaktır."},{"q":"Aynı bahçede yaşayan solucan ile kuş farklı işler yapar. Bu duruma ne denir?","steps":[{"t":"Habitat aynı mı?","a":"aynı bahçe","d":"İkisi de aynı yerde, yani aynı habitatta yaşıyor olabilir."},{"t":"İşleri farklı","a":"farklı niş","d":"Solucan toprağı havalandırır, kuş böcek yer. İşleri farklı olduğu için <b>nişleri</b> farklıdır."}],"ans":"Aynı habitatta yaşasalar da işleri (nişleri) farklı olduğu için her birinin ayrı ekolojik nişi vardır."},{"q":"İki hayvan tamamen aynı yiyeceği ve aynı yeri isterse ne olur?","steps":[{"t":"İstekler aynı","a":"aynı şeyi isterler","d":"İki hayvan aynı yiyeceği ve aynı yeri isterse aralarında bir çekişme başlar."},{"t":"Sonuç","a":"yarışırlar","d":"Aynı şeyi istedikleri için <b>yarışırlar</b> (rekabet). Genelde biri kazanır, diğeri başka yere gider."}],"ans":"Aynı şeyi isteyen iki hayvan birbiriyle yarışır (rekabet eder); biri kazanır, diğeri başka kaynak veya yer arar."},{"q":"Baykuş gece, atmaca gündüz avlanır. Bu durum onlara nasıl yardım eder?","steps":[{"t":"Farklı zaman","a":"gece-gündüz","d":"Baykuş geceleri, atmaca gündüzleri avlanır. Av zamanları farklıdır."},{"t":"Faydası","a":"yarışmazlar","d":"Farklı zamanlarda avlandıkları için aynı avı paylaşmak için fazla <b>yarışmazlar</b>; ikisi de rahat beslenir."}],"ans":"Farklı zamanlarda avlandıkları için aynı yiyecek için fazla yarışmazlar; böylece ikisi de rahatça yaşar."}]},"ortaokul":{"kolay":[{"q":"Habitat ile ekolojik niş arasındaki temel fark nedir?","steps":[{"t":"Habitat","a":"yaşanılan yer","d":"<b>Habitat</b>, bir canlının yaşadığı fiziksel ortamdır; yani onun adresidir."},{"t":"Ekolojik niş","a":"canlının rolü","d":"<b>Ekolojik niş</b>, canlının ekosistemdeki görevidir; beslenme, üreme ve diğer canlılarla ilişkilerini kapsar."}],"ans":"Habitat canlının yaşadığı yer (adres), ekolojik niş ise canlının ekosistemdeki rolü (meslek) olarak özetlenir."},{"q":"Bir kurbağanın habitatı ile nişini ayrı ayrı açıkla.","steps":[{"t":"Habitatı","a":"göl kenarı/sulak alan","d":"Kurbağa nemli, sulak alanlarda; göl ve dere kenarlarında yaşar. Bu onun <b>habitatıdır</b>."},{"t":"Nişi","a":"böcek avcısı","d":"Kurbağa böcekleri yiyerek böcek sayısını dengeler; kendisi de leyleğe besin olur. Bu onun <b>nişidir</b>."}],"ans":"Kurbağanın habitatı sulak alanlardır; nişi ise böcek avlayıp besin zincirinde yer almasıdır."},{"q":"Ekolojik niş hangi bilgileri içerir?","steps":[{"t":"Beslenme","a":"ne yer, kime yem olur","d":"Niş; canlının neyle beslendiğini ve hangi canlılara besin olduğunu içerir."},{"t":"İlişkiler ve ortam","a":"sıcaklık, rekabet, üreme","d":"Ayrıca canlının dayandığı sıcaklık aralığı, rekabet ettiği türler ve üreme biçimini de kapsar."}],"ans":"Ekolojik niş; canlının beslenmesini, diğer canlılarla ilişkilerini, ortam koşullarına dayanımını ve üreme biçimini içerir."},{"q":"Aynı habitatta yaşayan kartal ile fare farklı nişlere sahip midir? Neden?","steps":[{"t":"Habitat","a":"aynı çayır","d":"Kartal ve fare aynı çayır habitatını paylaşabilir."},{"t":"Niş farkı","a":"avcı ve av","d":"Fare bitki yer, kartal fareyi avlar. Beslenme rolleri farklı olduğu için <b>nişleri</b> farklıdır."}],"ans":"Evet; aynı habitatı paylaşsalar da kartal avcı, fare ot oburudur, bu yüzden ekolojik nişleri farklıdır."},{"q":"Bir bitkinin ekolojik nişi neden hayvanlardan farklı tanımlanır?","steps":[{"t":"Bitkinin beslenmesi","a":"fotosentez","d":"Bitki besinini kendisi üretir; güneş ışığı, su ve karbondioksit kullanır."},{"t":"Nişi","a":"üretici rolü","d":"Bu nedenle bitkinin nişi <b>üretici</b> olmaktır; ekosisteme besin ve oksijen sağlar."}],"ans":"Bitkinin nişi üretici olmaktır; fotosentezle besin ve oksijen üreterek ekosistemi besler."}],"zor":[{"q":"İki tür tamamen aynı nişi paylaşmaya çalışırsa uzun vadede ne olur?","steps":[{"t":"Kaynak rekabeti","a":"aynı kaynağı isterler","d":"Aynı nişi isteyen iki tür, aynı besin ve alan için sürekli <b>rekabet</b> eder."},{"t":"Sonuç","a":"biri elenir","d":"Daha az başarılı olan tür azalır veya bölgeden çekilir. Buna <b>rekabetçi dışlama</b> denir."}],"ans":"İki tür aynı nişi tam paylaşamaz; rekabet sonucu biri bölgeden dışlanır (rekabetçi dışlama ilkesi)."},{"q":"Aynı ağaçta beslenen iki kuş türü nasıl bir arada yaşayabilir?","steps":[{"t":"Sorun","a":"aynı kaynak","d":"İkisi de aynı ağaçtan besleniyorsa rekabet riski vardır."},{"t":"Çözüm","a":"niş ayrımı","d":"Biri üst dallardan, diğeri alt dallardan beslenirse <b>nişleri ayrışır</b> ve rekabet azalır."}],"ans":"Beslenme yerlerini ağacın farklı bölümlerine ayırarak (niş ayrımı) rekabeti azaltıp bir arada yaşarlar."},{"q":"Bir baykuş ve bir atmacanın aynı bölgede yaşamasını sağlayan niş farkı nedir?","steps":[{"t":"Ortak yön","a":"aynı avlar","d":"İkisi de küçük kemirgenlerle beslenebilir, bu rekabet yaratabilir."},{"t":"Niş ayrımı","a":"farklı zaman","d":"Baykuş gece, atmaca gündüz avlanır. Avlanma zamanları farklı olduğu için <b>nişleri ayrışır</b>."}],"ans":"Baykuş gece, atmaca gündüz avlandığı için zaman bakımından nişleri ayrışır ve aynı bölgede yaşayabilirler."},{"q":"Bir göldeki balık türlerinin farklı derinliklerde yaşaması nişle nasıl açıklanır?","steps":[{"t":"Gözlem","a":"farklı derinlik","d":"Bir türü yüzeye yakın, diğeri dipte yaşar. Aynı gölü paylaşırlar."},{"t":"Açıklama","a":"niş ayrımı","d":"Farklı derinliklerde farklı besin bulurlar; böylece kaynaklar paylaşılır ve <b>rekabet azalır</b>."}],"ans":"Türler farklı derinliklerde beslenerek nişlerini ayırır; kaynaklar paylaşıldığı için rekabet azalır."},{"q":"Bir türün doğal düşmanı olmasaydı yaşayabileceği geniş niş ile gerçekte yaşadığı dar niş nasıl adlandırılır?","steps":[{"t":"İdeal durum","a":"temel niş","d":"Hiç rakip ve düşman olmasaydı türün kullanabileceği tüm kaynaklara <b>temel niş</b> denir."},{"t":"Gerçek durum","a":"gerçekleşen niş","d":"Rekabet ve düşman baskısı yüzünden türün gerçekte kullandığı dar alana <b>gerçekleşen niş</b> denir."}],"ans":"Geniş ideal alan temel niş, rekabet nedeniyle daralan gerçek alan gerçekleşen niş olarak adlandırılır."}]},"lise":{"kolay":[{"q":"Habitat ve ekolojik niş kavramlarını bilimsel olarak tanımla.","steps":[{"t":"Habitat","a":"fiziksel yaşam alanı","d":"<b>Habitat</b>, bir türün doğal olarak bulunduğu, belirli abiyotik ve biyotik koşullara sahip fiziksel ortamdır."},{"t":"Ekolojik niş","a":"işlevsel rol","d":"<b>Ekolojik niş</b>, bir türün ekosistemdeki işlevsel rolüdür; kaynak kullanımı, ilişkileri ve etkileri kapsar."}],"ans":"Habitat türün yaşadığı fiziksel ortam; ekolojik niş ise türün o ortamdaki işlevsel rolü ve kaynak kullanım biçimidir."},{"q":"Ekolojik niş neden çok boyutlu bir kavram olarak ele alınır?","steps":[{"t":"Tek değişken yetersiz","a":"birçok faktör","d":"Bir türün yaşamı tek bir koşula değil; sıcaklık, nem, besin, ışık gibi çok sayıda faktöre bağlıdır."},{"t":"Çok boyutluluk","a":"hiper-hacim","d":"Bu faktörlerin her biri bir eksen olarak düşünülürse niş, çok boyutlu bir <b>hiper-hacim</b> olarak tanımlanır (Hutchinson)."}],"ans":"Niş, sıcaklık, nem, besin gibi birçok çevresel eksenin oluşturduğu çok boyutlu bir hiper-hacim olduğundan çok boyutlu kabul edilir."},{"q":"Temel niş (fundamental) ile gerçekleşen niş (realized) arasındaki fark nedir?","steps":[{"t":"Temel niş","a":"potansiyel kullanım","d":"<b>Temel niş</b>, türün hiçbir biyotik kısıt olmadan kullanabileceği tüm koşulların toplamıdır."},{"t":"Gerçekleşen niş","a":"fiili kullanım","d":"<b>Gerçekleşen niş</b>, rekabet ve avcılık gibi etkileşimler sonucu türün gerçekte işgal ettiği daha dar alandır."}],"ans":"Temel niş türün potansiyel olarak kullanabileceği tüm koşullar, gerçekleşen niş ise biyotik kısıtlarla daralan fiili kullanım alanıdır."},{"q":"Rekabetçi dışlama ilkesi (Gause ilkesi) neyi ifade eder?","steps":[{"t":"İlke","a":"aynı niş paylaşılamaz","d":"İki tür aynı kaynakları aynı şekilde kullanıyorsa, yani <b>özdeş niş</b> paylaşıyorsa kalıcı olarak bir arada var olamaz."},{"t":"Sonuç","a":"biri elenir","d":"Daha verimli tür kazanır; diğeri ya yerel olarak yok olur ya da nişini değiştirir."}],"ans":"Rekabetçi dışlama ilkesi, özdeş niş paylaşan iki türün kalıcı olarak birlikte yaşayamayacağını; birinin elenmesi gerektiğini ifade eder."},{"q":"Niş ayrımı (kaynak paylaşımı) bir arada yaşamayı nasıl mümkün kılar?","steps":[{"t":"Sorun","a":"kaynak çakışması","d":"Benzer türler aynı kaynağı kullanırsa rekabet şiddetlenir."},{"t":"Çözüm","a":"kaynakların bölüşülmesi","d":"Türler besini, zamanı veya mekânı bölüşerek <b>niş ayrımı</b> yapar; nişlerdeki örtüşme azalır ve birlikte yaşam mümkün olur."}],"ans":"Niş ayrımı, türlerin kaynak, zaman veya mekânı bölüşmesiyle niş örtüşmesini azaltarak rekabeti hafifletir ve bir arada yaşamayı sağlar."},{"q":"Aynı habitatı paylaşan iki türün farklı nişlere sahip olabilmesi neyi gösterir?","steps":[{"t":"Habitat ortak","a":"aynı alan","d":"İki tür aynı orman ya da gölü paylaşabilir; yani habitatları aynıdır."},{"t":"Niş farkı","a":"farklı rol","d":"Farklı besin veya tabaka kullanırlarsa rolleri ayrışır; bu, <b>habitatın paylaşılabildiğini ama nişin türe özgü olduğunu</b> gösterir."}],"ans":"Aynı habitatın paylaşılabilmesine karşın nişlerin farklı olması, habitatın ortak, nişin ise türe özgü işlevsel rol olduğunu gösterir."},{"q":"Bir türün generalist (genelci) ve specialist (uzmanlaşmış) niş tipi arasındaki fark nedir?","steps":[{"t":"Genelci","a":"geniş niş","d":"<b>Genelci</b> türler çok çeşitli kaynak ve koşulu kullanır; geniş bir nişe sahiptir (ör. fare, karga)."},{"t":"Uzmanlaşmış","a":"dar niş","d":"<b>Uzmanlaşmış</b> türler belirli kaynağa bağımlıdır; dar nişe sahiptir (ör. yalnız okaliptus yiyen koala)."}],"ans":"Genelci türlerin geniş bir nişi (çeşitli kaynak), uzmanlaşmış türlerin ise dar bir nişi (sınırlı kaynak) vardır."},{"q":"Karbonsuz dünyada bile bir bitkinin nişi neden 'üretici' rolüyle tanımlanır?","steps":[{"t":"Trofik konum","a":"besin üretimi","d":"Bitki, fotosentezle inorganik maddeden organik besin üretir; bu onun temel işlevidir."},{"t":"Niş tanımı","a":"üretici niş","d":"Niş, türün ekosistemdeki işlevsel rolü olduğundan bitkinin nişi <b>üretici</b> (ototrof) konumudur."}],"ans":"Niş işlevsel rolü ifade ettiğinden, fotosentezle besin üreten bitkinin ekolojik nişi üretici (ototrof) rolüdür."},{"q":"Bir tür yeni bir bölgeye girdiğinde yerli türün gerçekleşen nişi nasıl etkilenebilir?","steps":[{"t":"Yeni rekabet","a":"kaynak çakışması","d":"İstilacı tür, yerli türle aynı kaynakları kullanırsa rekabet artar."},{"t":"Niş daralması","a":"daralan kullanım","d":"Yerli tür kaynakların bir kısmından çekilir; <b>gerçekleşen nişi daralır</b>, hatta yok olabilir."}],"ans":"İstilacı tür rekabeti artırarak yerli türün gerçekleşen nişini daraltabilir, kaynak kullanımını sınırlar."},{"q":"Habitat çeşitliliği ile tür çeşitliliği arasındaki ilişki nedir?","steps":[{"t":"Çeşitli habitat","a":"farklı koşullar","d":"Bir alanda farklı habitatlar (su, kaya, orman tabakası) bulunması çeşitli yaşam koşulları sunar."},{"t":"Niş sayısı","a":"çok niş, çok tür","d":"Daha fazla farklı koşul daha fazla <b>niş</b> demektir; bu da daha çok türün bir arada yaşamasını sağlar."}],"ans":"Habitat çeşitliliği arttıkça kullanılabilir niş sayısı artar, bu da tür çeşitliliğinin yükselmesine olanak tanır."},{"q":"İki türün nişlerinin kısmen örtüşmesi ne anlama gelir?","steps":[{"t":"Kısmi örtüşme","a":"ortak kaynak","d":"İki tür bazı kaynakları paylaşır ama her birinin kendine özgü kaynakları da vardır."},{"t":"Sonuç","a":"sınırlı rekabet","d":"Örtüşen bölümde <b>rekabet</b> olur; örtüşmeyen kaynaklar sayesinde tam dışlanma olmadan bir arada yaşayabilirler."}],"ans":"Kısmi niş örtüşmesi, örtüşen kaynaklarda rekabet doğurur; ancak ayrı kaynaklar olduğundan türler tam dışlanmadan bir arada var olabilir."},{"q":"Bir türün nişinde sıcaklık 'tolerans aralığı' neden önemlidir?","steps":[{"t":"Tolerans","a":"yaşam sınırı","d":"Her türün yaşayabildiği bir alt ve üst sıcaklık sınırı (tolerans aralığı) vardır."},{"t":"Niş boyutu","a":"niş ekseni","d":"Bu aralık nişin bir <b>boyutudur</b>; türün hangi bölgede ve mevsimde yaşayabileceğini belirler."}],"ans":"Sıcaklık tolerans aralığı nişin bir boyutudur ve türün dağılımını, hangi koşullarda yaşayabileceğini belirler."},{"q":"Aynı çiçeği ziyaret eden farklı tozlaşma zamanlarına sahip iki böcek nişi nasıl paylaşır?","steps":[{"t":"Ortak kaynak","a":"aynı çiçek","d":"İki böcek de aynı çiçeğin nektarını kullanır, bu rekabet yaratabilir."},{"t":"Zamansal ayrım","a":"farklı saat","d":"Biri sabah, diğeri öğleden sonra ziyaret ederse <b>zamansal niş ayrımı</b> ile aynı çiçeği paylaşırlar."}],"ans":"Böcekler çiçeği farklı saatlerde ziyaret ederek zamansal niş ayrımı yapar ve aynı kaynağı paylaşabilir."},{"q":"Niş kavramı bir ekosistemde 'boş niş' fikrini nasıl açıklar?","steps":[{"t":"Boş niş","a":"kullanılmayan rol","d":"Bir ekosistemde henüz hiçbir türün kullanmadığı kaynak veya işlevsel rol bulunabilir; buna <b>boş niş</b> denir."},{"t":"Doldurulması","a":"yeni tür/uyum","d":"Bu niş, dışarıdan gelen ya da uyum sağlayan bir türle zamanla doldurulabilir."}],"ans":"Boş niş, ekosistemde henüz bir türün kullanmadığı işlevsel roldür ve göç veya evrimsel uyumla doldurulabilir."},{"q":"Habitatın bozulması bir türün nişini nasıl ortadan kaldırabilir?","steps":[{"t":"Habitat kaybı","a":"koşullar yok olur","d":"Ormanın kesilmesi gibi durumlarda türün ihtiyaç duyduğu koşullar ortadan kalkar."},{"t":"Niş kaybı","a":"rol icra edilemez","d":"Koşullar olmadan tür işlevsel rolünü (nişini) sürdüremez; bölgede <b>yok olabilir</b>."}],"ans":"Habitat bozulduğunda türün ihtiyaç duyduğu koşullar yok olur; tür nişini icra edemez ve yerel olarak yok olabilir."}],"zor":[{"q":"Gause'nin Paramecium deneyi rekabetçi dışlama ilkesini nasıl kanıtlar?","steps":[{"t":"Deney düzeneği","a":"iki tür aynı kapta","d":"Gause, aynı besinle beslenen iki Paramecium türünü aynı kapta yetiştirdi."},{"t":"Gözlem","a":"biri eledi","d":"Bir tür sayıca arttı, diğeri azalıp <b>yok oldu</b>. Ayrı kaplarda ise ikisi de yaşadı."},{"t":"Sonuç","a":"özdeş niş yaşatmaz","d":"Özdeş niş paylaşan türlerin bir arada kalamayacağı, yani <b>rekabetçi dışlama</b> doğrulandı."}],"ans":"Aynı kapta özdeş niş paylaşan iki Paramecium türünden biri elenirken ayrı kaplarda ikisinin de yaşaması, rekabetçi dışlama ilkesini kanıtlar."},{"q":"MacArthur'un ötleğen kuşları çalışması niş ayrımını nasıl gösterir?","steps":[{"t":"Sorun","a":"aynı ağaç, aynı besin","d":"Beş ötleğen türü aynı ladin ağacında böceklerle besleniyordu; özdeş niş beklentisi vardı."},{"t":"Gözlem","a":"farklı tabaka","d":"Her tür ağacın farklı bölgesinde (üst, orta, alt, iç, dış) beslenmekteydi."},{"t":"Sonuç","a":"mekânsal niş ayrımı","d":"Beslenme bölgelerini bölüşerek <b>niş ayrımı</b> yaptılar; rekabetçi dışlama olmadan bir arada yaşadılar."}],"ans":"Beş ötleğen türü aynı ağacın farklı bölgelerinde beslenerek mekânsal niş ayrımı yaptı; bu, özdeş niş gerginliğini çözerek bir arada yaşamayı sağladı."},{"q":"Connell'in deniz minaresi (Chthamalus-Balanus) deneyi temel niş ile gerçekleşen niş ayrımını nasıl ortaya koyar?","steps":[{"t":"Dağılım","a":"farklı yükseklik","d":"Kayalık kıyıda Chthamalus üst, Balanus alt bölgede yaşıyordu."},{"t":"Balanus uzaklaştırılınca","a":"Chthamalus yayıldı","d":"Balanus elenince Chthamalus alt bölgeye de yayıldı; yani <b>temel nişi</b> daha genişti."},{"t":"Sonuç","a":"rekabet daraltır","d":"Doğal koşulda Balanus rekabetle Chthamalus'u üst bölgeye sıkıştırıyordu; bu daralmış alan <b>gerçekleşen niştir</b>."}],"ans":"Balanus uzaklaştırılınca Chthamalus'un alt bölgeye yayılması, geniş temel nişin rekabetle daraldığını ve gözlenen dar alanın gerçekleşen niş olduğunu gösterir."},{"q":"Karakter kayması (character displacement) niş ayrımıyla nasıl ilişkilidir?","steps":[{"t":"Tek başına","a":"benzer özellik","d":"Bir tür yalnız yaşadığında özellikleri (ör. gaga boyu) belirli bir aralıktadır."},{"t":"Birlikte yaşayınca","a":"özellik farklılaşır","d":"Aynı bölgede benzer bir türle yaşadığında, rekabeti azaltmak için özellikleri <b>farklılaşır</b> (ör. gagalar farklı boyutlara kayar)."},{"t":"Sonuç","a":"niş ayrımı pekişir","d":"Bu evrimsel farklılaşma, türlerin farklı kaynakları kullanmasını sağlayıp <b>niş ayrımını</b> güçlendirir."}],"ans":"Karakter kayması, birlikte yaşayan benzer türlerin özelliklerinin evrimle farklılaşmasıdır; bu farklılaşma kaynak kullanımını ayırarak niş ayrımını pekiştirir."},{"q":"Rekabetçi dışlama ilkesi her durumda neden gerçekleşmez? Hangi etmenler dışlamayı engeller?","steps":[{"t":"İlkenin koşulu","a":"sabit, özdeş niş","d":"Dışlama, kaynaklar sabit ve nişler tam özdeş olduğunda beklenir."},{"t":"Engelleyen etmenler","a":"bozulma, avcılık","d":"Çevresel dalgalanmalar, avcılık ve karışıklıklar dengeyi sürekli bozarak hiçbir türün tam üstünlük kurmasını engeller."},{"t":"Sonuç","a":"birlikte yaşam sürer","d":"Kaynaklar değişken olduğundan veya avcı baskısı eşitlediğinden türler <b>bir arada</b> kalabilir."}],"ans":"Çevresel dalgalanmalar, avcılık ve karışıklıklar tam rekabetçi üstünlüğü engellediğinden, nişler özdeşe yakın olsa bile dışlama her zaman gerçekleşmez."},{"q":"Hutchinson'ın n-boyutlu hiper-hacim niş modeli klasik niş tanımını nasıl geliştirir?","steps":[{"t":"Klasik tanım","a":"rol/yer","d":"Daha önce niş, türün rolü ya da yeri olarak nitel tanımlanıyordu."},{"t":"Hutchinson modeli","a":"çok boyutlu hacim","d":"Sıcaklık, nem, besin gibi her çevresel değişken bir eksen kabul edilir; nişi bu eksenlerin oluşturduğu <b>n-boyutlu hiper-hacim</b> tanımlar."},{"t":"Katkı","a":"ölçülebilirlik","d":"Bu model nişi nicel ve <b>ölçülebilir</b> hale getirir; temel ve gerçekleşen niş tam olarak ayrılabilir."}],"ans":"Hutchinson modeli nişi, her çevresel değişkenin bir eksen olduğu n-boyutlu bir hiper-hacim olarak tanımlayarak nişi nicel, ölçülebilir ve temel/gerçekleşen ayrımına uygun hale getirir."},{"q":"Niş örtüşmesinin derecesi ile rekabet şiddeti arasındaki ilişki nasıl değerlendirilir?","steps":[{"t":"Örtüşme ölçütü","a":"ortak kaynak oranı","d":"İki türün niş hiper-hacimlerinin örtüşen bölümü, paylaşılan kaynak miktarını gösterir."},{"t":"İlişki","a":"örtüşme ↑ rekabet ↑","d":"Örtüşme arttıkça aynı kaynaklara olan talep artar; bu da <b>rekabet şiddetini</b> yükseltir."},{"t":"Eşik","a":"sınır benzerlik","d":"Belirli bir örtüşme eşiğini aşan türler bir arada yaşayamaz; bu eşiğe <b>sınır benzerlik (limiting similarity)</b> denir."}],"ans":"Niş örtüşmesi arttıkça rekabet şiddeti artar; sınır benzerlik eşiği aşıldığında türler bir arada yaşayamaz ve dışlama beklenir."},{"q":"Bir türün temel nişi neden gerçekleşen nişinden daima daha büyük (veya eşit) olur?","steps":[{"t":"Temel niş","a":"kısıtsız potansiyel","d":"Temel niş, biyotik etkileşimler hiç olmasaydı türün kullanabileceği tüm koşulları kapsar."},{"t":"Daraltıcı etkiler","a":"rekabet, avcılık","d":"Gerçekte rekabet, avcılık ve parazitlik gibi etkiler türün kullanımını <b>kısıtlar</b>."},{"t":"Sonuç","a":"daralma","d":"Bu kısıtlar kaynak eklemez, yalnızca çıkarır; bu yüzden gerçekleşen niş temel nişin <b>alt kümesidir</b>."}],"ans":"Biyotik etkileşimler ancak kaynak kullanımını daraltabildiğinden, gerçekleşen niş temel nişin alt kümesidir ve ondan daima küçük ya da eşittir."},{"q":"Niş yapılandırma (niche construction) kavramı, türün kendi nişini nasıl değiştirdiğini açıklar; örnekle anlat.","steps":[{"t":"Tanım","a":"ortamı değiştirme","d":"Bazı türler etkinlikleriyle çevreyi değiştirerek kendi ve diğer türlerin nişini yeniden biçimlendirir."},{"t":"Örnek","a":"kunduz barajı","d":"Kunduz baraj yaparak akarsuyu göle çevirir; bu hem kendi nişini hem de sulak alan türlerinin nişini <b>oluşturur</b>."},{"t":"Sonuç","a":"geri besleme","d":"Bu değişiklik gelecekteki seçilim baskılarını da etkiler; tür ile ortam arasında <b>geri besleme</b> doğar."}],"ans":"Niş yapılandırma, kunduzun baraj yapması gibi türlerin çevreyi değiştirerek kendi ve diğer türlerin nişini biçimlendirmesidir ve ortamla evrimsel geri besleme yaratır."},{"q":"İstilacı türler yerli türleri rekabetçi dışlama yoluyla nasıl elimine eder; süreci adımlandır.","steps":[{"t":"Giriş ve üstünlük","a":"avantajlı istilacı","d":"İstilacı tür, yeni alanda doğal düşmandan yoksun ve kaynak kullanımında daha verimli olabilir."},{"t":"Niş örtüşmesi","a":"aynı kaynak","d":"Yerli türle yüksek niş örtüşmesi olduğunda aynı kaynak için yoğun <b>rekabet</b> başlar."},{"t":"Dışlama","a":"yerli tür çekilir","d":"İstilacı kaynakları daha hızlı tüketerek yerli türün gerçekleşen nişini sıfıra indirir; yerli tür <b>yerel olarak yok olur</b>."}],"ans":"İstilacı tür, üstün kaynak kullanımı ve yüksek niş örtüşmesiyle yerli türle rekabete girer, kaynakları tüketerek onun gerçekleşen nişini yok eder ve yerel yok oluşa sürükler."},{"q":"Trofik niş ile mekânsal niş ayrımının bir besin ağındaki birlikte yaşamı nasıl desteklediğini açıkla.","steps":[{"t":"Trofik niş","a":"ne yediği","d":"Trofik niş, türün besin ağındaki beslenme düzeyini ve avını tanımlar."},{"t":"Mekânsal niş","a":"nerede beslendiği","d":"Mekânsal niş, türün kaynağı hangi konum/tabakada kullandığını belirtir."},{"t":"Birleşik etki","a":"çok eksenli ayrım","d":"Türler hem ne yedikleri hem nerede beslendikleri bakımından ayrışırsa örtüşme azalır; bu <b>çok eksenli niş ayrımı</b> rekabeti düşürerek bir arada yaşamı destekler."}],"ans":"Trofik (ne yediği) ve mekânsal (nerede beslendiği) niş ayrımının birleşmesi, niş örtüşmesini birden çok eksende azaltarak rekabeti düşürür ve türlerin bir arada yaşamasını destekler."},{"q":"Bir adaya ulaşan tek bir ata türden çok sayıda farklı türün oluşması (uyumsal açılım) niş kavramıyla nasıl açıklanır?","steps":[{"t":"Boş nişler","a":"kullanılmamış kaynaklar","d":"Yeni adada rakip az olduğundan birçok kaynak ve işlevsel rol, yani <b>boş niş</b> bulunur."},{"t":"Farklılaşma","a":"niş işgali","d":"Ata türün soyları farklı kaynaklara uyum sağlayarak değişik nişleri işgal eder (ör. Darwin ispinozlarında gaga çeşitliliği)."},{"t":"Sonuç","a":"uyumsal açılım","d":"Niş ayrımıyla giden hızlı tür oluşumuna <b>uyumsal açılım (adaptive radiation)</b> denir."}],"ans":"Yeni ortamdaki boş nişler, ata türün soylarının farklı kaynaklara uyum sağlayıp ayrı nişleri işgal etmesini sağlar; bu niş temelli çeşitlenme uyumsal açılım olarak açıklanır."},{"q":"Avcı baskısının türlerin gerçekleşen nişlerini genişletip rekabetçi dışlamayı engellemesi (predator-mediated coexistence) nasıl işler?","steps":[{"t":"Rekabet riski","a":"baskın tür","d":"Avcı yoksa en güçlü rakip tür kaynakları kapar ve diğerlerini dışlama eğilimindedir."},{"t":"Avcının etkisi","a":"baskını sınırlar","d":"Avcı, baskın türün sayısını düşürünce bu türün kaynak üzerindeki baskısı azalır."},{"t":"Sonuç","a":"birlikte yaşam","d":"Zayıf rakipler de kaynağa erişip nişlerini koruyabilir; böylece avcılık <b>rekabetçi dışlamayı engeller</b> ve çeşitliliği artırır."}],"ans":"Avcı, baskın rakibin sayısını sınırlayarak onun kaynak üzerindeki üstünlüğünü azaltır; bu sayede zayıf rakipler de var olur ve avcı aracılı birlikte yaşam rekabetçi dışlamayı engeller."},{"q":"Çevresel değişkenlik ve karışıklıkların orta düzeyde olması (orta düzey bozulma hipotezi) niş doluluğu ve tür çeşitliliğini nasıl etkiler?","steps":[{"t":"Düşük bozulma","a":"rekabet baskın","d":"Çok az karışıklıkta en güçlü rakip nişleri kapar; rekabetçi dışlamayla çeşitlilik <b>azalır</b>."},{"t":"Yüksek bozulma","a":"yalnız dirençliler","d":"Çok sık karışıklıkta yalnızca hızlı toparlanan birkaç tür kalır; çeşitlilik yine <b>düşer</b>."},{"t":"Orta düzey","a":"en yüksek çeşitlilik","d":"Orta düzey bozulmada hem rekabetçi hem öncü türler nişlerini koruyabilir; bu yüzden tür çeşitliliği <b>en yüksektir</b>."}],"ans":"Orta düzey bozulma hipotezine göre çeşitlilik orta seviye karışıklıkta en yüksektir; çünkü hem güçlü rakipler hem öncü türler nişlerini koruyup rekabetçi dışlama tamamlanmaz."},{"q":"Bir türün temel nişinin tamamen rakipler tarafından kaplanması durumunda hayatta kalmak için izleyebileceği ekolojik ve evrimsel yollar nelerdir?","steps":[{"t":"Sorun","a":"niş kaplanmış","d":"Rakip tür, hedef türün temel nişiyle tamamen örtüşürse gerçekleşen niş sıfıra yaklaşır."},{"t":"Ekolojik yanıt","a":"göç/kaynak değişimi","d":"Tür, rakibin bulunmadığı bir bölgeye göç edebilir veya kullanılmayan alternatif kaynaklara <b>kayabilir</b>."},{"t":"Evrimsel yanıt","a":"karakter kayması","d":"Uzun vadede seçilim, türün özelliklerini farklılaştırır (karakter kayması) ve <b>yeni bir niş</b> ayrışmasını sağlar; aksi halde yerel yok oluş gerçekleşir."}],"ans":"Tür ya rakibin olmadığı alana göç eder veya alternatif kaynağa kayar (ekolojik kaçış), ya da karakter kaymasıyla evrimsel niş ayrışması geliştirir; bu yollar başarısız olursa yerel yok oluşla karşılaşır."}]}},"karbonDongusu":{"ilkokul":{"kolay":[{"q":"Bitkiler havadan hangi gazı alır?","steps":[{"t":"Havadaki gaz","a":"karbondioksit","d":"Havada bitkilerin beslenmesi için kullandığı <b>karbondioksit</b> gazı vardır."},{"t":"Bitkinin işi","a":"yapraklarla alır","d":"Bitki, yaprakları ile bu gazı içine çeker ve besin yapmakta kullanır."}],"ans":"Bitkiler havadan karbondioksit (CO₂) gazını alır."},{"q":"Bir mum yandığında havaya hangi gaz verilir?","steps":[{"t":"Yanma olayı","a":"mum yanar","d":"Mum yandığında alev çıkar ve havaya görünmez bir gaz salınır."},{"t":"Çıkan gaz","a":"karbondioksit","d":"Yanma sonucu havaya <b>karbondioksit</b> gazı verilir."}],"ans":"Mum yanınca havaya karbondioksit (CO₂) verilir."},{"q":"Nefes verdiğimizde havaya hangi gazı bırakırız?","steps":[{"t":"Nefes alıp verme","a":"soluruz","d":"İçimize hava çeker, sonra geri veririz."},{"t":"Verilen gaz","a":"karbondioksit","d":"Nefes verirken vücudumuzdan havaya <b>karbondioksit</b> çıkar."}],"ans":"Nefes verince havaya karbondioksit (CO₂) bırakırız."},{"q":"Bitkiler büyümek için karbondioksiti nereden alır?","steps":[{"t":"Kaynak","a":"havadan","d":"Bitkiler etrafındaki havadan gaz alır."},{"t":"Kullanımı","a":"besin yapar","d":"Aldığı karbondioksiti güneş ışığıyla besine çevirir ve büyür."}],"ans":"Bitkiler karbondioksiti havadan alır."},{"q":"Odun sobada yandığında karbondioksit nereye gider?","steps":[{"t":"Odunun yanması","a":"duman çıkar","d":"Odun yanınca sobadan duman ve gaz çıkar."},{"t":"Gazın yeri","a":"havaya karışır","d":"Çıkan <b>karbondioksit</b> baca yoluyla havaya karışır."}],"ans":"Yanan odundan çıkan karbondioksit havaya karışır."}],"zor":[{"q":"Bitkiler karbondioksit alır, hayvanlar verir. Bu durum havadaki gaz için neyi sağlar?","steps":[{"t":"Hayvanlar","a":"CO₂ verir","d":"Hayvanlar ve insanlar nefes verirken havaya karbondioksit bırakır."},{"t":"Bitkiler","a":"CO₂ alır","d":"Bitkiler bu karbondioksiti havadan alıp kullanır."},{"t":"Sonuç","a":"denge","d":"Böylece havadaki gaz tükenmez, sürekli kullanılır."}],"ans":"Bitkiler aldığı için havadaki karbondioksit dengede kalır."},{"q":"Ormanlar kesilirse havadaki karbondioksite ne olur?","steps":[{"t":"Ağaçların işi","a":"CO₂ tutar","d":"Ağaçlar havadan karbondioksit alıp azaltır."},{"t":"Kesilince","a":"alan azalır","d":"Ağaçlar kesilince karbondioksiti alacak bitki azalır."},{"t":"Sonuç","a":"artar","d":"Havadaki karbondioksit eskisinden daha çok birikir."}],"ans":"Ormanlar kesilince havadaki karbondioksit artar."},{"q":"Yaprak çürüyünce içindeki karbon nereye gider?","steps":[{"t":"Çürüme","a":"ayrışır","d":"Yere düşen yaprak küçük canlılar tarafından çürütülür."},{"t":"Karbonun çıkışı","a":"havaya","d":"Çürüme sırasında karbon <b>karbondioksit</b> olarak havaya geri döner."}],"ans":"Çürüyen yapraktaki karbon karbondioksit olarak havaya döner."},{"q":"Bir bitki güneşte besin yaparken havadaki gaz nasıl değişir?","steps":[{"t":"Besin yapımı","a":"güneşle","d":"Bitki güneş ışığıyla besin üretir."},{"t":"Gaz alımı","a":"CO₂ azalır","d":"Bu sırada havadan karbondioksit alır, yani gaz azalır."},{"t":"Sonuç","a":"oksijen verir","d":"Karşılığında havaya oksijen bırakır."}],"ans":"Bitki besin yaparken havadaki karbondioksit azalır, oksijen artar."},{"q":"Çok sayıda araba egzozdan gaz çıkarırsa havaya ne olur?","steps":[{"t":"Arabaların yakıtı","a":"yanar","d":"Arabalar yakıt yakarak çalışır."},{"t":"Çıkan gaz","a":"karbondioksit","d":"Egzozdan havaya <b>karbondioksit</b> salınır."},{"t":"Sonuç","a":"birikir","d":"Çok araba olunca havada karbondioksit birikir ve hava kirlenir."}],"ans":"Çok araba olunca havadaki karbondioksit artar."}]},"ortaokul":{"kolay":[{"q":"Fotosentez sırasında bitkiler havadaki karbondioksiti ne yapar?","steps":[{"t":"Fotosentez","a":"besin üretimi","d":"Bitkiler güneş enerjisiyle fotosentez yapar."},{"t":"CO₂ kullanımı","a":"tutulur","d":"Havadaki karbondioksit alınıp besin (glikoz) yapımında kullanılır, yani karbon bitkide depolanır."}],"ans":"Fotosentezle bitkiler karbondioksiti tutup besine çevirir."},{"q":"Solunum sırasında canlılar karbon açısından ne yapar?","steps":[{"t":"Solunum","a":"enerji üretimi","d":"Canlılar besindeki enerjiyi solunumla açığa çıkarır."},{"t":"CO₂ salınımı","a":"havaya verilir","d":"Bu işlemde karbon <b>karbondioksit</b> olarak havaya salınır."}],"ans":"Solunumla canlılar havaya karbondioksit salar."},{"q":"Ölen canlıları ayrıştırıcılar parçalarken karbona ne olur?","steps":[{"t":"Ayrıştırıcılar","a":"bakteri, mantar","d":"Ölü canlıları bakteri ve mantarlar parçalar."},{"t":"Karbonun dönüşü","a":"havaya CO₂","d":"Ayrışma sırasında karbon karbondioksit olarak havaya geri döner."}],"ans":"Ayrıştırma sonucu karbon karbondioksit olarak havaya döner."},{"q":"Fosil yakıtlar (kömür, petrol) nereden oluşur?","steps":[{"t":"Kaynak","a":"eski canlılar","d":"Milyonlarca yıl önce ölen canlıların kalıntıları yer altında kalmıştır."},{"t":"Oluşum","a":"basınç ve zaman","d":"Uzun sürede basınç altında <b>fosil yakıtlara</b> dönüşmüştür; içlerinde karbon depolanmıştır."}],"ans":"Fosil yakıtlar, eski canlı kalıntılarından oluşur ve karbon depolar."},{"q":"Karbon döngüsünde havadaki karbondioksiti azaltan temel olay nedir?","steps":[{"t":"Süreçler","a":"fotosentez–solunum","d":"Karbon döngüsünde fotosentez CO₂ alır, solunum CO₂ verir."},{"t":"Azaltan olay","a":"fotosentez","d":"<b>Fotosentez</b> havadan karbondioksiti çekerek miktarını azaltır."}],"ans":"Havadaki karbondioksiti azaltan temel olay fotosentezdir."}],"zor":[{"q":"Fotosentez ve solunum karbon döngüsünde nasıl birbirini dengeler?","steps":[{"t":"Fotosentez","a":"CO₂ tutar","d":"Bitkiler havadan karbondioksit alıp organik karbona (glikoz) çevirir."},{"t":"Solunum","a":"CO₂ verir","d":"Tüm canlılar solunumda organik karbonu parçalayıp havaya CO₂ salar."},{"t":"Denge","a":"döngü kapanır","d":"Tutulan ve salınan karbon yaklaşık eşit olunca havadaki CO₂ dengede kalır."}],"ans":"Fotosentez CO₂ tutar, solunum salar; ikisi karbon dengesini sağlar."},{"q":"Kömür ve petrol yakıldığında milyonlarca yıllık karbona ne olur?","steps":[{"t":"Depolanan karbon","a":"fosilde","d":"Fosil yakıtlarda karbon yer altında uzun süre depolanmıştır."},{"t":"Yanma","a":"CO₂ açığa çıkar","d":"Yakıldığında bu karbon hızla <b>karbondioksite</b> dönüşür."},{"t":"Sonuç","a":"hava CO₂'si artar","d":"Kısa sürede çok karbon havaya eklenir, doğal denge bozulur."}],"ans":"Fosil yakıt yanınca depolanmış karbon hızla havaya CO₂ olarak eklenir."},{"q":"Atmosferdeki karbondioksitin artması neden küresel ısınmaya yol açar?","steps":[{"t":"Sera etkisi","a":"ısı tutar","d":"Karbondioksit, yeryüzünden yansıyan ısı ışınlarını tutan bir sera gazıdır."},{"t":"CO₂ artışı","a":"daha çok ısı","d":"Havada CO₂ artınca daha fazla ısı tutulur."},{"t":"Sonuç","a":"sıcaklık artar","d":"Yeryüzünün ortalama sıcaklığı yükselir; buna <b>küresel ısınma</b> denir."}],"ans":"Artan CO₂ daha çok ısı tuttuğu için küresel ısınmaya yol açar."},{"q":"Okyanuslar karbon döngüsünde nasıl bir rol üstlenir?","steps":[{"t":"CO₂ çözünmesi","a":"suda erir","d":"Havadaki karbondioksitin bir kısmı okyanus suyunda çözünür."},{"t":"Depolama","a":"karbon deposu","d":"Okyanuslar çok miktarda karbonu tuttuğu için büyük bir <b>karbon havuzudur</b>."},{"t":"Rol","a":"dengeleyici","d":"Bu sayede havadaki CO₂ miktarını bir miktar azaltır."}],"ans":"Okyanuslar CO₂'yi çözüp depolayan büyük bir karbon havuzudur."},{"q":"Bir ağacın gövdesindeki karbon aslında nereden gelmiştir?","steps":[{"t":"CO₂ alımı","a":"havadan","d":"Ağaç fotosentezde havadaki karbondioksiti alır."},{"t":"Karbonun yolu","a":"odunda saklanır","d":"Alınan karbon glikoza, sonra odun ve dallara dönüşerek depolanır."},{"t":"Sonuç","a":"havadan karbon","d":"Yani gövdedeki karbon büyük ölçüde havadaki <b>karbondioksitten</b> gelir."}],"ans":"Ağaç gövdesindeki karbon, havadan alınan karbondioksitten gelir."}]},"lise":{"kolay":[{"q":"Karbon döngüsünde karbon hangi formda atmosferde bulunur?","steps":[{"t":"Atmosfer karbonu","a":"gaz halinde","d":"Atmosferde karbon çoğunlukla gaz molekülleri halindedir."},{"t":"Form","a":"CO₂ (ve CH₄)","d":"Başlıca <b>karbondioksit</b> (CO₂), az miktarda metan (CH₄) olarak bulunur."}],"ans":"Atmosferde karbon esas olarak karbondioksit (CO₂) formundadır."},{"q":"Fotosentezde karbon hangi anorganik bileşikten organik bileşiğe geçer?","steps":[{"t":"Girdi","a":"CO₂","d":"Fotosentez girdisi anorganik karbondioksittir."},{"t":"Ürün","a":"glikoz","d":"Karbon, CO₂'den glikoz (C₆H₁₂O₆) gibi organik moleküllere bağlanır."}],"ans":"Fotosentezde karbon, CO₂'den organik glikoza geçer."},{"q":"Solunumda organik karbonun son hali ne olur?","steps":[{"t":"Yıkım","a":"glikoz parçalanır","d":"Hücresel solunumda glikozdaki organik karbon yükseltgenir."},{"t":"Ürün","a":"CO₂","d":"Karbon, son ürün olarak <b>karbondioksit</b> halinde atmosfere salınır."}],"ans":"Solunumda organik karbon CO₂'ye yükseltgenip atmosfere döner."},{"q":"Karbon döngüsünde ayrıştırıcıların temel işlevi nedir?","steps":[{"t":"Substrat","a":"ölü organik madde","d":"Ayrıştırıcılar ölü canlı ve atıklardaki organik karbonu kullanır."},{"t":"Sonuç","a":"CO₂ geri verir","d":"Bu maddeleri parçalayarak karbonu CO₂ olarak atmosfere döndürür."}],"ans":"Ayrıştırıcılar ölü organik karbonu parçalayıp CO₂ olarak geri verir."},{"q":"Fosil yakıtlar karbon havuzu olarak hangi sınıfa girer?","steps":[{"t":"Depolama süresi","a":"çok uzun","d":"Fosil yakıtlardaki karbon milyonlarca yıl yer altında kalır."},{"t":"Sınıf","a":"uzun vadeli havuz","d":"Bu yüzden litosferdeki <b>uzun vadeli (yavaş) karbon havuzu</b> sayılır."}],"ans":"Fosil yakıtlar, litosferdeki uzun vadeli karbon havuzudur."},{"q":"Atmosferik CO₂ okyanusa girdiğinde ilk olarak hangi bileşiği oluşturur?","steps":[{"t":"Çözünme","a":"suda erir","d":"CO₂ deniz suyunda çözünür."},{"t":"Tepkime","a":"karbonik asit","d":"Su ile birleşerek <b>karbonik asit</b> (H₂CO₃) oluşturur."}],"ans":"Okyanusta çözünen CO₂, su ile karbonik asit (H₂CO₃) oluşturur."},{"q":"Karbonatlı kayaçlar (kireçtaşı) karbon döngüsünde neyi temsil eder?","steps":[{"t":"Bileşim","a":"CaCO₃","d":"Kireçtaşı kalsiyum karbonat (CaCO₃) içerir, yapısında karbon vardır."},{"t":"Rol","a":"en büyük depo","d":"Tortul kayaçlar karbonun en büyük ve en uzun süreli <b>deposunu</b> oluşturur."}],"ans":"Karbonatlı kayaçlar, karbonun en büyük uzun süreli deposudur."},{"q":"Sera etkisi temel olarak hangi mekanizmaya dayanır?","steps":[{"t":"Gelen enerji","a":"görünür ışık","d":"Güneşten gelen kısa dalga boylu ışık yüzeyi ısıtır."},{"t":"Sera gazı etkisi","a":"IR tutulur","d":"Yüzeyden yayılan uzun dalga (kızılötesi) ısıyı CO₂ gibi gazlar tutar."}],"ans":"Sera etkisi, sera gazlarının kızılötesi ısıyı tutmasına dayanır."},{"q":"Karbon döngüsünde 'karbon tutulumu' (sekestrasyon) ne demektir?","steps":[{"t":"Anlam","a":"karbon depolama","d":"Atmosferdeki karbonun alınıp uzun süre depolanmasıdır."},{"t":"Örnek","a":"orman, toprak","d":"Ormanlar, toprak ve okyanuslar CO₂'yi tutarak <b>sekestrasyon</b> sağlar."}],"ans":"Karbon tutulumu, atmosfer CO₂'sinin alınıp depolanmasıdır."},{"q":"Net birincil üretim (NPP) karbon açısından neyi gösterir?","steps":[{"t":"Brüt üretim","a":"fotosentez","d":"Üreticilerin fotosentezle tuttuğu toplam karbon brüt üretimdir."},{"t":"Net üretim","a":"solunum çıkar","d":"Solunumla harcanan karbon çıkarılınca <b>net</b> tutulan karbon kalır."}],"ans":"NPP, fotosentezle tutulan karbondan solunum kaybı çıkınca kalan karbondur."},{"q":"İnsan etkisiyle atmosferik CO₂ derişimi sanayi öncesine göre nasıl değişmiştir?","steps":[{"t":"Sanayi öncesi","a":"yaklaşık 280 ppm","d":"Sanayi devriminden önce CO₂ derişimi yaklaşık 280 ppm idi."},{"t":"Bugün","a":"400 ppm üzeri","d":"Fosil yakıt kullanımıyla derişim 400 ppm'i aşacak şekilde <b>artmıştır</b>."}],"ans":"Atmosferik CO₂, ~280 ppm'den 400 ppm üzerine çıkarak artmıştır."},{"q":"Metan (CH₄) karbon döngüsünde neden önemli bir gazdır?","steps":[{"t":"Kaynak","a":"anaerobik ayrışma","d":"Bataklık, çürüme ve sindirimde oksijensiz ortamda metan açığa çıkar."},{"t":"Etki","a":"güçlü sera gazı","d":"Metan, birim başına CO₂'den çok daha güçlü bir <b>sera gazıdır</b>."}],"ans":"Metan, anaerobik ayrışmadan çıkan ve CO₂'den güçlü bir sera gazıdır."},{"q":"Ormansızlaşma karbon döngüsünü iki yönlü olarak nasıl etkiler?","steps":[{"t":"Tutulum azalır","a":"fotosentez düşer","d":"Ağaç azalınca fotosentezle tutulan CO₂ miktarı düşer."},{"t":"Salınım artar","a":"yakma/çürüme","d":"Kesilen ağaçların yakılması veya çürümesi depolanan karbonu CO₂ olarak salar."}],"ans":"Ormansızlaşma hem CO₂ tutulumunu azaltır hem salınımı artırır."},{"q":"Toprak karbon döngüsünde nasıl bir rol oynar?","steps":[{"t":"Depolama","a":"organik madde","d":"Toprak, ölü kök ve humustaki organik karbonu depolar."},{"t":"Salınım","a":"toprak solunumu","d":"Mikroorganizma solunumuyla bu karbon yavaşça CO₂ olarak atmosfere döner."}],"ans":"Toprak hem organik karbon deposu hem de CO₂ salan bir kaynaktır."},{"q":"Karbon döngüsünde 'hızlı' ve 'yavaş' döngü nasıl ayrılır?","steps":[{"t":"Hızlı döngü","a":"canlılar","d":"Fotosentez–solunum–ayrışma ile karbon gün/yıl ölçeğinde dolaşır."},{"t":"Yavaş döngü","a":"kayaç/fosil","d":"Kayaç oluşumu ve fosilleşme ile karbon milyonlarca yılda <b>yavaş</b> dolaşır."}],"ans":"Hızlı döngü canlılar arası kısa sürelidir; yavaş döngü kayaç/fosil temellidir."}],"zor":[{"q":"Bir karasal ekosistemde brüt birincil üretim 800 g C/m²·yıl, bitki solunumu 300 g C/m²·yıl ise net birincil üretim kaçtır ve bu ne anlama gelir?","steps":[{"t":"Formül","a":"NPP = GPP − Rₐ","d":"Net üretim, brüt üretimden bitkinin kendi solunum kaybı çıkarılarak bulunur."},{"t":"Hesap","a":"800 − 300 = 500","d":"500 g C/m²·yıl karbon, bitki biyokütlesine net olarak eklenir."},{"t":"Yorum","a":"net tutulan karbon","d":"Bu değer, tüketicilere aktarılabilecek ve depolanan <b>net karbonu</b> gösterir."}],"ans":"NPP = 500 g C/m²·yıl; ekosistemin net depoladığı organik karbondur."},{"q":"Okyanusların artan CO₂'yi soğurması neden 'okyanus asitlenmesine' yol açar ve bu deniz canlılarını nasıl etkiler?","steps":[{"t":"Çözünme","a":"H₂CO₃","d":"Atmosferik CO₂ deniz suyunda çözünüp karbonik asit oluşturur."},{"t":"İyonlaşma","a":"H⁺ artar","d":"Karbonik asit ayrışınca H⁺ derişimi artar, pH düşer (asitlenme)."},{"t":"Biyolojik etki","a":"kabuk zayıflar","d":"Düşen pH, karbonat iyonunu azaltır; mercan ve kabuklu canlıların <b>CaCO₃</b> kabuk yapımı zorlaşır."}],"ans":"Çözünen CO₂ asit oluşturup pH'ı düşürür; bu kabuk/iskelet yapımını zorlaştırır."},{"q":"Fotosentez ve solunum atmosferik CO₂'yi binlerce yıl dengede tutarken, fosil yakıt yakımı bu dengeyi neden bozar?","steps":[{"t":"Doğal denge","a":"tutulum ≈ salınım","d":"Fotosentezle tutulan ve solunum/ayrışma ile salınan karbon yaklaşık eşittir."},{"t":"Fosil katkı","a":"ek karbon","d":"Fosil yakıt, yavaş döngüde kilitli karbonu hızlı döngüye <b>ek girdi</b> olarak sokar."},{"t":"Sonuç","a":"birikim","d":"Bu ekstra CO₂ doğal süreçlerle aynı hızda tutulamaz, atmosferde birikir."}],"ans":"Fosil yakıt, dengeli döngüye fazladan karbon ekler ve CO₂ birikir."},{"q":"Sera gazı derişimindeki artış nasıl olup da 'pozitif geri besleme' ile küresel ısınmayı hızlandırabilir?","steps":[{"t":"Başlangıç","a":"sıcaklık artar","d":"Artan CO₂ ısıyı tutarak yüzey sıcaklığını yükseltir."},{"t":"Geri besleme","a":"daha çok salınım","d":"Isınma; permafrost erimesi ve okyanus CO₂ salımıyla daha çok sera gazı açığa çıkarır."},{"t":"Döngü","a":"hızlanır","d":"Artan gaz daha çok ısınmaya, o da daha çok salınıma yol açar; bu <b>pozitif geri beslemedir</b>."}],"ans":"Isınma ek sera gazı salımını tetikler; bu pozitif geri besleme ısınmayı hızlandırır."},{"q":"Bir besin zincirinde üreticide depolanan karbonun çoğu neden üst tüketicilere ulaşmaz?","steps":[{"t":"Solunum kaybı","a":"CO₂ olarak gider","d":"Her basamak aldığı organik karbonun büyük kısmını solunumla CO₂ olarak harcar."},{"t":"Aktarım verimi","a":"yaklaşık %10","d":"Bir basamaktan diğerine ortalama %10 enerji/karbon aktarılır."},{"t":"Sonuç","a":"azalarak iletilir","d":"Basamak yükseldikçe depolanan karbon hızla azaldığı için üst tüketiciye çok azı ulaşır."}],"ans":"Her basamakta karbonun çoğu solunumla CO₂'ye gittiği için üst tüketiciye azı ulaşır."},{"q":"Bir orman 1 yılda 12 ton CO₂ tutuyor; karbonun CO₂ içindeki kütle oranı 12/44 ise yılda kaç ton saf karbon depolanmıştır?","steps":[{"t":"Kütle oranı","a":"12/44","d":"CO₂'nin molekül kütlesi 44, içindeki karbonun kütlesi 12'dir."},{"t":"Hesap","a":"12 × (12/44)","d":"12 × 12 ÷ 44 ≈ 3,27 ton karbon bulunur."},{"t":"Yorum","a":"net karbon","d":"Bu, biyokütleye gerçekten bağlanan saf <b>karbon</b> kütlesidir."}],"ans":"Yaklaşık 3,27 ton saf karbon depolanmıştır."},{"q":"Karbon döngüsünde okyanusun 'çözünürlük pompası' ile 'biyolojik pompa'sı nasıl farklı çalışır?","steps":[{"t":"Çözünürlük pompası","a":"fiziksel","d":"Soğuk yüzey suları CO₂'yi daha çok çözüp derinlere taşıyarak depolar."},{"t":"Biyolojik pompa","a":"canlı temelli","d":"Fitoplankton CO₂'yi organik maddeye çevirir; ölünce karbon derine çöker."},{"t":"Fark","a":"mekanizma","d":"Biri fiziksel çözünme, diğeri fotosentez–çökelme yoluyla karbonu derine <b>hapseder</b>."}],"ans":"Çözünürlük pompası fizikseldir; biyolojik pompa fotosentez–çökelme ile karbonu derine taşır."},{"q":"Permafrostun (donmuş toprak) erimesi karbon döngüsü için neden ciddi bir risk oluşturur?","steps":[{"t":"Depolanan karbon","a":"donmuş organik madde","d":"Permafrostta büyük miktarda çürümemiş organik karbon donmuş halde kilitlidir."},{"t":"Erime","a":"mikrobiyal ayrışma","d":"Isınmayla erien toprakta mikroplar bu karbonu ayrıştırır."},{"t":"Salınım","a":"CO₂ ve CH₄","d":"Ayrışma CO₂ ve güçlü sera gazı <b>metan</b> salar, ısınmayı artırır."}],"ans":"Eriyen permafrost depolanmış karbonu CO₂ ve metan olarak salıp ısınmayı hızlandırır."},{"q":"Fotosentezle tutulan karbonun bir kısmı milyonlarca yıl sonra nasıl fosil yakıta dönüşür?","steps":[{"t":"Karbon tutulumu","a":"organik madde","d":"Bitki ve planktonlar fotosentezle CO₂'yi organik karbona çevirir."},{"t":"Gömülme","a":"oksijensiz ortam","d":"Ölü canlılar ayrışmadan tortul tabakalar altında oksijensiz ortamda gömülür."},{"t":"Dönüşüm","a":"basınç ve ısı","d":"Uzun sürede yüksek basınç ve sıcaklık altında <b>kömür/petrol/gaz</b> oluşur."}],"ans":"Gömülen organik karbon, oksijensiz ortamda basınç ve ısıyla fosil yakıta dönüşür."},{"q":"Atmosferik CO₂ derişimi yıl içinde neden mevsimsel olarak dalgalanır?","steps":[{"t":"İlkbahar–yaz","a":"fotosentez baskın","d":"Bitki örtüsünün yoğun olduğu mevsimde fotosentez çok CO₂ çeker, derişim düşer."},{"t":"Sonbahar–kış","a":"solunum/ayrışma baskın","d":"Yapraklar dökülünce ayrışma ve solunum öne çıkar, CO₂ artar."},{"t":"Sonuç","a":"mevsimsel salınım","d":"Bu dengenin mevsime göre kayması düzenli bir <b>dalgalanma</b> oluşturur."}],"ans":"Fotosentez ve solunum dengesinin mevsimsel kayması CO₂'de dalgalanmaya yol açar."},{"q":"Bir bölgede solunumla salınan karbon, fotosentezle tutulandan fazlaysa bu ekosistem karbon açısından nasıl tanımlanır?","steps":[{"t":"Karşılaştırma","a":"salınım > tutulum","d":"Salınan CO₂ tutulandan fazlaysa net olarak atmosfere karbon eklenir."},{"t":"Tanım","a":"karbon kaynağı","d":"Böyle bir sistem atmosfere karbon veren bir <b>karbon kaynağıdır</b> (source)."},{"t":"Karşıtı","a":"karbon yutağı","d":"Tutulum salınımdan fazla olsaydı sistem karbon yutağı (sink) olurdu."}],"ans":"Salınım tutulumdan fazlaysa ekosistem net bir karbon kaynağıdır (source)."},{"q":"Karbon döngüsünde kalsiyum karbonatlı deniz canlılarının ölümü uzun vadeli depoyu nasıl besler?","steps":[{"t":"Kabuk yapımı","a":"CaCO₃","d":"Mercan ve kabuklular karbonu kalsiyum karbonat kabuk olarak biriktirir."},{"t":"Çökelme","a":"deniz dibine","d":"Öldüklerinde kabuklar deniz dibinde tortu olarak birikir."},{"t":"Kayaçlaşma","a":"kireçtaşı","d":"Zamanla sıkışıp <b>kireçtaşına</b> dönüşerek karbonu uzun vadeli depoya kilitler."}],"ans":"Ölen kabuklu canlıların CaCO₃'ü çökelip kireçtaşına dönüşerek uzun vadeli karbonu depolar."},{"q":"Ağaçlandırma (afforestation) küresel ısınmayla mücadelede neden etkili sayılır, sınırı nedir?","steps":[{"t":"CO₂ tutulumu","a":"fotosentez","d":"Yeni dikilen ağaçlar büyürken fotosentezle atmosferden CO₂ çeker."},{"t":"Depolama","a":"biyokütle/toprak","d":"Tutulan karbon odun ve toprakta uzun süre depolanır, atmosferdeki yük azalır."},{"t":"Sınır","a":"geri salınım riski","d":"Ağaç yanar/çürür ya da kesilirse depolanan karbon yine CO₂ olarak <b>geri salınabilir</b>."}],"ans":"Ağaçlandırma CO₂'yi tutup depolar; ancak yanma/çürümeyle karbon geri salınabilir."},{"q":"İnsan kaynaklı emisyonların yaklaşık yarısı atmosferde kalırken diğer yarısı nereye gider?","steps":[{"t":"Atmosferde kalan","a":"yaklaşık yarısı","d":"Salınan CO₂'nin kabaca yarısı atmosferde birikip derişimi artırır."},{"t":"Okyanus yutağı","a":"çözünme","d":"Önemli bir kısmı okyanuslarca çözünerek soğurulur."},{"t":"Kara yutağı","a":"bitki/toprak","d":"Kalanı kara ekosistemlerinde <b>fotosentezle</b> tutulur."}],"ans":"Emisyonun yarısı atmosferde kalır; gerisini okyanus ve kara ekosistemleri yutar."},{"q":"Sera gazları olmasaydı Dünya yaşam için neden uygun olmazdı, peki fazlası neden sorun?","steps":[{"t":"Doğal sera etkisi","a":"ısıyı tutar","d":"Sera gazları yüzey ısısının bir kısmını tutarak Dünya'yı yaşanabilir sıcaklıkta tutar."},{"t":"Olmasaydı","a":"çok soğuk","d":"Sera etkisi hiç olmasa yüzey ortalaması donma altına düşer, yaşam zorlaşır."},{"t":"Fazlası","a":"aşırı ısınma","d":"İnsan kaynaklı CO₂ artışı bu etkiyi güçlendirip <b>küresel ısınmaya</b> yol açar."}],"ans":"Doğal sera etkisi Dünya'yı ısıtır; ancak fazla CO₂ onu güçlendirip küresel ısınma yaratır."}]}},"populasyon":{"ilkokul":{"kolay":[{"q":"Bir göldeki ördeklerin hepsine birlikte ne ad verilir?","steps":[{"t":"Aynı canlılar bir arada","a":"Bir grup","d":"Aynı türden, yani <b>aynı çeşit</b> canlıların bir arada yaşamasına bir topluluk diyebiliriz."},{"t":"Bu gruba ne denir?","a":"Popülasyon","d":"Aynı yerde yaşayan aynı tür canlıların oluşturduğu gruba <b>popülasyon</b> denir."}],"ans":"Bir göldeki ördeklerin tümüne ördek popülasyonu denir."},{"q":"Bir bahçede 5 tavşan varken, yavrular doğunca 9 tavşan oluyor. Tavşan sayısı arttı mı, azaldı mı?","steps":[{"t":"Önce kaç vardı?","a":"5 tavşan","d":"Başlangıçta bahçede <b>5 tavşan</b> bulunuyordu."},{"t":"Sonra kaç oldu?","a":"9 tavşan","d":"Yavrular doğunca sayı 9'a çıktı; 9 sayısı 5'ten büyük olduğu için sayı arttı."}],"ans":"Tavşan sayısı 5'ten 9'a çıktığı için arttı."},{"q":"Bir kümeste 10 tavuk varken kümesten 4 tavuk başka çiftliğe gidiyor. Kümeste kaç tavuk kalır?","steps":[{"t":"Önce kaç vardı?","a":"10 tavuk","d":"Kümeste başta <b>10 tavuk</b> vardı."},{"t":"Gidince ne olur?","a":"10 − 4 = 6","d":"4 tavuk gidince 10'dan 4 çıkarılır, geriye 6 tavuk kalır; gidenler olduğu için sayı azalır."}],"ans":"Kümeste 6 tavuk kalır; tavuk sayısı azalmıştır."},{"q":"Bir akvaryumdaki balıkların yumurtaları açılıp yeni balıklar oluyor. Balık sayısına ne olur?","steps":[{"t":"Yeni balıklar nereden gelir?","a":"Yumurtalardan","d":"Yumurtalar açılınca <b>yeni balıklar</b> dünyaya gelir."},{"t":"Sayıya etkisi","a":"Artar","d":"Yeni balıklar eklendiği için akvaryumdaki toplam balık sayısı artar."}],"ans":"Yeni balıklar dünyaya geldiği için balık sayısı artar."},{"q":"Bir ormanda hava çok soğursa ve yiyecek azalırsa geyik sayısına ne olabilir?","steps":[{"t":"Yiyecek azalınca","a":"Beslenmek zorlaşır","d":"Yiyecek az olunca geyikler yeterince <b>beslenemez</b>."},{"t":"Sayıya etkisi","a":"Azalır","d":"Yeterince beslenemeyen bazı geyikler yaşayamadığı için geyik sayısı azalabilir."}],"ans":"Yiyecek azalıp hava soğuyunca geyik sayısı azalabilir."}],"zor":[{"q":"Bir tarlada başta 8 fare varken, yıl boyunca 6 fare doğuyor ve 2 fare ölüyor. Yıl sonunda kaç fare olur?","steps":[{"t":"Doğanları ekle","a":"8 + 6 = 14","d":"Başlangıçtaki 8 fareye doğan <b>6 fareyi</b> eklersek 14 olur."},{"t":"Ölenleri çıkar","a":"14 − 2 = 12","d":"Sonra ölen 2 fareyi çıkarırsak 14'ten 2 gider, geriye 12 fare kalır."}],"ans":"Yıl sonunda tarlada 12 fare olur."},{"q":"Bir bahçede 7 kelebek var. 3 kelebek başka bahçeden geliyor, 1 kelebek de uçup gidiyor. Bahçede kaç kelebek olur?","steps":[{"t":"Gelenleri ekle","a":"7 + 3 = 10","d":"Başta 7 kelebek vardı, dışarıdan <b>3 kelebek</b> gelince 10 olur."},{"t":"Gideni çıkar","a":"10 − 1 = 9","d":"Sonra 1 kelebek uçup gidince 10'dan 1 çıkar, 9 kelebek kalır."}],"ans":"Bahçede 9 kelebek olur."},{"q":"İki çayırdan birinde bol ot, diğerinde çok az ot var. Aynı sayıda koyun bırakılırsa hangi çayırda koyunlar daha rahat yaşar?","steps":[{"t":"Yiyecek miktarı","a":"Bol otlu çayır","d":"Bol otlu çayırda koyunlara yetecek <b>çok yiyecek</b> vardır."},{"t":"Hangisi daha iyi?","a":"Bol otlu","d":"Yiyecek bol olduğu için bol otlu çayırdaki koyunlar daha iyi beslenip rahat yaşar."}],"ans":"Bol otlu çayırda koyunlar daha rahat yaşar, çünkü yiyecek boldur."},{"q":"Bir gölette balık sayısı her yıl artıyor. Bir yıl gölete kuraklık gelip su azalırsa balık sayısına ne olur?","steps":[{"t":"Su balıklar için","a":"Yaşam alanı","d":"Balıklar yaşamak için <b>suya</b> ihtiyaç duyar."},{"t":"Su azalınca","a":"Sayı azalır","d":"Su azalınca balıklara daha az yer ve yaşam kalır; bu yüzden balık sayısı azalır."}],"ans":"Su azalınca balıklara yer kalmadığı için balık sayısı azalır."},{"q":"Bir ormanda kurtlar geyikleri avlıyor. Kurt sayısı çok artarsa geyik sayısına ne olur?","steps":[{"t":"Kurtlar ne yapar?","a":"Geyik avlar","d":"Kurtlar beslenmek için <b>geyik avlar</b>."},{"t":"Kurt çoğalınca","a":"Geyik azalır","d":"Çok sayıda kurt daha çok geyik avladığı için geyik sayısı azalır."}],"ans":"Kurtlar çoğalınca daha çok geyik avlandığı için geyik sayısı azalır."}]},"ortaokul":{"kolay":[{"q":"Popülasyon ne demektir?","steps":[{"t":"Hangi canlılar?","a":"Aynı tür","d":"Popülasyonu oluşturan canlılar <b>aynı türdendir</b>, yani birbirleriyle üreyebilirler."},{"t":"Nerede yaşarlar?","a":"Aynı bölgede","d":"Bu aynı tür canlılar belirli bir bölgede, aynı zamanda bir arada yaşar."}],"ans":"Popülasyon, belirli bir bölgede yaşayan aynı türden canlıların oluşturduğu topluluktur."},{"q":"Popülasyon yoğunluğu nasıl bulunur?","steps":[{"t":"Neler gerekli?","a":"Birey sayısı ve alan","d":"Yoğunluğu bulmak için bireylerin <b>sayısı</b> ve yaşadıkları <b>alan</b> bilinmelidir."},{"t":"Nasıl hesaplanır?","a":"Sayı ÷ alan","d":"Yoğunluk, birey sayısının yaşam alanına bölünmesiyle (sayı ÷ alan) bulunur."}],"ans":"Popülasyon yoğunluğu, birey sayısının yaşam alanına bölünmesiyle bulunur."},{"q":"Bir popülasyonun büyüklüğünü artıran iki olay nedir?","steps":[{"t":"Yeni bireyler nereden gelir?","a":"Doğum","d":"Doğan yavrularla popülasyona <b>yeni bireyler</b> eklenir."},{"t":"Dışarıdan katılım","a":"İçe göç","d":"Başka bölgeden gelen bireyler (içe göç) de popülasyonu büyütür."}],"ans":"Doğum ve içe göç, popülasyon büyüklüğünü artıran olaylardır."},{"q":"Bir popülasyonun büyüklüğünü azaltan iki olay nedir?","steps":[{"t":"Bireyler nasıl eksilir?","a":"Ölüm","d":"Ölen bireyler popülasyondan <b>çıkar</b> ve sayıyı azaltır."},{"t":"Başka bölgeye gitme","a":"Dışa göç","d":"Bölgeden ayrılan bireyler (dışa göç) de popülasyon büyüklüğünü azaltır."}],"ans":"Ölüm ve dışa göç, popülasyon büyüklüğünü azaltan olaylardır."},{"q":"Bir bölgede doğum sayısı ölüm sayısından fazlaysa popülasyon büyüklüğü nasıl değişir?","steps":[{"t":"Doğum ve ölümü karşılaştır","a":"Doğum fazla","d":"Doğan birey sayısı, ölen birey sayısından <b>daha fazladır</b>."},{"t":"Sonuç","a":"Artar","d":"Eklenen birey, çıkandan çok olduğu için popülasyon büyüklüğü artar."}],"ans":"Doğum ölümden fazlaysa popülasyon büyüklüğü artar."}],"zor":[{"q":"Bir kasaba popülasyonunda bir yılda 40 doğum, 15 ölüm, 10 içe göç ve 5 dışa göç gerçekleşiyor. Net değişim nedir?","steps":[{"t":"Artıranları topla","a":"40 + 10 = 50","d":"Popülasyonu artıran doğum (40) ve içe göçü (10) toplarsak 50 birey eklenir."},{"t":"Azaltanları topla","a":"15 + 5 = 20","d":"Azaltan ölüm (15) ve dışa göçü (5) toplarsak 20 birey çıkar."},{"t":"Net değişimi bul","a":"50 − 20 = +30","d":"Eklenenden (50) çıkanı (20) çıkarınca net +30 olur; popülasyon 30 birey artar."}],"ans":"Net değişim +30'dur; popülasyon 30 birey artmıştır."},{"q":"Bir çayırda 600 birey 200 m² alana yayılmıştır. Popülasyon yoğunluğu nedir?","steps":[{"t":"Formülü yaz","a":"Yoğunluk = sayı ÷ alan","d":"Yoğunluk, birey sayısının yaşam <b>alanına</b> bölünmesiyle bulunur."},{"t":"Değerleri yerleştir","a":"600 ÷ 200","d":"600 bireyi 200 m²'ye bölersek hesap yapılır."},{"t":"Sonucu bul","a":"3 birey/m²","d":"600 ÷ 200 = 3; yani her metrekareye 3 birey düşer."}],"ans":"Popülasyon yoğunluğu 3 birey/m²'dir."},{"q":"Aynı sayıda bireye sahip iki popülasyondan biri küçük, diğeri büyük bir alanda yaşıyor. Hangisinin yoğunluğu daha fazladır?","steps":[{"t":"Yoğunluk neye bağlı?","a":"Sayı ve alan","d":"Birey sayısı aynıyken yoğunluğu belirleyen tek şey yaşam <b>alanıdır</b>."},{"t":"Alan küçükse","a":"Yoğunluk büyük","d":"Alan ne kadar küçükse sayı aynı kalsa da birim alana düşen birey artar; küçük alandaki yoğunluk daha fazladır."}],"ans":"Küçük alanda yaşayan popülasyonun yoğunluğu daha fazladır."},{"q":"Bir adaya ilk kez gelen az sayıda tavşan, bol yiyecek ve avcı olmadığı için hızla çoğalıyor. Bu büyüme neden bir süre çok hızlıdır?","steps":[{"t":"Koşullar nasıl?","a":"Sınırsıza yakın","d":"Bol yiyecek ve avcının olmaması, kaynakların <b>sınırsıza yakın</b> olması demektir."},{"t":"Üreme nasıl artar?","a":"Katlanarak","d":"Her birey ürediği için birey sayısı arttıkça doğum da artar, büyüme katlanarak hızlanır."}],"ans":"Kaynaklar bol ve engel az olduğu için bireyler katlanarak çoğalır, büyüme çok hızlı olur."},{"q":"Bir ormanda geyik sayısı çok arttığında otlar tükenmeye başlıyor. Bu durum geyik popülasyonunu nasıl etkiler?","steps":[{"t":"Otların önemi","a":"Yiyecek kaynağı","d":"Otlar geyikler için temel <b>yiyecek kaynağıdır</b>."},{"t":"Ot tükenince","a":"Beslenme zorlaşır","d":"Geyik çok olunca otlar yetmez, beslenme zorlaşır."},{"t":"Sonuç","a":"Sayı dengelenir veya azalır","d":"Yiyecek yetersizliği ölümleri ve göçü artırır; geyik sayısı durur ya da azalır."}],"ans":"Yiyecek tükenince beslenme zorlaşır, ölüm ve göç artar; geyik sayısı dengelenir ya da azalır."}]},"lise":{"kolay":[{"q":"Popülasyon ekolojik açıdan nasıl tanımlanır?","steps":[{"t":"Bireylerin türü","a":"Aynı tür","d":"Popülasyon, <b>aynı türe</b> ait, aralarında gen alışverişi yapabilen bireylerden oluşur."},{"t":"Yer ve zaman","a":"Belirli alan, aynı zaman","d":"Bu bireyler belirli bir coğrafi alanda ve aynı zaman diliminde bir arada yaşar."}],"ans":"Popülasyon, belirli bir alanda ve zamanda yaşayan, aralarında üreme yapabilen aynı türden bireylerin oluşturduğu topluluktur."},{"q":"Popülasyon yoğunluğu nedir ve nasıl ifade edilir?","steps":[{"t":"Tanım","a":"Birim alandaki birey","d":"Popülasyon yoğunluğu, <b>birim alan</b> veya hacme düşen birey sayısıdır."},{"t":"İfade biçimi","a":"Sayı ÷ alan/hacim","d":"Toplam birey sayısının yaşam alanı ya da hacmine bölünmesiyle (birey/m² veya birey/m³) ifade edilir."}],"ans":"Popülasyon yoğunluğu, birim alan veya hacme düşen birey sayısıdır; sayının alan/hacme bölünmesiyle ifade edilir."},{"q":"Bir popülasyonun büyüklüğünü belirleyen dört temel faktör nedir?","steps":[{"t":"Artıran faktörler","a":"Doğum ve içe göç","d":"Doğumlar ve dışarıdan katılan bireyler (<b>içe göç</b>) popülasyonu büyütür."},{"t":"Azaltan faktörler","a":"Ölüm ve dışa göç","d":"Ölümler ve bölgeden ayrılan bireyler (<b>dışa göç</b>) popülasyonu küçültür."}],"ans":"Doğum, ölüm, içe göç ve dışa göç popülasyon büyüklüğünü belirleyen dört temel faktördür."},{"q":"Doğum oranı (natalite) ve ölüm oranı (mortalite) kavramları neyi ifade eder?","steps":[{"t":"Doğum oranı","a":"Birim zamanda doğum","d":"Natalite, belirli bir sürede popülasyona katılan birey (<b>doğum</b>) oranıdır."},{"t":"Ölüm oranı","a":"Birim zamanda ölüm","d":"Mortalite, aynı sürede popülasyondan ayrılan birey (<b>ölüm</b>) oranıdır."}],"ans":"Natalite birim zamandaki doğum oranı, mortalite ise birim zamandaki ölüm oranıdır."},{"q":"J tipi (üstel) büyüme eğrisi neyi gösterir?","steps":[{"t":"Hangi koşulda görülür?","a":"Sınırsız kaynak","d":"J eğrisi, kaynakların <b>sınırsıza yakın</b> ve engelin az olduğu ortamlarda görülür."},{"t":"Eğrinin biçimi","a":"Sürekli ve hızlanan artış","d":"Birey sayısı zamanla katlanarak (üstel) arttığı için eğri J harfi gibi sürekli dikleşir."}],"ans":"J tipi büyüme, sınırsız kaynak ortamında birey sayısının katlanarak (üstel) arttığı büyümeyi gösterir."},{"q":"S tipi (lojistik) büyüme eğrisi neyi gösterir?","steps":[{"t":"Başlangıç","a":"Hızlı artış","d":"Başta kaynak bol olduğu için popülasyon önce hızlıca <b>büyür</b>."},{"t":"Sonraki evre","a":"Yavaşlama ve plato","d":"Kaynaklar sınırlandıkça büyüme yavaşlar ve taşıma kapasitesinde sabitlenerek eğri S biçimini alır."}],"ans":"S tipi büyüme, önce hızlı artıp sonra taşıma kapasitesinde dengelenen, S biçimli gerçekçi büyümeyi gösterir."},{"q":"Taşıma kapasitesi (K) ne anlama gelir?","steps":[{"t":"Tanım","a":"En fazla birey sayısı","d":"Taşıma kapasitesi, bir ortamın kaynaklarının sürekli olarak <b>destekleyebileceği</b> en yüksek birey sayısıdır."},{"t":"Eğrideki yeri","a":"S eğrisinin platosu","d":"Lojistik büyümede popülasyon bu K değerine ulaşınca büyüme durur ve eğri yatay (plato) seyreder."}],"ans":"Taşıma kapasitesi (K), bir ortamın sürekli olarak destekleyebileceği en yüksek birey sayısıdır."},{"q":"Yaş piramidi nedir ve neyi gösterir?","steps":[{"t":"Tanım","a":"Yaş gruplarının dağılımı","d":"Yaş piramidi, bir popülasyondaki bireylerin <b>yaş gruplarına</b> göre dağılımını gösteren grafiktir."},{"t":"Ne işe yarar?","a":"Geleceği tahmin","d":"Genç-yetişkin-yaşlı oranlarına bakılarak popülasyonun gelecekte büyüyüp büyümeyeceği tahmin edilir."}],"ans":"Yaş piramidi, popülasyondaki bireylerin yaş gruplarına dağılımını gösterir ve gelecekteki büyümeyi tahmin etmeye yarar."},{"q":"Tabanı geniş bir yaş piramidi popülasyonun geleceği hakkında ne söyler?","steps":[{"t":"Geniş taban neyi gösterir?","a":"Çok genç birey","d":"Geniş taban, popülasyonda üreme çağına gelecek <b>genç bireyin</b> çok olduğunu gösterir."},{"t":"Gelecekteki etki","a":"Büyüme","d":"Bu gençler ileride üreyeceği için popülasyonun gelecekte büyümesi beklenir."}],"ans":"Tabanı geniş yaş piramidi, çok sayıda genç birey olduğunu ve popülasyonun gelecekte büyüyeceğini gösterir."},{"q":"Sınırlayıcı faktör popülasyon için ne anlama gelir?","steps":[{"t":"Tanım","a":"Büyümeyi sınırlayan etken","d":"Sınırlayıcı faktör, popülasyonun büyümesini <b>sınırlayan</b> ortam koşulu veya kaynaktır."},{"t":"Örnek","a":"Besin, su, yer","d":"Besin, su, yaşam alanı, ışık ya da avcılar gibi etkenler büyümeyi sınırlayabilir."}],"ans":"Sınırlayıcı faktör, besin veya alan gibi popülasyon büyümesini kısıtlayan ortam koşulu ya da kaynaktır."},{"q":"Yoğunluğa bağlı (dansiteye bağımlı) sınırlayıcı faktörlere iki örnek veriniz.","steps":[{"t":"Bu faktörlerin ortak özelliği","a":"Etkisi yoğunlukla artar","d":"Yoğunluğa bağlı faktörlerin etkisi, popülasyon <b>yoğunluğu arttıkça</b> güçlenir."},{"t":"Örnekler","a":"Besin rekabeti, hastalık","d":"Besin için rekabet, hastalıkların yayılması ve avcılık bunlara örnektir."}],"ans":"Besin için rekabet ve bulaşıcı hastalıklar, yoğunluğa bağlı sınırlayıcı faktörlere örnektir."},{"q":"Yoğunluğa bağlı olmayan (dansiteden bağımsız) sınırlayıcı faktörlere iki örnek veriniz.","steps":[{"t":"Ortak özellik","a":"Yoğunluktan etkilenmez","d":"Bu faktörlerin etkisi popülasyon yoğunluğundan <b>bağımsızdır</b>, az ya da çok bireye benzer etki yapar."},{"t":"Örnekler","a":"Sel, don, yangın","d":"Sel, kuraklık, don, orman yangını gibi iklim ve doğal afet olayları bunlara örnektir."}],"ans":"Sel, kuraklık, don ve yangın gibi iklim olayları yoğunluğa bağlı olmayan sınırlayıcı faktörlere örnektir."},{"q":"Bir popülasyonun büyüme hızı en yüksek olduğunda lojistik eğride nerede bulunur?","steps":[{"t":"K'ye yakınken","a":"Hız düşük","d":"Popülasyon taşıma kapasitesine (K) yakınken kaynak az kaldığından büyüme hızı <b>düşüktür</b>."},{"t":"Orta bölgede","a":"Hız en yüksek","d":"Eğrinin orta bölgesinde (yaklaşık K/2) hem birey hem kaynak yeterli olduğundan büyüme hızı en yüksektir."}],"ans":"Lojistik büyümede en yüksek hız, eğrinin orta bölgesinde (yaklaşık K/2) görülür."},{"q":"Göç (migrasyon) bir popülasyonun büyüklüğünü nasıl etkiler?","steps":[{"t":"İçe göç","a":"Sayıyı artırır","d":"Dışarıdan gelen bireyler (<b>içe göç</b>) popülasyona katıldığı için büyüklüğü artırır."},{"t":"Dışa göç","a":"Sayıyı azaltır","d":"Bölgeden ayrılan bireyler (dışa göç) popülasyondan çıktığı için büyüklüğü azaltır."}],"ans":"İçe göç popülasyon büyüklüğünü artırır, dışa göç ise azaltır."},{"q":"Popülasyon büyüklüğünü tahmin etmede kullanılan işaretle-yakala-tekrar yakala yönteminin temel mantığı nedir?","steps":[{"t":"İlk aşama","a":"Yakala ve işaretle","d":"Bir grup birey yakalanıp <b>işaretlenir</b> ve doğaya geri bırakılır."},{"t":"İkinci aşama","a":"Tekrar yakala","d":"Bir süre sonra ikinci bir örnek yakalanır; içindeki işaretli birey oranına bakılır."},{"t":"Tahmin","a":"Oranla hesapla","d":"İkinci örnekteki işaretli oranı, tüm popülasyondaki işaretli oranına eşit kabul edilerek toplam birey sayısı tahmin edilir."}],"ans":"Yöntemde işaretli bireylerin ikinci örnekteki oranı tüm popülasyona genellenerek toplam birey sayısı tahmin edilir."}],"zor":[{"q":"J tipi (üstel) ile S tipi (lojistik) büyümeyi taşıma kapasitesi ve kaynaklar açısından karşılaştırınız.","steps":[{"t":"J tipi büyüme","a":"Sınırsız kaynak","d":"J tipinde kaynaklar sınırsıza yakındır; popülasyon <b>taşıma kapasitesi</b> kısıtı olmadan katlanarak büyür."},{"t":"S tipi büyüme","a":"Sınırlı kaynak","d":"S tipinde kaynaklar sınırlıdır; büyüme önce hızlı, sonra yavaşlar."},{"t":"Plato farkı","a":"K'de denge","d":"S eğrisi taşıma kapasitesinde (K) sabitlenirken J eğrisinde böyle bir plato yoktur, eğri sürekli dikleşir."}],"ans":"J tipi sınırsız kaynakta plato yapmadan katlanarak büyür; S tipi sınırlı kaynakta taşıma kapasitesinde (K) dengelenerek S biçimi alır."},{"q":"Bir popülasyonda yıllık doğum oranı %12, ölüm oranı %5, içe göç %3 ve dışa göç %4'tür. Net büyüme oranını bulunuz ve yorumlayınız.","steps":[{"t":"Artıranları topla","a":"%12 + %3 = %15","d":"Büyümeyi artıran doğum (%12) ve içe göçü (%3) toplarsak %15 elde edilir."},{"t":"Azaltanları topla","a":"%5 + %4 = %9","d":"Azaltan ölüm (%5) ve dışa göçü (%4) toplarsak %9 olur."},{"t":"Net oranı bul","a":"%15 − %9 = +%7","d":"Artıranlardan azaltanları çıkarınca net büyüme +%7 bulunur; oran pozitif olduğu için popülasyon büyümektedir."}],"ans":"Net büyüme oranı +%7'dir; oran pozitif olduğundan popülasyon büyümektedir."},{"q":"Lojistik (S) büyüme eğrisinde büyüme hızının başta düşük, ortada en yüksek, K'ye yakın yine düşük olmasını açıklayınız.","steps":[{"t":"Başlangıç bölgesi","a":"Az birey","d":"Başta birey sayısı az olduğundan toplam üreyen birey azdır; bu nedenle büyüme hızı <b>düşüktür</b>."},{"t":"Orta bölge","a":"K/2 civarı","d":"Orta bölgede hem üreyebilen birey çok hem de kaynak yeterli olduğundan büyüme hızı en yüksektir."},{"t":"K'ye yakın bölge","a":"Kaynak kıtlığı","d":"Taşıma kapasitesine yaklaşıldıkça kaynaklar azalır, rekabet artar; büyüme hızı tekrar düşer ve sıfıra yaklaşır."}],"ans":"Az bireyde üreme düşük, K/2 civarında birey ve kaynak ikisi de yeterli olduğundan hız en yüksek, K'ye yakın kaynak kıtlığı nedeniyle hız yine düşüktür."},{"q":"Yoğunluğa bağlı ve yoğunluğa bağlı olmayan sınırlayıcı faktörleri etki mekanizması açısından örneklerle karşılaştırınız.","steps":[{"t":"Yoğunluğa bağlı","a":"Etkisi yoğunlukla artar","d":"Besin rekabeti, hastalık ve avcılık gibi faktörlerin etkisi popülasyon <b>yoğunluğu arttıkça</b> güçlenir."},{"t":"Yoğunluğa bağlı olmayan","a":"Yoğunluktan bağımsız","d":"Sel, don, yangın gibi iklim olaylarının etkisi yoğunluktan bağımsızdır; az ya da çok bireye benzer biçimde zarar verir."},{"t":"Karşılaştırma","a":"İç-dış kaynaklı","d":"Yoğunluğa bağlı faktörler çoğunlukla popülasyon içi etkileşimlerden, bağımsız faktörler ise dış çevre olaylarından kaynaklanır."}],"ans":"Yoğunluğa bağlı faktörlerin (rekabet, hastalık) etkisi yoğunlukla artarken, yoğunluğa bağlı olmayan faktörler (sel, don, yangın) yoğunluktan bağımsız etki gösterir."},{"q":"Bir geyik popülasyonu taşıma kapasitesini aşacak kadar büyüyünce sonradan sayısının düşmesini, doğum ve ölüm oranlarıyla açıklayınız.","steps":[{"t":"K aşılınca","a":"Kaynak yetersiz","d":"Birey sayısı taşıma kapasitesini aşınca besin ve alan <b>yetersiz</b> kalır."},{"t":"Oranlardaki değişim","a":"Ölüm artar, doğum azalır","d":"Kaynak kıtlığı nedeniyle ölüm oranı yükselir, beslenme bozulduğundan doğum oranı düşer."},{"t":"Sonuç","a":"K'ye geri iner","d":"Ölüm doğumu aşınca popülasyon küçülür ve taşıma kapasitesi çevresinde dengelenir."}],"ans":"K aşılınca kaynak yetersizliği ölüm oranını artırıp doğum oranını düşürür; ölüm doğumu aştığı için popülasyon küçülerek K çevresinde dengelenir."},{"q":"Tabanı geniş, tabanı dar (çan) ve tabanı ile tepesi dengeli üç yaş piramidinin popülasyon büyümesine etkisini karşılaştırınız.","steps":[{"t":"Geniş tabanlı","a":"Hızlı büyüyen","d":"Genç birey çok olduğundan ileride <b>doğum</b> yüksek olur; popülasyon hızla büyür."},{"t":"Dengeli tabanlı","a":"Durağan","d":"Genç ve yetişkin oranları dengeliyse doğum ve ölüm benzer olur; popülasyon büyüklüğü yaklaşık sabit kalır."},{"t":"Dar (çan) tabanlı","a":"Küçülen","d":"Genç birey azsa gelecekte doğum düşük kalır, yaşlı oranı fazladır; popülasyon küçülmeye eğilimlidir."}],"ans":"Geniş tabanlı piramit hızlı büyüyen, dengeli taban durağan, dar tabanlı (çan) ise küçülen bir popülasyonu gösterir."},{"q":"Aynı sayıda bireye sahip iki popülasyondan biri kümeli (öbekli), diğeri rastgele dağılmıştır. Bu dağılım farkı popülasyon yoğunluğu ölçümünü nasıl etkiler?","steps":[{"t":"Ortalama yoğunluk","a":"Aynı","d":"Birey sayısı ve toplam alan aynı olduğundan tüm alana göre <b>ortalama yoğunluk</b> ikisinde de eşittir."},{"t":"Örnekleme etkisi","a":"Hata kaynağı","d":"Kümeli dağılımda küçük bir örnek alanı seçilirse, örneğin yerine göre yoğunluk olduğundan çok yüksek ya da düşük ölçülebilir."},{"t":"Sonuç","a":"Dağılım önemli","d":"Bu yüzden yoğunluk tahmininde rastgele dağılımda hata azken, kümeli dağılımda çok sayıda ve geniş örnek almak gerekir."}],"ans":"Ortalama yoğunluk aynı olsa da kümeli dağılımda küçük örnekler yanıltıcı sonuç verir; bu yüzden kümeli dağılımda daha çok ve geniş örnekleme gerekir."},{"q":"İşaretle-yakala-tekrar yakala yönteminde 80 birey işaretlenip bırakılıyor; ikinci yakalamada 100 bireyin 20'si işaretli çıkıyor. Toplam popülasyon büyüklüğünü tahmin ediniz.","steps":[{"t":"Yöntemin orantısı","a":"İşaretli / toplam","d":"İkinci örnekteki işaretli oranı, tüm popülasyondaki işaretli oranına eşit kabul edilir: 20/100 = 80/N."},{"t":"İşaretli oranını bul","a":"20/100 = 0,2","d":"İkinci örnekte işaretli oranı 20 ÷ 100 = 0,2'dir, yani örneklerin beşte biri işaretlidir."},{"t":"N'yi hesapla","a":"N = 80 ÷ 0,2 = 400","d":"İşaretlenen 80 birey tüm popülasyonun 0,2'sine karşılık geldiğinden N = 80 ÷ 0,2 = 400 bulunur."}],"ans":"Toplam popülasyon büyüklüğü yaklaşık 400 bireydir."},{"q":"Bir adaya yeni gelen bir tür neden başlangıçta J tipine yakın büyür, sonra S tipine döner? Süreci açıklayınız.","steps":[{"t":"İlk evre","a":"Bol kaynak","d":"Tür ilk geldiğinde birey azken besin ve alan boldur, avcı/rekabet zayıftır; bu yüzden katlanarak (<b>J tipine yakın</b>) büyür."},{"t":"Direnç artışı","a":"Çevre direnci","d":"Birey sayısı arttıkça besin azalır, rekabet, hastalık ve avcılık (çevre direnci) güçlenir."},{"t":"Sonuç","a":"K'de dengeleme","d":"Bu dirençlerle büyüme yavaşlar ve popülasyon taşıma kapasitesinde sabitlenir; eğri S tipine döner."}],"ans":"Başta bol kaynak ve zayıf direnç katlanan (J tipine yakın) büyüme sağlar; birey arttıkça çevre direnci güçlenir, büyüme yavaşlayıp K'de dengelenir ve eğri S tipine döner."},{"q":"Bir popülasyonda dişi-erkek (eşey) oranının üreme potansiyeli üzerindeki etkisini açıklayınız.","steps":[{"t":"Eşey oranı nedir?","a":"Dişi/erkek dağılımı","d":"Eşey oranı, popülasyondaki dişi ve erkek bireylerin <b>oranıdır</b>."},{"t":"Doğumu belirleyen","a":"Üreyebilen dişi sayısı","d":"Çoğu türde doğum sayısı büyük ölçüde üreyebilen dişi sayısına bağlıdır."},{"t":"Sonuç","a":"Dişi oranı kritik","d":"Dişi oranı yüksekse üreme potansiyeli ve doğum oranı artar; dişi azsa toplam birey çok olsa bile büyüme sınırlı kalır."}],"ans":"Doğum sayısı üreyen dişi sayısına bağlı olduğundan dişi oranı yüksek popülasyonda üreme potansiyeli ve büyüme hızı daha yüksektir."},{"q":"Bir av (tavşan) ve avcı (tilki) popülasyonunun sayılarının zaman içinde birbirini izleyerek dalgalanmasını açıklayınız.","steps":[{"t":"Av çoğalınca","a":"Avcı artar","d":"Tavşan (av) sayısı arttığında tilkilere (<b>avcı</b>) bol besin olur, avcı sayısı bir süre sonra artar."},{"t":"Avcı artınca","a":"Av azalır","d":"Avcı sayısı arttıkça daha çok tavşan avlanır, av popülasyonu azalır."},{"t":"Av azalınca","a":"Avcı azalır","d":"Av azaldığında avcıya besin kalmaz, avcı sayısı da düşer; av tekrar çoğalır ve döngü gecikmeli dalgalanma olarak sürer."}],"ans":"Av artınca avcı artar, avcı artınca av azalır, av azalınca avcı azalır; bu gecikmeli geri besleme av-avcı sayılarında birbirini izleyen dalgalanmalar oluşturur."},{"q":"Bir bölgenin taşıma kapasitesi (K) çevresel değişimle düşerse, kapasiteyi aşan mevcut popülasyona ne olur? Açıklayınız.","steps":[{"t":"K düşünce","a":"Birey K'yi aşar","d":"Kuraklık gibi bir değişimle kaynak azalıp K düşünce, mevcut birey sayısı yeni <b>taşıma kapasitesini</b> aşar."},{"t":"Kaynak rekabeti","a":"Ölüm/göç artar","d":"Kaynak yetmediği için rekabet, açlık ve hastalık artar; ölüm ve dışa göç yükselir."},{"t":"Sonuç","a":"Yeni K'ye iner","d":"Birey sayısı azalarak düşen taşıma kapasitesi seviyesinde yeniden dengelenir."}],"ans":"K düşünce mevcut popülasyon kapasiteyi aşar; kaynak rekabetiyle ölüm ve göç artar, birey sayısı azalarak yeni (daha düşük) K seviyesinde dengelenir."},{"q":"Çevre direnci kavramı nedir ve bir popülasyonun üstel (J) büyümeden lojistik (S) büyümeye geçmesindeki rolünü açıklayınız.","steps":[{"t":"Tanım","a":"Büyümeyi sınırlayan etkenler","d":"Çevre direnci, besin kıtlığı, rekabet, avcılık, hastalık ve olumsuz iklim gibi büyümeyi <b>sınırlayan</b> faktörlerin toplamıdır."},{"t":"Düşükken","a":"Üstel büyüme","d":"Birey azken çevre direnci düşüktür; popülasyon biyotik potansiyeline yakın, üstel (J) büyür."},{"t":"Arttıkça","a":"Büyüme yavaşlar","d":"Birey arttıkça çevre direnci güçlenir, büyüme yavaşlayıp taşıma kapasitesinde durur; bu nedenle eğri S tipine döner."}],"ans":"Çevre direnci, büyümeyi sınırlayan tüm faktörlerin toplamıdır; birey arttıkça güçlenerek üstel büyümeyi frenler ve popülasyonu K'de dengeleyip S tipi büyüme oluşturur."},{"q":"Bir popülasyonun biyotik (üreme) potansiyeli ile gerçek büyüme hızı arasındaki farkı, çevre direnciyle ilişkilendirerek açıklayınız.","steps":[{"t":"Biyotik potansiyel","a":"En yüksek üreme","d":"Biyotik potansiyel, ideal koşullarda bir popülasyonun ulaşabileceği <b>en yüksek</b> üreme hızıdır."},{"t":"Gerçek büyüme","a":"Daha düşük","d":"Doğada koşullar ideal olmadığından gerçek büyüme hızı bu potansiyelden daha düşüktür."},{"t":"Aradaki fark","a":"Çevre direnci","d":"Bu iki değer arasındaki farkı, kaynakları ve koşulları sınırlayan çevre direnci oluşturur."}],"ans":"Biyotik potansiyel ideal koşullardaki en yüksek üreme hızıdır; gerçek büyüme bunun altındadır ve aradaki farkı çevre direnci belirler."},{"q":"İki popülasyon aynı anda 100 bireyden başlıyor; birinin büyüme oranı %10, diğerininki %20. İki nesil sonra sayılarını hesaplayıp farkı yorumlayınız.","steps":[{"t":"%10'luk popülasyon","a":"100 → 110 → 121","d":"Her nesilde %10 artarsa 100 × 1,1 = 110, ardından 110 × 1,1 = 121 birey olur."},{"t":"%20'lik popülasyon","a":"100 → 120 → 144","d":"Her nesilde %20 artarsa 100 × 1,2 = 120, ardından 120 × 1,2 = 144 birey olur."},{"t":"Farkı yorumla","a":"144 − 121 = 23","d":"İki nesil sonra fark 23 bireydir; yüksek oranlı popülasyon, üstel büyüme nedeniyle giderek açılan bir farkla daha hızlı büyür."}],"ans":"İki nesil sonra %10'luk popülasyon 121, %20'lik popülasyon 144 bireye ulaşır; aralarındaki 23 bireylik fark, üstel büyümede yüksek oranın zamanla daha da açıldığını gösterir."}]}},"suDongusu":{"ilkokul":{"kolay":[{"q":"Güneş sıcakken denizdeki ve göldeki suya ne olur?","steps":[{"t":"Güneşin ısısı","a":"suyu ısıtır","d":"Güneş, deniz ve göllerdeki suyu ısıtır."},{"t":"Suyun değişimi","a":"buhar olur","d":"Isınan su, su buharına dönüşüp gökyüzüne doğru yükselir."}],"ans":"Güneş suyu ısıtınca su buharlaşır ve gökyüzüne yükselir."},{"q":"Gökyüzündeki bulutlar nasıl oluşur?","steps":[{"t":"Yükselen buhar","a":"su buharı","d":"Sudan yükselen su buharı yukarıda soğur."},{"t":"Bulut oluşması","a":"bulut olur","d":"Soğuyan su buharı küçük su damlacıklarına dönüşür ve bir araya gelip bulut olur."}],"ans":"Yukarı çıkan su buharı soğuyup damlacıklara dönüşür ve bulutları oluşturur."},{"q":"Buluttan yere ne yağar?","steps":[{"t":"Bulutta biriken","a":"su damlaları","d":"Bulutta küçük su damlaları gittikçe büyüyüp ağırlaşır."},{"t":"Yere düşmesi","a":"yağmur","d":"Ağırlaşan damlalar yere yağmur olarak düşer."}],"ans":"Buluttan yere yağmur yağar."},{"q":"Hava çok soğuk olduğunda buluttan ne yağabilir?","steps":[{"t":"Soğuk hava","a":"su donar","d":"Hava çok soğuk olunca buluttaki su damlaları donar."},{"t":"Yere düşen","a":"kar","d":"Donan su, kar taneleri olarak yere düşer."}],"ans":"Çok soğuk havada buluttan kar yağar."},{"q":"Yağan yağmur suları nereye gider?","steps":[{"t":"Yere düşen su","a":"akar","d":"Yağmur suyu önce toprağa düşer, bir kısmı toprağın üstünden akar."},{"t":"Toplandığı yer","a":"dere, göl, deniz","d":"Akan sular dereye, oradan göle ve denize ulaşır."}],"ans":"Yağan yağmur suları akarak dere, göl ve denize gider."}],"zor":[{"q":"Su döngüsünde su sürekli aynı yolu nasıl tekrar eder?","steps":[{"t":"Yukarı çıkış","a":"buharlaşma","d":"Deniz ve göllerdeki su Güneş ile ısınıp buharlaşarak gökyüzüne çıkar."},{"t":"Aşağı iniş","a":"yağış","d":"Yukarıda bulut olan su, yağmur olarak tekrar yere iner."},{"t":"Tekrar başlama","a":"baştan başlar","d":"Yere inen su yine denize gider ve döngü baştan başlar."}],"ans":"Su buharlaşıp bulut olur, yağmur olarak yere iner ve tekrar denize giderek aynı yolu sürekli tekrar eder."},{"q":"Su döngüsünün dönmesini sağlayan en büyük güç nedir?","steps":[{"t":"Suyu ısıtan","a":"Güneş","d":"Suyu ısıtıp buharlaştıran Güneş'in sıcaklığıdır."},{"t":"Güneşin gücü","a":"ısı verir","d":"Güneş olmasaydı su ısınmaz ve buharlaşmazdı; döngü dönmezdi."}],"ans":"Su döngüsünü en çok Güneş çalıştırır çünkü suyu ısıtıp buharlaştırır."},{"q":"Yağmur damlasının yere düşmesini ne sağlar?","steps":[{"t":"Damlanın ağırlığı","a":"ağırlaşır","d":"Bulutta damlalar birleşince büyür ve ağırlaşır."},{"t":"Aşağı çeken güç","a":"yer çekimi","d":"Dünya, ağır damlaları kendine doğru aşağı çeker; buna yer çekimi denir."}],"ans":"Yer çekimi, ağırlaşan yağmur damlalarını yere doğru çeker."},{"q":"Bir su bardağını güneşli pencere kenarında açık bırakırsak günlerce sonra ne olur?","steps":[{"t":"Güneşin etkisi","a":"su buharlaşır","d":"Güneş bardaktaki suyu yavaş yavaş ısıtır ve su buharlaşır."},{"t":"Sonuç","a":"su azalır","d":"Buharlaşan su havaya karışır, bardaktaki su giderek azalır."}],"ans":"Su yavaşça buharlaşıp havaya karışır ve bardaktaki su azalır, hatta biter."},{"q":"Ağaçlar ve yapraklar su döngüsüne nasıl katkı yapar?","steps":[{"t":"Bitkinin suyu","a":"kökten alır","d":"Bitkiler topraktaki suyu kökleriyle emip yapraklarına taşır."},{"t":"Yapraktan çıkış","a":"buhar verir","d":"Yapraklar bu suyu su buharı olarak havaya bırakır."}],"ans":"Bitkiler topraktan aldıkları suyu yapraklarından buhar olarak havaya vererek su döngüsüne katkı yapar."}]},"ortaokul":{"kolay":[{"q":"Su döngüsündeki buharlaşma olayını açıklayınız.","steps":[{"t":"Isı kaynağı","a":"Güneş","d":"Güneş enerjisi, yeryüzündeki sıvı suyu ısıtır."},{"t":"Hâl değişimi","a":"sıvı → gaz","d":"Isınan su, sıvı hâlden gaz hâle (su buharı) geçerek atmosfere yükselir."}],"ans":"Buharlaşma, Güneş ısısıyla sıvı suyun gaz hâle (su buharına) geçip atmosfere yükselmesidir."},{"q":"Yoğunlaşma (yoğuşma) olayı su döngüsünde nasıl gerçekleşir?","steps":[{"t":"Yükselen buhar","a":"soğur","d":"Atmosferde yükselen su buharı, yükseklerde sıcaklık düştüğü için soğur."},{"t":"Hâl değişimi","a":"gaz → sıvı","d":"Soğuyan su buharı küçük su damlacıklarına dönüşerek bulutları oluşturur."}],"ans":"Yoğunlaşma, yükselen su buharının soğuyup su damlacıklarına dönüşerek bulut oluşturmasıdır."},{"q":"Bitkilerin terleme (transpirasyon) ile su döngüsüne katkısı nedir?","steps":[{"t":"Suyun alınması","a":"kökle emilir","d":"Bitkiler topraktaki suyu kökleriyle alıp gövdeyle yapraklara taşır."},{"t":"Havaya verilmesi","a":"yapraktan buharlaşır","d":"Su, yaprak yüzeyindeki gözeneklerden (stoma) buhar olarak atmosfere verilir."}],"ans":"Terleme ile bitkiler topraktan aldıkları suyu yapraklarından buhar olarak havaya vererek döngüye su katar."},{"q":"Yağış (yağmur, kar) su döngüsünün hangi aşamasıdır?","steps":[{"t":"Buluttaki birikme","a":"damlalar büyür","d":"Buluttaki su damlacıkları birleşip büyüyerek ağırlaşır."},{"t":"Yeryüzüne dönüş","a":"yağmur/kar","d":"Ağırlaşan damlalar yer çekimiyle yağmur, kar veya dolu olarak yeryüzüne iner."}],"ans":"Yağış, bulutlardaki suyun ağırlaşıp yağmur veya kar olarak yeryüzüne döndüğü aşamadır."},{"q":"Dünya'daki suyun büyük bölümü nerede bulunur?","steps":[{"t":"En büyük su deposu","a":"okyanuslar","d":"Yeryüzü suyunun yaklaşık yüzde 97'si okyanuslarda tuzlu su olarak bulunur."},{"t":"Döngüdeki rolü","a":"buharlaşma kaynağı","d":"Okyanuslar, buharlaşan suyun en büyük kaynağıdır."}],"ans":"Dünya'daki suyun büyük bölümü okyanuslarda bulunur ve buharlaşmanın ana kaynağıdır."}],"zor":[{"q":"Su döngüsünün aşamalarını sırasıyla yazınız.","steps":[{"t":"Yukarı çıkış","a":"buharlaşma + terleme","d":"Su, okyanus ve göllerden buharlaşır, bitkilerden terleme ile havaya geçer."},{"t":"Bulut oluşumu","a":"yoğunlaşma","d":"Yükselen buhar soğuyup yoğunlaşarak bulutları oluşturur."},{"t":"Yere dönüş","a":"yağış ve akış","d":"Yağışla yere inen su, yüzey akışı ve yer altı suyuyla tekrar denizlere döner."}],"ans":"Buharlaşma/terleme → yoğunlaşma → yağış → yüzey akışı ve yer altı suyu ile döngü tamamlanır."},{"q":"Su döngüsünde Güneş enerjisinin rolü nedir?","steps":[{"t":"Suyu ısıtma","a":"buharlaşmayı sağlar","d":"Güneş, yüzeydeki suyu ısıtarak buharlaşmayı başlatır."},{"t":"Buharı yükseltme","a":"hava hareketi","d":"Güneş havayı da ısıtarak rüzgârları ve buharın yükselmesini sağlar."},{"t":"Sonuç","a":"döngünün motoru","d":"Güneş enerjisi olmasaydı buharlaşma olmaz, döngü işlemezdi."}],"ans":"Güneş enerjisi suyu buharlaştırıp havaya yükselterek su döngüsünün çalışmasını sağlayan ana güçtür."},{"q":"Yağan yağmurun toprağa süzülüp yer altı suyuna nasıl dönüştüğünü açıklayınız.","steps":[{"t":"Toprağa süzülme","a":"sızma","d":"Yağan suyun bir kısmı toprak boşluklarından aşağıya doğru sızar."},{"t":"Birikme","a":"yer altı suyu","d":"Sızan su, geçirimsiz kaya tabakaları üzerinde birikerek yer altı suyunu oluşturur."},{"t":"Kullanım","a":"kuyu/pınar","d":"Bu su, kuyu ve pınarlarla yeryüzüne çıkar veya yeniden döngüye katılır."}],"ans":"Yağmur suyunun bir kısmı toprağa sızar, alttaki tabakalarda birikerek yer altı suyunu oluşturur."},{"q":"Yer çekiminin su döngüsündeki rolü nedir?","steps":[{"t":"Yağışı indirme","a":"aşağı çeker","d":"Yer çekimi, bulutlardaki ağırlaşan suyu yeryüzüne doğru çekerek yağışı sağlar."},{"t":"Suyu akıtma","a":"yüzey akışı","d":"Yere inen su, yer çekimiyle yüksekten alçağa akarak denizlere taşınır."},{"t":"Yer altına süzme","a":"sızma","d":"Yer çekimi ayrıca suyun toprağa aşağı doğru sızmasını da sağlar."}],"ans":"Yer çekimi, yağışı yere indirir, suyu yüksekten alçağa akıtır ve toprağa sızmasını sağlar."},{"q":"Okyanuslara neden Dünya'nın en büyük su deposu denir?","steps":[{"t":"Miktar","a":"suyun yüzde 97'si","d":"Dünya'daki suyun yaklaşık yüzde 97'si okyanuslarda bulunur."},{"t":"Buharlaşma payı","a":"en çok buhar","d":"Su döngüsündeki buharın büyük kısmı geniş okyanus yüzeyinden sağlanır."},{"t":"Sonuç","a":"ana depo","d":"Hem en çok suyu içerdiği hem de döngüyü beslediği için okyanuslar ana su deposudur."}],"ans":"Okyanuslar suyun yüzde 97'sini içerir ve buharlaşmanın büyük kısmını sağladığı için en büyük su deposudur."}]},"lise":{"kolay":[{"q":"Su döngüsü (hidrolojik döngü) bilimsel olarak nasıl tanımlanır?","steps":[{"t":"Tanım","a":"suyun sürekli dolaşımı","d":"Su döngüsü, suyun atmosfer, kara ve okyanuslar arasında hâl değiştirerek sürekli dolaşmasıdır."},{"t":"İtici güçler","a":"Güneş ve yer çekimi","d":"Bu dolaşımı Güneş enerjisi (buharlaşma) ve yer çekimi (yağış, akış) yürütür."}],"ans":"Su döngüsü, suyun Güneş enerjisi ve yer çekimi etkisiyle atmosfer, kara ve okyanuslar arasında hâl değiştirerek sürekli dolaşmasıdır."},{"q":"Buharlaşma (evaporasyon) ve terleme (transpirasyon) arasındaki fark nedir?","steps":[{"t":"Buharlaşma","a":"yüzeyden","d":"Buharlaşma, açık su yüzeylerinden (okyanus, göl, toprak nemi) suyun gaz hâle geçmesidir."},{"t":"Terleme","a":"bitkiden","d":"Terleme, bitkilerin kökle aldığı suyu yaprak stomalarından buhar olarak vermesidir."}],"ans":"Buharlaşma açık su yüzeylerinden olur, terleme ise bitki yapraklarından suyun buharlaşmasıdır."},{"q":"Evapotranspirasyon terimi neyi ifade eder?","steps":[{"t":"İki süreç","a":"buharlaşma + terleme","d":"Evapotranspirasyon, yüzeyden buharlaşma ile bitkilerden terlemenin toplamıdır."},{"t":"Önemi","a":"karasal nem kaynağı","d":"Karalardan atmosfere geçen su buharının büyük kısmını bu iki süreç sağlar."}],"ans":"Evapotranspirasyon, bir alandaki buharlaşma ile bitki terlemesinin toplamını ifade eder."},{"q":"Yoğunlaşmanın gerçekleşmesi için atmosferde neye ihtiyaç vardır?","steps":[{"t":"Soğuma","a":"doyma noktası","d":"Yükselen nemli hava soğuyarak su buharı bakımından doygun hâle gelir."},{"t":"Yoğunlaşma çekirdeği","a":"toz/tuz partikülleri","d":"Su buharı, havadaki toz veya tuz gibi küçük partiküller (çekirdek) üzerinde yoğunlaşır."}],"ans":"Yoğunlaşma için havanın doyma noktasına soğuması ve üzerinde yoğunlaşacağı çekirdek partikülleri gerekir."},{"q":"Yüzey akışı (yüzeysel akış) nedir?","steps":[{"t":"Tanım","a":"yüzeyde akan su","d":"Yüzey akışı, toprağa sızamayan yağış suyunun yer çekimiyle yüzeyde akmasıdır."},{"t":"Yönü","a":"denize doğru","d":"Bu su dere ve nehirlerle toplanarak göl ve okyanuslara taşınır."}],"ans":"Yüzey akışı, toprağa sızamayan suyun yer çekimiyle yüzeyde akıp nehirler aracılığıyla denizlere ulaşmasıdır."},{"q":"Akifer (yer altı su tabakası) nedir?","steps":[{"t":"Tanım","a":"su tutan kaya tabakası","d":"Akifer, gözenekli ve geçirgen yapısıyla yer altı suyunu depolayan kaya/tortul tabakadır."},{"t":"Beslenme","a":"sızma ile","d":"Yüzeyden sızan yağış suyu akiferleri besler, kuyularla bu sudan yararlanılır."}],"ans":"Akifer, yer altı suyunu depolayan ve ileten gözenekli, geçirgen yer altı tabakasıdır."},{"q":"İnfiltrasyon (sızma) ve perkolasyon kavramları neyi anlatır?","steps":[{"t":"İnfiltrasyon","a":"toprağa giriş","d":"İnfiltrasyon, suyun toprak yüzeyinden içeriye girmesidir."},{"t":"Perkolasyon","a":"derine inme","d":"Perkolasyon, toprağa giren suyun yer çekimiyle daha derine, yer altı suyuna doğru süzülmesidir."}],"ans":"İnfiltrasyon suyun toprağa girmesi, perkolasyon ise bu suyun derine süzülerek yer altı suyuna ulaşmasıdır."},{"q":"Su döngüsünde suyun bulunduğu üç temel hâl nedir?","steps":[{"t":"Sıvı ve gaz","a":"su ve buhar","d":"Su, okyanus/göllerde sıvı, atmosferde su buharı (gaz) hâlinde bulunur."},{"t":"Katı","a":"buz/kar","d":"Kutuplarda ve buzullarda ise katı hâlde (buz, kar) bulunur."}],"ans":"Su döngüsünde su sıvı (su), gaz (su buharı) ve katı (buz/kar) olmak üzere üç hâlde bulunur."},{"q":"Tatlı su, Dünya'daki toplam suyun ne kadarını oluşturur?","steps":[{"t":"Tuzlu su payı","a":"yüzde 97","d":"Toplam suyun yaklaşık yüzde 97'si okyanuslardaki tuzlu sudur."},{"t":"Tatlı su payı","a":"yüzde 3","d":"Geriye kalan yaklaşık yüzde 3'lük kısım tatlı sudur, çoğu da buzullarda donmuştur."}],"ans":"Dünya'daki suyun yaklaşık yüzde 3'ü tatlı sudur; büyük bölümü buzullarda bulunur."},{"q":"Süblimleşme su döngüsünde hangi durumda görülür?","steps":[{"t":"Hâl değişimi","a":"katı → gaz","d":"Süblimleşme, katı hâldeki suyun (buz/kar) sıvı hâle geçmeden doğrudan su buharına dönüşmesidir."},{"t":"Görüldüğü yer","a":"buzul/kar","d":"Soğuk ve kuru bölgelerde kar ve buzulların doğrudan buharlaşmasıyla görülür."}],"ans":"Süblimleşme, buz veya karın sıvılaşmadan doğrudan su buharına dönüşmesidir."},{"q":"Su döngüsünde 'rezervuar' (depo) kavramı ne anlama gelir?","steps":[{"t":"Tanım","a":"suyun biriktiği yer","d":"Rezervuar, suyun belirli süre depolandığı havuzlardır (okyanus, buzul, göl, atmosfer, yer altı suyu)."},{"t":"En büyük","a":"okyanuslar","d":"En büyük rezervuar okyanuslardır; en uzun bekleme süresi buzullarda görülür."}],"ans":"Rezervuar, suyun bir süre depolandığı havuzdur; en büyüğü okyanuslar, en kalıcısı buzullardır."},{"q":"Atmosferdeki su buharının döngüdeki rolü nedir?","steps":[{"t":"Taşıyıcı","a":"suyu taşır","d":"Su buharı, buharlaşan suyu rüzgârlarla kara ve denizler arasında taşır."},{"t":"Yağışın kaynağı","a":"yoğunlaşıp yağar","d":"Yoğunlaşan su buharı bulutları ve sonra yağışı oluşturur."}],"ans":"Atmosferdeki su buharı, suyu bölgeler arası taşır ve yoğunlaşarak yağışın kaynağını oluşturur."},{"q":"Kalıcı buzullar (kriyosfer) su döngüsünü nasıl etkiler?","steps":[{"t":"Depolama","a":"tatlı suyu tutar","d":"Buzullar, tatlı suyun büyük kısmını uzun süre katı hâlde depolar."},{"t":"Salınım","a":"erime ile","d":"Erime sırasında bu su yavaşça akarak nehirleri ve denizleri besler."}],"ans":"Buzullar tatlı suyu uzun süre depolar, eridiklerinde ise yavaşça suları besleyerek döngüyü etkiler."},{"q":"Nem ve bağıl nem kavramı su döngüsüyle nasıl ilişkilidir?","steps":[{"t":"Nem","a":"havadaki su buharı","d":"Nem, havadaki su buharı miktarıdır ve buharlaşmayla artar."},{"t":"Bağıl nem","a":"doymaya yakınlık","d":"Bağıl nem yüksekse hava doymaya yakındır ve yoğunlaşma/yağış olasılığı artar."}],"ans":"Nem havadaki su buharını gösterir; bağıl nem yükseldikçe yoğunlaşma ve yağış olasılığı artar."},{"q":"Su döngüsünde 'bekleme süresi' (residence time) ne demektir?","steps":[{"t":"Tanım","a":"depoda kalma süresi","d":"Bekleme süresi, bir su molekülünün belirli bir rezervuarda ortalama kalma süresidir."},{"t":"Örnek","a":"atmosfer kısa, buzul uzun","d":"Atmosferde günler sürerken, derin okyanus ve buzullarda binlerce yıl olabilir."}],"ans":"Bekleme süresi, bir su molekülünün bir rezervuarda ortalama kalma süresidir; atmosferde kısa, buzul ve okyanusta çok uzundur."}],"zor":[{"q":"Su döngüsünün ana itici güçleri olan Güneş enerjisi ve yer çekiminin görevlerini karşılaştırınız.","steps":[{"t":"Güneş enerjisi","a":"suyu yükseltir","d":"Güneş, suyu buharlaştırarak ve havayı ısıtarak su buharını atmosfere yükseltir; döngünün 'yukarı' kolunu sağlar."},{"t":"Yer çekimi","a":"suyu indirir","d":"Yer çekimi, yağışı yere indirir, yüzey akışını ve sızmayı sağlar; döngünün 'aşağı' kolunu yürütür."},{"t":"Birlikte","a":"sürekli döngü","d":"İki kuvvet birlikte çalışarak suyu yukarı ve aşağı taşıyıp döngüyü kapatır."}],"ans":"Güneş enerjisi buharlaşmayla suyu yukarı taşır, yer çekimi yağış ve akışla aşağı taşır; ikisi birlikte döngüyü sürdürür."},{"q":"Bir su molekülünün okyanustan başlayıp tekrar okyanusa dönen tam bir döngü yolunu açıklayınız.","steps":[{"t":"Atmosfere çıkış","a":"buharlaşma","d":"Molekül, okyanus yüzeyinden Güneş enerjisiyle buharlaşarak atmosfere geçer."},{"t":"Karaya taşınma","a":"yoğunlaşma + yağış","d":"Rüzgârla karaya taşınan buhar yoğunlaşıp bulut olur ve yağışla karaya iner."},{"t":"Geri dönüş","a":"akış/yer altı suyu","d":"Yere inen su, yüzey akışı veya yer altı suyuyla nehirlere ulaşıp tekrar okyanusa döner."}],"ans":"Molekül okyanustan buharlaşır, karaya taşınıp yağar, ardından yüzey akışı veya yer altı suyuyla nehirler aracılığıyla tekrar okyanusa döner."},{"q":"Ormansızlaşmanın yerel su döngüsüne etkisini açıklayınız.","steps":[{"t":"Terleme azalır","a":"daha az buhar","d":"Ağaçlar kesilince terleme (transpirasyon) azalır, atmosfere geçen su buharı düşer."},{"t":"Sızma azalır","a":"daha çok yüzey akışı","d":"Köklerin tuttuğu toprak gitince su sızamaz, yüzey akışı ve erozyon artar."},{"t":"Sonuç","a":"yağış ve nem düşer","d":"Yerel nem azaldığı için yağışlar azalabilir ve bölge kuraklaşabilir."}],"ans":"Ormansızlaşma terleme ve sızmayı azaltır, yüzey akışını artırır; yerel nem ve yağış düşerek bölge kuraklaşabilir."},{"q":"Kentleşme (beton/asfalt yüzeyler) su döngüsünü nasıl değiştirir?","steps":[{"t":"Geçirimsiz yüzey","a":"sızma engellenir","d":"Asfalt ve beton, suyun toprağa sızmasını engeller, yer altı suyu beslenmesi azalır."},{"t":"Yüzey akışı","a":"hızlı ve fazla","d":"Sızamayan su hızla yüzeyde akar, ani su baskınları riski artar."},{"t":"Sonuç","a":"döngü bozulur","d":"Yer altı suyu azalırken sel riski yükselir, doğal denge bozulur."}],"ans":"Kentleşme geçirimsiz yüzeylerle sızmayı azaltır, hızlı yüzey akışı ve sel riskini artırarak yer altı suyu beslenmesini düşürür."},{"q":"Küresel ısınmanın su döngüsünün hızını ve şiddetini nasıl etkilediğini açıklayınız.","steps":[{"t":"Buharlaşma artar","a":"daha çok buhar","d":"Sıcaklık arttıkça okyanus ve karalardan buharlaşma hızlanır, atmosferdeki nem artar."},{"t":"Yağış değişir","a":"şiddetli olaylar","d":"Artan nem, bazı bölgelerde şiddetli yağış ve sel, bazılarında ise kuraklık yaratır."},{"t":"Sonuç","a":"döngü hızlanır","d":"Döngü genel olarak hızlanır (yoğunlaşır), aşırı hava olayları sıklaşır."}],"ans":"Küresel ısınma buharlaşmayı artırarak su döngüsünü hızlandırır; şiddetli yağış, sel ve kuraklık gibi aşırı olaylar sıklaşır."},{"q":"Yer altı suyunun aşırı çekilmesi (kuyu kullanımı) akiferleri nasıl etkiler?","steps":[{"t":"Çekim hızı","a":"beslenmeden hızlı","d":"Sular akifere yağışla yavaş beslenirken, kuyularla çok hızlı çekilir."},{"t":"Su seviyesi","a":"taban suyu düşer","d":"Çekim beslenmeyi aşınca yer altı su seviyesi (taban suyu) sürekli düşer."},{"t":"Sonuç","a":"çökme/tuzlanma","d":"Boşalan akifer zemin çökmesine, kıyıda ise deniz suyu girişiyle tuzlanmaya yol açabilir."}],"ans":"Aşırı çekim beslenmeyi aşınca taban suyu düşer; akifer tükenir, zemin çökmesi ve kıyılarda tuzlanma görülebilir."},{"q":"Yağışın yere düştükten sonra izlediği üç farklı yolu (akış, sızma, buharlaşma) açıklayınız.","steps":[{"t":"Yüzey akışı","a":"yüzeyde akar","d":"Yağışın bir kısmı toprağa giremeyip yüzeyde akarak nehirlere ulaşır."},{"t":"İnfiltrasyon","a":"toprağa sızar","d":"Bir kısmı toprağa sızarak yer altı suyunu besler."},{"t":"Buharlaşma","a":"havaya döner","d":"Kalan kısım yüzeyden buharlaşarak veya bitki terlemesiyle tekrar atmosfere döner."}],"ans":"Yere inen yağış yüzey akışıyla nehirlere gider, infiltrasyonla yer altı suyunu besler veya buharlaşma/terleme ile atmosfere döner."},{"q":"Su döngüsünün 'kapalı bir sistem' olarak kabul edilmesinin anlamını açıklayınız.","steps":[{"t":"Toplam miktar","a":"sabit kalır","d":"Dünya'daki toplam su miktarı pratikte sabittir; su yok olmaz, sadece yer ve hâl değiştirir."},{"t":"Dönüşüm","a":"hâl değiştirir","d":"Su sıvı, gaz ve katı hâller arasında dönüşerek rezervuarlar arasında dolaşır."},{"t":"Sonuç","a":"korunum","d":"Bu yüzden su döngüsü, kütlenin korunduğu kapalı bir sistem gibi değerlendirilir."}],"ans":"Dünya'daki toplam su miktarı sabit kaldığı, su yalnızca hâl ve yer değiştirdiği için su döngüsü kapalı bir sistem olarak kabul edilir."},{"q":"Bitki örtüsünün su döngüsündeki düzenleyici (tampon) rolünü açıklayınız.","steps":[{"t":"Yağışı tutma","a":"yavaşlatır","d":"Bitki örtüsü, yağışı yapraklarda ve köklerde tutarak yüzey akışını yavaşlatır."},{"t":"Sızmayı artırma","a":"toprağa girer","d":"Yavaşlayan su toprağa daha çok sızar, yer altı suyu beslenir."},{"t":"Terlemeyle nem","a":"havaya su verir","d":"Bitkiler terlemeyle atmosfere nem katar, yerel yağışı destekler."}],"ans":"Bitki örtüsü yağışı yavaşlatıp sızmayı artırır, erozyonu azaltır ve terlemeyle nem katar; böylece döngüde tampon görevi görür."},{"q":"Deniz suyunun buharlaşırken tuzunu geride bırakması su döngüsünü nasıl etkiler?","steps":[{"t":"Saf buhar","a":"sadece su","d":"Buharlaşma sırasında yalnızca su molekülleri havaya geçer, tuz okyanusta kalır."},{"t":"Tatlı yağış","a":"tuzsuz yağar","d":"Yoğunlaşıp yağan su tatlıdır; karalar bu tatlı suyla beslenir."},{"t":"Doğal arıtma","a":"tuz dengesi","d":"Bu süreç doğal bir damıtmadır; okyanus tuzluluğunu korurken karalara tatlı su sağlar."}],"ans":"Buharlaşmada tuz geride kaldığı için yağış tatlıdır; bu doğal damıtma karalara tatlı su sağlarken okyanus tuzluluğunu korur."},{"q":"İklim kuşaklarına göre buharlaşma ve yağış dengesinin neden farklı olduğunu açıklayınız.","steps":[{"t":"Ekvator","a":"çok buhar, çok yağış","d":"Sıcak ekvator bölgesinde buharlaşma yüksektir, yükselen nemli hava bol yağış verir."},{"t":"Çöl kuşağı","a":"alçalan kuru hava","d":"30° dolaylarında alçalan kuru hava yağışı engeller, buharlaşma yağıştan fazladır."},{"t":"Sonuç","a":"dengesiz dağılım","d":"Güneşlenme ve hava hareketleri yağış ile buharlaşmayı kuşaklara göre dengesiz dağıtır."}],"ans":"Güneşlenme ve atmosfer dolaşımı kuşaklara göre değiştiği için ekvatorda yağış, çöl kuşağında buharlaşma baskındır; denge bölgesel olarak farklılaşır."},{"q":"Baraj ve göletlerin su döngüsü üzerindeki etkilerini açıklayınız.","steps":[{"t":"Akışı yavaşlatma","a":"su biriktirir","d":"Barajlar nehir akışını durdurup büyük su yüzeyleri oluşturur."},{"t":"Buharlaşma artışı","a":"geniş yüzey","d":"Geniş ve durgun su yüzeyinden buharlaşma artar, suyun bir kısmı kaybolur."},{"t":"Beslenme değişimi","a":"yer altı suyu/nehir","d":"Sızma yerel yer altı suyunu beslerken, aşağı havzaya giden su akışı azalabilir."}],"ans":"Barajlar akışı yavaşlatıp su biriktirir; geniş yüzeyden buharlaşmayı ve yerel sızmayı artırırken aşağı havzanın su akışını azaltabilir."},{"q":"Su döngüsünde enerji aktarımının (gizli ısı) nasıl gerçekleştiğini açıklayınız.","steps":[{"t":"Buharlaşmada","a":"ısı emilir","d":"Su buharlaşırken çevreden gizli ısı (buharlaşma ısısı) emer, ortamı serinletir."},{"t":"Yoğunlaşmada","a":"ısı salınır","d":"Su buharı yükseklerde yoğunlaşırken bu gizli ısıyı atmosfere geri verir."},{"t":"Sonuç","a":"ısı taşınması","d":"Böylece su döngüsü, yüzeyden atmosfere büyük miktarda enerji taşır ve iklimi düzenler."}],"ans":"Buharlaşmada emilen gizli ısı, yoğunlaşmada atmosfere salınır; böylece su döngüsü yüzeyden atmosfere enerji taşıyarak iklimi düzenler."},{"q":"Karalardan okyanuslara giden su ile okyanuslardan karalara taşınan suyun dengesini açıklayınız.","steps":[{"t":"Okyanustan karaya","a":"net buhar taşınır","d":"Okyanuslarda buharlaşma yağıştan fazladır; fazla buhar rüzgârla karalara taşınır."},{"t":"Karadan okyanusa","a":"akışla döner","d":"Karalarda yağış buharlaşmadan fazladır; fazla su nehirler ve yer altı suyuyla okyanusa döner."},{"t":"Denge","a":"eşitlenir","d":"Atmosferle karaya taşınan su, akarsularla okyanusa dönen suya uzun vadede eşittir."}],"ans":"Okyanuslardan karalara atmosferle taşınan net su, karalardan nehir ve yer altı suyuyla okyanusa dönen suya eşittir; sistem dengededir."},{"q":"Su döngüsünün ekosistemlerin sürekliliği açısından önemini açıklayınız.","steps":[{"t":"Tatlı su sağlama","a":"canlılara su","d":"Döngü, yağışla karalara sürekli tatlı su getirerek bitki ve hayvanların su ihtiyacını karşılar."},{"t":"Madde taşıma","a":"besin/mineral","d":"Akan sular toprağa ve sucul ortamlara mineral ve besin taşıyarak verimliliği destekler."},{"t":"İklim düzenleme","a":"sıcaklık dengesi","d":"Buharlaşma ve yoğunlaşma ısı taşıyarak sıcaklık ve nem dengesini sağlar, yaşamı sürdürür."}],"ans":"Su döngüsü canlılara sürekli tatlı su ve besin taşır, iklimi düzenler; bu yüzden ekosistemlerin sürekliliği için temeldir."}]}},"tuketiciler":{"ilkokul":{"kolay":[{"q":"Tüketici ne demektir? Kısaca açıkla.","steps":[{"t":"Kelimenin anlamı","a":"tüketen, yiyen","d":"Tüketmek bir şeyi kullanıp bitirmek demektir. Burada besini yiyip kullanmak anlamındadır."},{"t":"Doğadaki anlamı","a":"besini hazır yiyen","d":"Kendi besinini yapamayan, başka canlıları yiyerek beslenen canlılara tüketici denir."}],"ans":"Tüketici, kendi besinini yapamayıp başka canlıları yiyerek beslenen canlıdır."},{"q":"Aşağıdakilerden hangileri tüketicidir: bitki mi yoksa hayvan mı?","steps":[{"t":"Bitkiyi düşün","a":"kendi besinini yapar","d":"Bitkiler güneş ışığıyla kendi besinini yapar, bu yüzden tüketici değildir."},{"t":"Hayvanı düşün","a":"besini yer","d":"Hayvanlar besinini kendi yapamaz, otları veya başka hayvanları yer."}],"ans":"Hayvanlar tüketicidir çünkü besinini başka canlılardan alır."},{"q":"Sadece ot ve yaprak yiyen hayvanlara ne ad verilir?","steps":[{"t":"Ne yediğine bak","a":"bitki yer","d":"Tavşan, inek ve keçi gibi hayvanlar ot, yaprak ve bitki yer."},{"t":"Adını söyle","a":"otçul","d":"Sadece bitkiyle beslenen bu hayvanlara otçul denir."}],"ans":"Sadece bitki yiyen hayvanlara otçul denir."},{"q":"Sadece et yiyen hayvanlara ne ad verilir?","steps":[{"t":"Ne yediğine bak","a":"et yer","d":"Aslan, kurt ve kartal gibi hayvanlar başka hayvanları avlayıp etini yer."},{"t":"Adını söyle","a":"etçil","d":"Sadece et yiyen bu hayvanlara etçil denir."}],"ans":"Sadece et yiyen hayvanlara etçil denir."},{"q":"İnek bir tüketici midir? Neden?","steps":[{"t":"İnek ne yer","a":"ot yer","d":"İnek tarladaki otları ve samanı yiyerek beslenir."},{"t":"Sonuç","a":"tüketicidir","d":"Kendi besinini yapamayıp ot yediği için inek bir tüketicidir."}],"ans":"Evet; inek kendi besinini yapamayıp ot yediği için tüketicidir."}],"zor":[{"q":"Hem ot hem et yiyen hayvanlara ne ad verilir? Bir örnek ver.","steps":[{"t":"Beslenmesine bak","a":"hem bitki hem et","d":"Bazı hayvanlar hem meyve, ot gibi bitkileri hem de et yer."},{"t":"Adını söyle","a":"hepçil","d":"Hem bitki hem et yiyen hayvanlara hepçil denir."},{"t":"Örnek ver","a":"ayı, insan","d":"Ayı hem bal ve meyve hem balık yer; insan da hem sebze hem et yer."}],"ans":"Hem ot hem et yiyen hayvanlara hepçil denir; ayı ve insan örnektir."},{"q":"Tavşan otları, tilki de tavşanı yer. Bu canlılar arasında besin nasıl aktarılır?","steps":[{"t":"Otun rolü","a":"besin yapar","d":"Bitki olan ot güneşle kendi besinini yapan üreticidir."},{"t":"Tavşanın beslenmesi","a":"otu yer","d":"Tavşan otu yiyerek otun içindeki besini ve enerjiyi alır."},{"t":"Tilkinin beslenmesi","a":"tavşanı yer","d":"Tilki tavşanı yiyince besin ottan tavşana, tavşandan tilkiye geçer."}],"ans":"Besin önce ottan tavşana, sonra tavşandan tilkiye geçerek aktarılır."},{"q":"Neden bir kaplan kendi besinini bitki gibi yapamaz?","steps":[{"t":"Bitkinin özelliği","a":"güneşle yapar","d":"Bitkilerin yeşil yaprakları vardır ve güneş ışığıyla besin üretir."},{"t":"Kaplanda eksik olan","a":"yeşil yaprak yok","d":"Kaplanın yeşil yaprağı yoktur, güneşten besin yapamaz."},{"t":"Sonuç","a":"avlanır","d":"Bu yüzden kaplan besinini başka hayvanları avlayarak alır."}],"ans":"Kaplanın yeşil yaprağı olmadığı için güneşten besin yapamaz, avlanarak beslenir."},{"q":"Bir bahçede otları yiyen çekirgeyi kuş yiyor. Burada tüketici olanlar kimlerdir?","steps":[{"t":"Otun durumu","a":"üretici","d":"Ot kendi besinini yaptığı için tüketici değil, üreticidir."},{"t":"Çekirge","a":"tüketici","d":"Çekirge otu yediği için tüketicidir."},{"t":"Kuş","a":"tüketici","d":"Kuş çekirgeyi yediği için o da tüketicidir."}],"ans":"Çekirge ve kuş tüketicidir; ot ise üreticidir."},{"q":"Tüketiciler aldıkları besinden ne kazanır?","steps":[{"t":"Besinin içinde olan","a":"enerji","d":"Yenen otun veya etin içinde gizli bir enerji vardır."},{"t":"Tüketici ne yapar","a":"enerji alır","d":"Hayvan besini yiyip sindirince bu enerjiyi vücuduna alır."},{"t":"Enerji ne işe yarar","a":"hareket ve yaşam","d":"Aldığı enerjiyle koşar, büyür ve yaşamını sürdürür."}],"ans":"Tüketiciler yedikleri besinden enerji kazanır ve bu enerjiyle hareket edip yaşar."}]},"ortaokul":{"kolay":[{"q":"Tüketiciler beslenme biçimine göre temelde kaç gruba ayrılır?","steps":[{"t":"Grupları say","a":"otçul, etçil, hepçil","d":"Tüketiciler ne yedikleri dikkate alınarak üç ana gruba ayrılır."},{"t":"Sonuç","a":"üç grup","d":"Otçullar bitki, etçiller et, hepçiller hem bitki hem et yer."}],"ans":"Tüketiciler otçul, etçil ve hepçil olmak üzere üç gruba ayrılır."},{"q":"Tüketicilere neden 'heterotrof' denir?","steps":[{"t":"Kelimenin anlamı","a":"başkasıyla beslenen","d":"Hetero başka, trof beslenme demektir; yani başkasından beslenen anlamına gelir."},{"t":"Tüketicinin durumu","a":"hazır besin alır","d":"Tüketiciler besinini kendi üretemez, hazır organik besini dışarıdan alır."}],"ans":"Tüketiciler besinini kendi üretemeyip dışarıdan hazır aldığı için heterotrof denir."},{"q":"Bir besin zincirinde üreticiyi yiyen ilk tüketiciye ne ad verilir?","steps":[{"t":"Üreticiyi yiyen","a":"otçul hayvan","d":"Üretici bitkiyi doğrudan yiyen hayvan bir otçuldur."},{"t":"Sıradaki adı","a":"birincil tüketici","d":"Üreticiyi yiyen ilk tüketiciye birincil (1.) tüketici denir."}],"ans":"Üreticiyi yiyen ilk tüketiciye birincil tüketici denir."},{"q":"Birincil tüketiciyi yiyen etçil hayvana ne ad verilir?","steps":[{"t":"Kimi yiyor","a":"otçulu yer","d":"Bu hayvan otçul olan birincil tüketiciyi avlayıp yer."},{"t":"Sıradaki adı","a":"ikincil tüketici","d":"Birincil tüketiciyi yiyen etçile ikincil (2.) tüketici denir."}],"ans":"Birincil tüketiciyi yiyen etçil hayvana ikincil tüketici denir."},{"q":"Otçul, etçil ve hepçil hayvanlara birer örnek ver.","steps":[{"t":"Otçul örneği","a":"inek, tavşan","d":"İnek ve tavşan sadece bitkiyle beslendiği için otçuldur."},{"t":"Etçil ve hepçil örneği","a":"aslan; ayı","d":"Aslan sadece et yer (etçil), ayı hem bitki hem et yer (hepçil)."}],"ans":"Otçul: inek; etçil: aslan; hepçil: ayı örnek verilebilir."}],"zor":[{"q":"Bir besin zincirinde trofik düzey ne anlama gelir?","steps":[{"t":"Kelimenin anlamı","a":"beslenme basamağı","d":"Trofik beslenmeyle ilgilidir; trofik düzey besin zincirindeki beslenme basamağıdır."},{"t":"Üreticinin düzeyi","a":"1. düzey","d":"Üreticiler her zaman birinci trofik düzeyde yer alır."},{"t":"Tüketicilerin düzeyi","a":"2., 3., ...","d":"Birincil tüketici 2., ikincil tüketici 3. trofik düzeydedir."}],"ans":"Trofik düzey, bir canlının besin zincirindeki beslenme basamağıdır; üretici 1., birincil tüketici 2. düzeydedir."},{"q":"Çayır → çekirge → kurbağa → yılan zincirinde yılan kaçıncı tüketicidir?","steps":[{"t":"Çekirge","a":"birincil tüketici","d":"Çekirge çayırı (üretici) yediği için birincil tüketicidir."},{"t":"Kurbağa","a":"ikincil tüketici","d":"Kurbağa çekirgeyi yediği için ikincil tüketicidir."},{"t":"Yılan","a":"üçüncül tüketici","d":"Yılan kurbağayı yediği için üçüncül (3.) tüketicidir."}],"ans":"Yılan, kurbağayı yediği için bu zincirde üçüncül tüketicidir."},{"q":"Tüketiciler aldıkları enerjiyi ilk olarak hangi canlılardan elde eder?","steps":[{"t":"Enerjinin kaynağı","a":"güneş","d":"Bir ekosistemdeki tüm enerji başlangıçta güneşten gelir."},{"t":"Enerjiyi bağlayan","a":"üreticiler","d":"Üreticiler fotosentezle güneş enerjisini besinin içine bağlar."},{"t":"Tüketiciye geçiş","a":"üreticiyi yiyince","d":"Tüketiciler üreticileri (ya da onları yiyenleri) yiyerek bu enerjiyi alır."}],"ans":"Tüketiciler enerjiyi, güneş enerjisini besine bağlayan üreticilerden (doğrudan ya da dolaylı) elde eder."},{"q":"Neden bir ekosistemde otçul sayısı genellikle etçil sayısından fazladır?","steps":[{"t":"Enerji aktarımı","a":"her basamakta azalır","d":"Bir basamaktan diğerine geçerken enerjinin büyük kısmı kaybolur."},{"t":"Etçile kalan enerji","a":"daha az","d":"Etçillere ulaşan enerji, otçulların aldığından çok daha azdır."},{"t":"Sonuç","a":"otçul daha çok","d":"Az enerji az canlı besler; bu yüzden etçil sayısı otçuldan azdır."}],"ans":"Enerji her basamakta azaldığı için etçillere daha az enerji ulaşır; bu nedenle otçul sayısı etçil sayısından fazladır."},{"q":"Hepçil bir canlının beslenme bakımından otçul ve etçile göre avantajı nedir?","steps":[{"t":"Hepçilin beslenmesi","a":"hem bitki hem et","d":"Hepçiller hem bitkisel hem hayvansal besinleri tüketebilir."},{"t":"Besin seçeneği","a":"daha geniş","d":"Bir besin azaldığında diğerine yönelebilir, seçeneği fazladır."},{"t":"Sonuç","a":"kolay hayatta kalma","d":"Geniş besin yelpazesi sayesinde değişen ortamlarda daha kolay hayatta kalır."}],"ans":"Hepçiller hem bitki hem et yiyebildiği için besin seçenekleri geniştir ve değişen koşullarda daha kolay hayatta kalır."}]},"lise":{"kolay":[{"q":"Heterotrof beslenme bilimsel olarak nasıl tanımlanır?","steps":[{"t":"Karbon kaynağı","a":"organik madde","d":"Heterotroflar karbon ihtiyacını hazır organik bileşiklerden karşılar."},{"t":"Enerji elde etme","a":"besini parçalar","d":"Aldıkları organik besini parçalayarak enerji ve yapı taşı elde eder."}],"ans":"Heterotrof beslenme, canlının karbon ve enerjisini dışarıdan aldığı hazır organik besinlerden sağlamasıdır."},{"q":"Birincil tüketici hangi trofik düzeyde yer alır?","steps":[{"t":"Üreticinin düzeyi","a":"1. düzey","d":"Üreticiler besin zincirinin birinci trofik düzeyini oluşturur."},{"t":"Birincil tüketici","a":"2. düzey","d":"Üreticiyle beslenen birincil tüketici ikinci trofik düzeydedir."}],"ans":"Birincil tüketici ikinci trofik düzeyde yer alır."},{"q":"Otçul (herbivor) beslenme nedir?","steps":[{"t":"Besin kaynağı","a":"üreticiler","d":"Otçullar doğrudan bitki, alg gibi üreticilerle beslenir."},{"t":"Trofik konumu","a":"birincil tüketici","d":"Üreticiyi yedikleri için besin zincirinde birincil tüketicidir."}],"ans":"Otçul beslenme, canlının üreticilerle (bitki, alg) beslenmesidir; otçullar birincil tüketicidir."},{"q":"Karnivor (etçil) tüketici hangi besinle beslenir ve hangi trofik düzeyde olabilir?","steps":[{"t":"Besin kaynağı","a":"diğer hayvanlar","d":"Etçiller başka tüketicileri (hayvanları) avlayarak beslenir."},{"t":"Trofik konumu","a":"2. ve üzeri","d":"Otçulu yerse ikincil, ikincili yerse üçüncül tüketici olur."}],"ans":"Etçiller diğer hayvanlarla beslenir ve avladıkları canlıya göre ikincil, üçüncül veya daha üst trofik düzeyde yer alır."},{"q":"Omnivor (hepçil) beslenme tipinin temel özelliği nedir?","steps":[{"t":"Besin çeşidi","a":"bitki ve hayvan","d":"Hepçiller hem bitkisel hem hayvansal besinleri tüketebilir."},{"t":"Trofik esneklik","a":"birden fazla düzey","d":"Aynı anda hem birincil hem ikincil tüketici rolü üstlenebilir."}],"ans":"Hepçiller hem bitki hem hayvan tükettiği için aynı anda birden fazla trofik düzeyde beslenebilen esnek tüketicilerdir."},{"q":"Tüketiciler bir ekosistemde enerjiyi nasıl elde eder?","steps":[{"t":"Enerji kaynağı","a":"organik besin","d":"Tüketiciler enerjiyi diğer canlılardaki organik moleküllerin bağlarından alır."},{"t":"Açığa çıkarma","a":"hücresel solunum","d":"Bu organik maddeler hücresel solunumla parçalanıp ATP üretilir."}],"ans":"Tüketiciler, besinle aldıkları organik moleküllerin kimyasal bağ enerjisini hücresel solunumla ATP'ye çevirerek enerji elde eder."},{"q":"Üreticiler ile tüketiciler arasındaki temel beslenme farkı nedir?","steps":[{"t":"Üreticiler","a":"ototrof","d":"Üreticiler inorganik maddeden kendi organik besinini üretir (ototrof)."},{"t":"Tüketiciler","a":"heterotrof","d":"Tüketiciler organik besini hazır olarak dışarıdan alır (heterotrof)."}],"ans":"Üreticiler ototroftur ve besinini kendi üretir; tüketiciler heterotroftur ve besinini dışarıdan hazır alır."},{"q":"Besin zincirinde tüketicilerin başlangıçtaki enerjisi son tahlilde nereden gelir?","steps":[{"t":"İlk kaynak","a":"Güneş","d":"Ekosistemdeki enerjinin temel kaynağı güneş ışığıdır."},{"t":"Bağlanması","a":"fotosentez","d":"Üreticiler bu enerjiyi fotosentezle organik maddeye bağlar."},{"t":"Tüketiciye akış","a":"beslenmeyle","d":"Tüketiciler beslenerek bu bağlı enerjiyi üreticilerden devralır."}],"ans":"Tüketicilerin enerjisi son tahlilde güneşten gelir; üreticiler bunu fotosentezle bağlar, tüketiciler beslenmeyle alır."},{"q":"Tepe (apeks) yırtıcı (üst düzey tüketici) kavramı ne anlama gelir?","steps":[{"t":"Konumu","a":"zincirin tepesi","d":"Tepe yırtıcı, besin zincirinin en üst trofik düzeyinde yer alır."},{"t":"Avcı durumu","a":"avlanmayan","d":"Doğal koşullarda kendisini avlayan başka bir tüketici yoktur."}],"ans":"Tepe yırtıcı, besin zincirinin en üst düzeyinde bulunan ve normalde başka canlı tarafından avlanmayan tüketicidir."},{"q":"Filtre ile beslenen (süzücü) tüketicilere bir örnek vererek beslenme biçimini açıklayınız.","steps":[{"t":"Örnek canlı","a":"midye, balina","d":"Midye ve sakallı balinalar suyu süzerek beslenir."},{"t":"Beslenme biçimi","a":"suyu süzme","d":"Su içindeki plankton ve küçük canlıları süzgeç yapılarıyla ayırır."}],"ans":"Midye ve balina gibi süzücü tüketiciler, su içindeki plankton ve küçük canlıları süzerek besin olarak alır."},{"q":"Etçillerin sindirim sistemi, otçullara göre genellikle hangi özelliği gösterir?","steps":[{"t":"Besin türü","a":"et, sindirimi kolay","d":"Et, bitkiye göre daha kolay sindirilen yoğun besindir."},{"t":"Bağırsak uzunluğu","a":"daha kısa","d":"Etçillerde sindirim kanalı genellikle otçullara göre daha kısadır."}],"ans":"Et daha kolay sindirildiği için etçillerin sindirim kanalı genellikle otçullarınkinden daha kısadır."},{"q":"Birincil ve ikincil tüketici terimleri neyi belirler?","steps":[{"t":"Birincil","a":"üreticiyi yer","d":"Birincil tüketici doğrudan üreticiyle beslenen otçuldur."},{"t":"İkincil","a":"birincili yer","d":"İkincil tüketici, birincil tüketiciyle beslenen etçildir."}],"ans":"Bu terimler canlının zincirdeki sırasını belirtir: birincil üreticiyi, ikincil ise birincil tüketiciyi yer."},{"q":"Tüketiciler enerji aktarımında neden 'enerji akışının taşıyıcısı' olarak görülür?","steps":[{"t":"Enerjiyi alma","a":"besinle","d":"Tüketiciler beslenerek bir basamaktaki enerjiyi alır."},{"t":"Bir üst düzeye taşıma","a":"avlanınca","d":"Kendileri avlandığında bu enerjiyi bir üst trofik düzeye aktarır."}],"ans":"Tüketiciler bir basamaktan aldıkları enerjiyi beslenip avlanarak üst düzeylere taşıdığı için enerji akışının taşıyıcısıdır."},{"q":"Bir besin ağında aynı tür neden birden fazla trofik düzeyde bulunabilir?","steps":[{"t":"Çeşitli beslenme","a":"farklı besinler","d":"Bir canlı hem otçul hem küçük hayvanlarla beslenebilir (hepçil)."},{"t":"Sonuç","a":"birden çok düzey","d":"Yediği besine göre kimi zaman birincil, kimi zaman ikincil tüketici olur."}],"ans":"Hepçil gibi farklı besinlerle beslenen türler, yedikleri besine göre hem birincil hem ikincil tüketici sayılabildiğinden birden fazla trofik düzeyde bulunur."},{"q":"Tüketiciler ekosistemde besin dışında hangi temel işlevi yerine getirir?","steps":[{"t":"Popülasyon kontrolü","a":"av sayısını dengeler","d":"Yırtıcılar avladıkları türlerin sayısının aşırı artmasını engeller."},{"t":"Madde dolaşımı","a":"besin döngüsü","d":"Beslenip atık üreterek madde ve enerjinin döngüde kalmasına katkı sağlar."}],"ans":"Tüketiciler, av popülasyonlarını dengeleyerek ve madde döngüsüne katkı yaparak ekosistemin dengesini korur."}],"zor":[{"q":"Bir enerji piramidinde tüketicilerin sayısının yukarı çıkıldıkça azalmasının nedenini açıklayınız.","steps":[{"t":"Enerji aktarım oranı","a":"yaklaşık %10","d":"Bir trofik düzeyden diğerine enerjinin ortalama yalnızca %10'u aktarılır."},{"t":"Enerji kaybı","a":"solunum ve ısı","d":"Enerjinin büyük kısmı solunum, hareket ve ısı olarak kaybolur."},{"t":"Sonuç","a":"az birey beslenir","d":"Üst düzeye az enerji ulaştığı için daha az birey beslenebilir."}],"ans":"Her basamakta enerjinin yaklaşık %90'ı kaybolup yalnızca %10'u aktarıldığı için üst düzeylerde daha az tüketici beslenebilir."},{"q":"Geviş getiren otçulların selülozu sindirebilmesini sağlayan uyum nedir?","steps":[{"t":"Selülozun sorunu","a":"sindirimi zor","d":"Bitkilerin selülozunu hayvanların enzimleri tek başına parçalayamaz."},{"t":"Ortak yaşam","a":"mikroorganizmalar","d":"Mide bölmelerinde yaşayan bakteri ve protistalar selülozu parçalar."},{"t":"Sonuç","a":"besin elde edilir","d":"Bu simbiyotik canlılar sayesinde otçul, bitkideki enerjiye ulaşır."}],"ans":"Geviş getiren otçullar, sindirim sistemlerinde selülozu parçalayan simbiyotik mikroorganizmalar sayesinde bitkisel besinden enerji elde eder."},{"q":"Ekolojik verimlilik (%10 kuralı) tüketici çeşitliliğini nasıl sınırlar?","steps":[{"t":"Aktarılan enerji","a":"%10","d":"Her trofik düzeye bir öncekinden yaklaşık %10 enerji aktarılır."},{"t":"Üst düzeyde enerji","a":"çok azalır","d":"Dört-beş basamak sonra kalan enerji çok azaldığı için canlı besleyemez."},{"t":"Sonuç","a":"basamak sınırı","d":"Bu yüzden besin zinciri genellikle 4-5 trofik düzeyle sınırlı kalır."}],"ans":"Her düzeyde enerjinin yalnızca %10'u aktarıldığından üst basamaklara yetersiz enerji ulaşır; bu nedenle tüketici basamak sayısı genellikle 4-5 ile sınırlıdır."},{"q":"Bir besin ağında tepe yırtıcının yok olması alt düzeylerdeki tüketicileri nasıl etkiler (trofik şelale)?","steps":[{"t":"Yırtıcı kalkar","a":"av baskısı azalır","d":"Tepe yırtıcı yok olunca avladığı tüketicinin sayısı hızla artar."},{"t":"Etki yayılır","a":"alt düzeye baskı","d":"Artan tüketici kendi besinini aşırı tüketerek bir alt düzeyi azaltır."},{"t":"Sonuç","a":"trofik şelale","d":"Bu zincirleme etkiye trofik şelale denir ve denge bozulur."}],"ans":"Tepe yırtıcının kaybı, avının aşırı artmasına ve onun beslendiği düzeyin çökmesine yol açar; bu zincirleme etki trofik şelale olarak ekosistem dengesini bozar."},{"q":"Otçullar ile etçillerin diş yapıları beslenmelerine göre nasıl uyum göstermiştir?","steps":[{"t":"Otçul dişleri","a":"geniş azı","d":"Otçullarda bitkiyi öğütmek için geniş, yassı azı dişleri gelişmiştir."},{"t":"Etçil dişleri","a":"sivri köpek dişi","d":"Etçillerde avı yakalayıp eti parçalamak için sivri köpek dişleri vardır."},{"t":"Sonuç","a":"besine uyum","d":"Diş yapısı, hayvanın beslenme tipine göre evrimsel uyum gösterir."}],"ans":"Otçullarda bitkiyi öğüten geniş azı dişleri, etçillerde eti parçalayan sivri köpek dişleri gelişmiştir; diş yapısı beslenme tipine uyum sağlar."},{"q":"Tüketicilerin enerjisinin tamamı bir önceki düzeyden gelmesine rağmen neden o düzeyin biyokütlesine eşit olamaz?","steps":[{"t":"Alınan enerji","a":"bir kısmı","d":"Tüketici, alt düzeydeki bireylerin tümünü ve tamamını yiyemez."},{"t":"Harcanan enerji","a":"solunum, atık","d":"Aldığı enerjinin çoğunu solunum, hareket ve atıkla kaybeder."},{"t":"Depolanan kısım","a":"çok az","d":"Yalnızca küçük bir bölüm yeni dokuya (biyokütleye) dönüşür."}],"ans":"Tüketici alt düzeyin tamamını yiyemediği ve aldığı enerjinin çoğunu solunumla kaybettiği için biyokütlesi bir önceki düzeyden daima küçüktür."},{"q":"Detritus (artık) ile beslenen tüketiciler (detritivorlar) ile ayrıştırıcılar arasındaki fark nedir?","steps":[{"t":"Detritivor","a":"artığı yer","d":"Solucan, gübre böceği gibi detritivorlar ölü organik maddeyi yiyerek tüketir."},{"t":"Ayrıştırıcı","a":"dışarıda parçalar","d":"Bakteri ve mantarlar enzim salgılayıp maddeyi vücut dışında parçalar."},{"t":"Fark","a":"yeme yöntemi","d":"Detritivor yutarak, ayrıştırıcı ise salgılayarak organik maddeyi işler."}],"ans":"Detritivorlar ölü organik maddeyi yutarak tüketen hayvansal canlılardır; ayrıştırıcılar ise enzim salgılayıp maddeyi vücut dışında parçalayan bakteri ve mantarlardır."},{"q":"Biyolojik birikim (biyoakümülasyon) ve biyomagnifikasyon tüketicilerin trofik düzeyiyle nasıl ilişkilidir?","steps":[{"t":"Birikim","a":"vücutta toplanma","d":"Parçalanmayan zararlı maddeler (cıva, DDT) canlının vücudunda birikir."},{"t":"Düzey çıktıkça","a":"derişim artar","d":"Üst tüketici çok sayıda birikmiş av yediği için maddenin derişimi büyür."},{"t":"Sonuç","a":"tepede en yüksek","d":"Bu yüzden zehirli madde en yüksek derişimi tepe yırtıcıda gösterir."}],"ans":"Parçalanmayan toksinler her trofik düzeyde yoğunlaşarak biyomagnifikasyona uğrar; bu nedenle derişim en üst düzeydeki tüketicilerde (tepe yırtıcı) en yüksektir."},{"q":"Bir hepçilin trofik düzeyi neden kesin bir tam sayı yerine ortalama bir değerle ifade edilir?","steps":[{"t":"Karışık beslenme","a":"farklı düzeyler","d":"Hepçil hem üreticiyle (1. düzey) hem tüketiciyle (üst düzey) beslenir."},{"t":"Hesaplama","a":"ağırlıklı ortalama","d":"Trofik düzeyi, beslendiği kaynakların oranına göre ağırlıklı ortalamayla bulunur."},{"t":"Sonuç","a":"ondalık değer","d":"Bu nedenle hepçilin trofik düzeyi 2,3 gibi ondalıklı bir değer çıkar."}],"ans":"Hepçil birden çok düzeyden beslendiği için trofik düzeyi, beslenme oranlarının ağırlıklı ortalaması olarak 2,3 gibi ondalıklı bir değerle ifade edilir."},{"q":"Tüketicilerde 'asimilasyon verimliliği' kavramı ne anlama gelir ve neden etçillerde daha yüksektir?","steps":[{"t":"Tanım","a":"sindirilen oran","d":"Asimilasyon verimliliği, yenen besinin sindirilip emilen oranıdır."},{"t":"Et vs bitki","a":"et kolay sindirilir","d":"Et, selüloz içermediği için bitkiye göre çok daha kolay sindirilir."},{"t":"Sonuç","a":"etçilde yüksek","d":"Bu nedenle etçillerin asimilasyon verimliliği otçullarınkinden yüksektir."}],"ans":"Asimilasyon verimliliği yenen besinin emilen oranıdır; et selülozsuz ve kolay sindirildiği için etçillerde otçullara göre daha yüksektir."},{"q":"Tüketicilerin enerji elde etmesinde 'tüketim → asimilasyon → üretim' aşamaları nasıl işler?","steps":[{"t":"Tüketim","a":"besini alma","d":"Tüketici önce avı veya bitkiyi yiyerek besini vücuduna alır."},{"t":"Asimilasyon","a":"sindirip emme","d":"Sindirilen besin emilir, sindirilemeyen kısım dışkıyla atılır."},{"t":"Üretim","a":"dokuya dönüşür","d":"Emilen enerjinin solunumdan artan kısmı yeni doku (büyüme) olarak depolanır."}],"ans":"Tüketici besini tüketir, sindirip emerek asimile eder ve solunumdan artan enerjiyi yeni dokuya (üretim) dönüştürerek büyür."},{"q":"Avcı-av popülasyonları arasındaki sayısal ilişki (Lotka-Volterra dalgalanması) nasıl açıklanır?","steps":[{"t":"Av artışı","a":"avcı çoğalır","d":"Av bollaşınca beslenecek besin artar, avcı popülasyonu yükselir."},{"t":"Avcı baskısı","a":"av azalır","d":"Çoğalan avcılar avı yoğun tükettiğinden av popülasyonu düşer."},{"t":"Geri besleme","a":"avcı da azalır","d":"Av azalınca besinsiz kalan avcılar da azalır, döngü baştan başlar."}],"ans":"Av artışı avcıyı çoğaltır, artan avcı avı azaltır, av azalınca avcı da azalır; bu gecikmeli geri besleme avcı-av sayılarında döngüsel dalgalanma oluşturur."},{"q":"Mikroskobik tüketiciler (zooplanktonlar) sucul ekosistemin enerji akışında neden kritik öneme sahiptir?","steps":[{"t":"Beslenmeleri","a":"fitoplanktonu yer","d":"Zooplankton, üretici olan fitoplanktonla beslenen birincil tüketicidir."},{"t":"Aktarımları","a":"balıklara enerji","d":"Kendileri balık gibi üst tüketicilere besin olur, enerjiyi yukarı taşır."},{"t":"Sonuç","a":"köprü görevi","d":"Üreticiyle büyük tüketiciler arasında temel enerji köprüsü kurar."}],"ans":"Zooplanktonlar fitoplanktonu yiyip balıklara besin olarak üreticilerle üst tüketiciler arasında enerji köprüsü kurduğu için sucul ekosistemde kritik öneme sahiptir."},{"q":"Bir besin ağında bir tüketici türünün ortadan kalkması neden tek bir zincirden daha geniş etki yaratır?","steps":[{"t":"Ağdaki bağlar","a":"çok bağlantı","d":"Besin ağında bir tür birden çok canlıyla beslenme bağı kurar."},{"t":"Tür yok olunca","a":"birçok bağ kopar","d":"O tür kalkınca hem avları hem avcıları aynı anda etkilenir."},{"t":"Sonuç","a":"yayılan etki","d":"Etki tek zincir yerine ağ boyunca birçok türe yayılır."}],"ans":"Besin ağında bir tüketici birçok türle bağlantılı olduğundan yok oluşu hem avlarını hem avcılarını etkiler ve etki tek bir zincirden çok daha geniş bir alana yayılır."},{"q":"Tüketiciler neden enerjiyi tek yönde alır ve geri üreticiye veremez? Termodinamik açıdan açıklayınız.","steps":[{"t":"Enerji kullanımı","a":"iş ve ısı","d":"Tüketici aldığı kimyasal enerjiyi iş yaparken büyük oranda ısıya çevirir."},{"t":"Isının kaybı","a":"geri alınamaz","d":"Termodinamiğin 2. yasasına göre dağılan ısı tekrar kullanılır enerjiye dönüşemez."},{"t":"Sonuç","a":"tek yönlü akış","d":"Bu yüzden enerji besin zincirinde yalnızca tek yönde akar, döngü oluşturamaz."}],"ans":"Tüketici aldığı enerjinin büyük kısmını termodinamiğin 2. yasası gereği geri kazanılamayan ısıya çevirdiği için enerji üreticiden tüketiciye tek yönde akar ve geri dönmez."}]}},"turlerArasi":{"ilkokul":{"kolay":[{"q":"Arı ile çiçek arasında nasıl bir yardımlaşma vardır?","steps":[{"t":"Arının kazancı","a":"besin alır","d":"Arı çiçekten tatlı bal özünü (nektar) alarak karnını doyurur."},{"t":"Çiçeğin kazancı","a":"taşınır","d":"Arı uçarken çiçek tozlarını başka çiçeğe taşır, böylece çiçek çoğalır."}],"ans":"Arı çiçekten besin alır, çiçek de arı sayesinde çoğalır; ikisi de yarar görür."},{"q":"Aslan ile ceylan arasında nasıl bir ilişki vardır?","steps":[{"t":"Kim avlar","a":"aslan avlar","d":"Aslan karnını doyurmak için ceylanı kovalayıp yakalar."},{"t":"Kim av olur","a":"ceylan av","d":"Ceylan aslandan kaçmaya çalışır çünkü ona yem olabilir."}],"ans":"Aslan avcıdır, ceylan ise avdır; buna avcı-av ilişkisi denir."},{"q":"Köpekteki pireler köpeğe yarar mı verir, zarar mı?","steps":[{"t":"Pirenin işi","a":"kan emer","d":"Pire köpeğin üzerinde yaşar ve onun kanını emerek beslenir."},{"t":"Köpeğin durumu","a":"zarar görür","d":"Köpek kaşınır ve rahatsız olur, yani zarar görür."}],"ans":"Pire köpekten kan emerek yarar görür, köpek ise zarar görür."},{"q":"İki köpek aynı kemiği isterse ne olur?","steps":[{"t":"Aynı şeyi isteme","a":"ikisi de ister","d":"İki köpek de aynı kemiği yemek ister."},{"t":"Sonuç","a":"yarışırlar","d":"Aynı şeyi paylaşamadıkları için birbirleriyle yarışır, buna rekabet denir."}],"ans":"İki köpek aynı kemik için yarışır; buna rekabet (yarış) denir."},{"q":"Kuş, ineğin sırtına konup üzerindeki böcekleri yerse kim yarar görür?","steps":[{"t":"Kuşun kazancı","a":"besin bulur","d":"Kuş ineğin üzerindeki böcekleri yiyerek karnını doyurur."},{"t":"İneğin kazancı","a":"böceklerden kurtulur","d":"İnek de onu rahatsız eden böceklerden temizlenir."}],"ans":"Kuş böcekleri yiyerek doyar, inek de böceklerden kurtulur; ikisi de yarar görür."}],"zor":[{"q":"Bir kuş, ağacın dalına yuva yaparsa kuş ile ağaç bu ilişkiden nasıl etkilenir?","steps":[{"t":"Kuşun kazancı","a":"barınak bulur","d":"Kuş ağacın dalında güvenli bir yuva yapıp yumurtalarını korur."},{"t":"Ağacın durumu","a":"etkilenmez","d":"Ağaç bundan ne yarar görür ne de zarar; ona bir şey olmaz."}],"ans":"Kuş ağaçtan barınak kazanır, ağaca ise bir şey olmaz; kuş yarar görür, ağaç etkilenmez."},{"q":"Otları aynı tarlada yiyen iki tavşan neden birbirine zorluk çıkarır?","steps":[{"t":"Aynı besin","a":"aynı otları yer","d":"İki tavşan da aynı tarladaki otlarla beslenir."},{"t":"Az besin","a":"yetmeyebilir","d":"Otlar azalınca ikisine birden yetmez, biri çok yerse diğerine az kalır."},{"t":"Sonuç","a":"rekabet","d":"Aynı besin için yarıştıkları için aralarında rekabet vardır."}],"ans":"İki tavşan aynı otlar için yarıştığından birbirine zorluk çıkarır; buna rekabet denir."},{"q":"Baykuş geceleri fareleri avlarsa, farelerin sayısı çok artarsa ne olur?","steps":[{"t":"Bol av","a":"çok fare","d":"Fareler çoğalınca baykuşa bol miktarda yiyecek olur."},{"t":"Avcının çoğalması","a":"baykuş artar","d":"Bol besin bulan baykuşlar da zamanla çoğalır."},{"t":"Sonuç","a":"fare azalır","d":"Çok baykuş daha çok fare avlayınca fare sayısı tekrar azalır."}],"ans":"Fareler çoğalınca baykuşlar da artar, sonra fareleri çok avlayıp sayılarını azaltır; avcı ve av birbirini dengeler."},{"q":"Bir solucan, bir insanın bağırsağında yaşayıp besinini çalarsa kim yarar kim zarar görür?","steps":[{"t":"Solucanın kazancı","a":"hazır besin","d":"Solucan insanın yediği besinden pay alarak beslenir."},{"t":"İnsanın durumu","a":"zarar görür","d":"İnsan yeterli besin alamaz, halsizleşir ve hastalanır."}],"ans":"Solucan hazır besin bulup yarar görür, insan ise zarar görür; buna parazitlik denir."},{"q":"Bir çiçek tarlasında arılar olmasaydı çiçekler için ne değişirdi?","steps":[{"t":"Arının görevi","a":"çiçek tozu taşır","d":"Arılar bir çiçekten ötekine çiçek tozu taşıyarak çoğalmaya yardım eder."},{"t":"Arı olmazsa","a":"taşınmaz","d":"Arı olmazsa çiçek tozları başka çiçeğe gidemez."},{"t":"Sonuç","a":"çoğalamaz","d":"Tozlaşma olmayınca çiçekler tohum yapıp çoğalamaz."}],"ans":"Arılar olmasaydı çiçek tozu taşınamaz, çiçekler tohum yapıp çoğalamazdı; arı ile çiçek birbirine yardım eder."}]},"ortaokul":{"kolay":[{"q":"İki canlının da yarar gördüğü ortak yaşama ne ad verilir?","steps":[{"t":"İlişkinin yönü","a":"iki tarafa yarar","d":"Bu ilişkide canlıların ikisi de birbirinden fayda sağlar."},{"t":"Adı","a":"mutualizm","d":"Karşılıklı yarar sağlanan bu ilişkiye mutualizm (ortak yaşam) denir."}],"ans":"İki canlının da yarar gördüğü ilişkiye mutualizm denir."},{"q":"Parazitlik ilişkisinde taraflar nasıl etkilenir?","steps":[{"t":"Parazitin durumu","a":"yarar görür","d":"Parazit, üzerinde yaşadığı canlıdan besin alarak yarar görür."},{"t":"Konağın durumu","a":"zarar görür","d":"Üzerinde yaşanan canlı (konak) ise besin kaybeder ve zarar görür."}],"ans":"Parazitlikte parazit yarar görür, konak zarar görür."},{"q":"Av-avcı ilişkisinde avcının görevi nedir?","steps":[{"t":"Avcının beslenmesi","a":"avı yer","d":"Avcı, başka bir canlıyı (avı) yakalayıp yiyerek beslenir."},{"t":"İlişkinin türü","a":"bir taraf zarar","d":"Av yenildiği için zarar görür, avcı ise besin kazanır."}],"ans":"Av-avcı ilişkisinde avcı avı yakalayıp yer; avcı yarar, av zarar görür."},{"q":"Aynı besin ve alan için iki canlının yarışmasına ne denir?","steps":[{"t":"Ortak ihtiyaç","a":"aynı kaynak","d":"İki canlı aynı besin, su veya yaşama alanına ihtiyaç duyar."},{"t":"Adı","a":"rekabet","d":"Sınırlı kaynak için yarıştıkları bu ilişkiye rekabet denir."}],"ans":"Aynı kaynak için yarışan canlılar arasındaki ilişkiye rekabet denir."},{"q":"Bir canlının yarar gördüğü, diğerinin ne yarar ne zarar gördüğü ilişkiye ne denir?","steps":[{"t":"Bir tarafın durumu","a":"yarar görür","d":"İlişkideki bir canlı barınma veya taşınma gibi bir yarar sağlar."},{"t":"Diğer tarafın durumu","a":"etkilenmez","d":"Diğer canlı bu ilişkiden etkilenmez; ne kazanır ne kaybeder."}],"ans":"Biri yarar gördüğü, diğerinin etkilenmediği ilişkiye komensalizm (kommensalizm) denir."}],"zor":[{"q":"Likende yaşayan mantar ve alg arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Algin katkısı","a":"besin üretir","d":"Alg fotosentez yaparak ortak yaşam için besin üretir."},{"t":"Mantarın katkısı","a":"su ve mineral","d":"Mantar su ve mineral tutarak alge koruma ve nem sağlar."},{"t":"İlişki türü","a":"mutualizm","d":"İkisi de yarar gördüğü için bu bir mutualizm örneğidir."}],"ans":"Likende alg besin üretir, mantar su ve koruma sağlar; ikisi de yarar gördüğü için bu bir mutualizmdir."},{"q":"Köpekbalığının yanında yüzen ve artıklarını yiyen küçük balıkların ilişkisi hangi türdür?","steps":[{"t":"Küçük balığın durumu","a":"yarar görür","d":"Küçük balık köpekbalığının yemek artıklarını yiyerek beslenir."},{"t":"Köpekbalığının durumu","a":"etkilenmez","d":"Köpekbalığı bu durumdan ne yarar görür ne de zarar."},{"t":"İlişki türü","a":"komensalizm","d":"Biri yarar görüp diğeri etkilenmediği için bu komensalizmdir."}],"ans":"Küçük balık artıkları yiyerek yarar görür, köpekbalığı etkilenmez; bu komensalizmdir."},{"q":"Bir bölgede kurtlar yok edilirse geyik sayısı neden önce artar, sonra sorun çıkarır?","steps":[{"t":"Avcı yok","a":"baskı kalkar","d":"Kurtlar gidince geyikleri avlayan baskı ortadan kalkar."},{"t":"Aşırı artış","a":"geyik çoğalır","d":"Avlanmadıkları için geyik sayısı hızla artar."},{"t":"Sonuç","a":"bitki tükenir","d":"Çok sayıda geyik bitkileri aşırı yer, besin tükenir ve geyikler aç kalır."}],"ans":"Avcı kurt olmayınca geyik aşırı çoğalır, bitkileri tüketir ve sonunda besin yetmediği için zorluk yaşanır; avcı popülasyonu dengede tutar."},{"q":"Bağırsak solucanı ile insan arasındaki parazitlik ilişkisini taraflar açısından değerlendiriniz.","steps":[{"t":"Solucanın durumu","a":"besin alır","d":"Solucan insanın bağırsağındaki hazır besinden pay alarak beslenir."},{"t":"İnsanın durumu","a":"zarar görür","d":"İnsan besin kaybeder, halsizleşir ve hastalanabilir."},{"t":"İlişki türü","a":"parazitlik","d":"Biri yarar, diğeri zarar gördüğü için bu bir parazitlik ilişkisidir."}],"ans":"Solucan hazır besinden yarar görür, insan besin kaybedip zarar görür; bu bir parazitlik (iç parazit) ilişkisidir."},{"q":"Baklagil bitkisi ile köklerindeki azot bakterileri arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Bakterinin katkısı","a":"azot sağlar","d":"Bakteriler havadaki azotu bitkinin kullanabileceği biçime dönüştürür."},{"t":"Bitkinin katkısı","a":"besin ve yer","d":"Bitki, bakterilere besin ve köklerinde barınma yeri sağlar."},{"t":"İlişki türü","a":"mutualizm","d":"İkisi de yarar gördüğü için bu bir mutualizm örneğidir."}],"ans":"Bakteri bitkiye azot sağlar, bitki bakteriye besin ve barınak verir; ikisi de yarar gördüğü için mutualizmdir."}]},"lise":{"kolay":[{"q":"Türler arası ilişkilerde +/− gösterimi neyi ifade eder?","steps":[{"t":"Artı işareti","a":"yarar","d":"+ işareti, ilişkiden o türün yarar (fayda) gördüğünü belirtir."},{"t":"Eksi ve sıfır","a":"zarar ve nötr","d":"− işareti zararı, 0 işareti ise etkilenmemeyi (nötr) gösterir."}],"ans":"+ yararı, − zararı, 0 ise etkilenmemeyi gösterir; ilişkiler bu işaretlerle sınıflandırılır."},{"q":"Mutualizm ilişkisini +/− gösterimiyle ifade ediniz.","steps":[{"t":"Taraf etkileri","a":"iki tarafa yarar","d":"Mutualizmde her iki tür de ilişkiden fayda sağlar."},{"t":"Gösterim","a":"(+ / +)","d":"İki tarafa da yarar olduğu için gösterim (+ / +) biçimindedir."}],"ans":"Mutualizm (+ / +) olarak gösterilir; her iki tür de yarar görür."},{"q":"Komensalizm ilişkisini +/− gösterimiyle ifade ediniz.","steps":[{"t":"Taraf etkileri","a":"biri yarar biri nötr","d":"Komensalizmde bir tür yarar görür, diğeri etkilenmez."},{"t":"Gösterim","a":"(+ / 0)","d":"Yarar gören için +, etkilenmeyen için 0 yazılır."}],"ans":"Komensalizm (+ / 0) olarak gösterilir; bir tür yarar görür, diğeri etkilenmez."},{"q":"Parazitlik ilişkisini +/− gösterimiyle ifade ediniz.","steps":[{"t":"Taraf etkileri","a":"parazit + konak −","d":"Parazit konaktan beslenerek yarar görür, konak zarar görür."},{"t":"Gösterim","a":"(+ / −)","d":"Parazit için +, konak için − yazılarak gösterilir."}],"ans":"Parazitlik (+ / −) olarak gösterilir; parazit yarar, konak zarar görür."},{"q":"Rekabet (kompetisyon) ilişkisini +/− gösterimiyle ifade ediniz.","steps":[{"t":"Taraf etkileri","a":"iki tarafa zarar","d":"Sınırlı kaynak için yarışan her iki tür de kaynaktan kısıtlı pay alır."},{"t":"Gösterim","a":"(− / −)","d":"Her iki taraf da olumsuz etkilendiği için (− / −) gösterilir."}],"ans":"Rekabet (− / −) olarak gösterilir; sınırlı kaynak yüzünden her iki tür de zarar görür."},{"q":"Av-avcı (predasyon) ilişkisinde tarafların etkilerini belirtiniz.","steps":[{"t":"Avcının durumu","a":"yarar (+)","d":"Avcı, avı yakalayıp tükettiği için besin kazanır."},{"t":"Avın durumu","a":"zarar (−)","d":"Av yendiği için bireysel olarak zarar görür."}],"ans":"Av-avcı ilişkisi (+ / −) biçimindedir; avcı yarar görür, av zarar görür."},{"q":"Amensalizm ilişkisi nedir, taraflar nasıl etkilenir?","steps":[{"t":"Bir tarafın etkisi","a":"zarar (−)","d":"Bir tür, ürettiği maddeyle diğerinin gelişimini engeller veya zarar verir."},{"t":"Diğer tarafın etkisi","a":"etkilenmez (0)","d":"Zarar veren tür bu ilişkiden ne yarar ne zarar görür, nötrdür."}],"ans":"Amensalizm (− / 0) biçimindedir; bir tür zarar görürken diğeri hiç etkilenmez."},{"q":"İç parazit ile dış parazit arasındaki fark nedir?","steps":[{"t":"İç parazit","a":"vücut içinde","d":"İç parazit konağın vücudunun içinde (örneğin bağırsakta) yaşar."},{"t":"Dış parazit","a":"vücut yüzeyinde","d":"Dış parazit konağın derisi veya tüyleri üzerinde yaşar (bit, pire)."}],"ans":"İç parazit konağın iç organlarında, dış parazit ise vücut yüzeyinde yaşar; ikisi de konaktan beslenir."},{"q":"Mutualizm ile komensalizm arasındaki temel fark nedir?","steps":[{"t":"Mutualizm","a":"(+ / +)","d":"Mutualizmde her iki tür de ilişkiden yarar sağlar."},{"t":"Komensalizm","a":"(+ / 0)","d":"Komensalizmde yalnız bir tür yarar görür, diğeri etkilenmez."}],"ans":"Mutualizmde her iki taraf da yarar görür (+ / +), komensalizmde ise yalnızca bir taraf yarar görür, diğeri etkilenmez (+ / 0)."},{"q":"Predasyon (av-avcı) ile parazitlik arasındaki temel fark nedir?","steps":[{"t":"Predasyon","a":"av öldürülür","d":"Avcı avını genellikle hızla öldürerek tüketir."},{"t":"Parazitlik","a":"konak yaşar","d":"Parazit konağı genellikle hemen öldürmez, ondan uzun süre beslenir."}],"ans":"Predasyonda av yakalanıp öldürülür; parazitlikte konak çoğunlukla canlı kalır ve parazit ondan sürekli beslenir."},{"q":"Mutualizmde 'zorunlu' ve 'isteğe bağlı' ortaklık ne anlama gelir?","steps":[{"t":"Zorunlu mutualizm","a":"biri olmadan yaşayamaz","d":"Zorunlu (obligat) mutualizmde türler birbiri olmadan yaşayamaz (likendeki mantar-alg)."},{"t":"İsteğe bağlı","a":"ayrı da yaşar","d":"İsteğe bağlı (fakültatif) mutualizmde türler ayrı da yaşayabilir ama birlikte daha avantajlıdır."}],"ans":"Zorunlu mutualizmde türler birbiri olmadan yaşayamaz; isteğe bağlı mutualizmde ayrı yaşayabilirler ama birliktelik avantaj sağlar."},{"q":"Konak (host) kavramı parazitlikte neyi ifade eder?","steps":[{"t":"Konağın tanımı","a":"barındıran canlı","d":"Konak, parazitin üzerinde veya içinde yaşadığı, ondan beslendiği canlıdır."},{"t":"Konağın etkisi","a":"zarar görür","d":"Konak besin ve enerji kaybeder, bu yüzden zarar gören taraftır."}],"ans":"Konak, parazitin üzerinde veya içinde yaşayıp beslendiği canlıdır ve parazitlikten zarar gören taraftır."},{"q":"Ekosistemde av-avcı ilişkisinin denge sağlayıcı rolü nedir?","steps":[{"t":"Av sayısı artışı","a":"avcıya bol besin","d":"Av popülasyonu artınca avcılar bol besin bulup çoğalır."},{"t":"Avcı baskısı","a":"avı azaltır","d":"Çoğalan avcılar avı daha çok tüketerek sayısını düşürür."},{"t":"Geri dönüş","a":"dengeye gelir","d":"Av azalınca avcı da azalır; iki popülasyon birbirini dengede tutar."}],"ans":"Av ve avcı popülasyonları birbirini izleyerek dalgalanır; bu karşılıklı denetim ekosistemde sayısal dengeyi korur."},{"q":"Temizleyici (ortakçı) balıkların büyük balıklarla ilişkisi hangi türdür ve neden?","steps":[{"t":"Temizleyicinin kazancı","a":"besin","d":"Temizleyici balık, büyük balığın derisindeki parazit ve ölü dokuyu yiyerek beslenir."},{"t":"Büyük balığın kazancı","a":"temizlenir","d":"Büyük balık parazitlerden arınır, böylece sağlığı korunur."}],"ans":"Bu bir mutualizmdir; temizleyici balık besin bulur, büyük balık parazitlerden temizlenir, her iki taraf da yarar görür."},{"q":"Allelopati olayı hangi türler arası ilişkiyle ilgilidir?","steps":[{"t":"Allelopatinin tanımı","a":"kimyasal salgı","d":"Bir bitki, salgıladığı kimyasal maddelerle çevresindeki başka bitkilerin gelişimini engeller."},{"t":"Etki yönü","a":"biri zarar biri nötr","d":"Engellenen bitki zarar görür, salgılayan bitki bu durumdan etkilenmez."}],"ans":"Allelopati bir amensalizm örneğidir (− / 0); salgılanan kimyasal komşu bitkiye zarar verirken salgılayan tür etkilenmez."}],"zor":[{"q":"Yarış (rekabet) iki tür arasında türler arası, aynı tür içinde tür içi olabilir; bu ayrımın ekolojik sonucu nedir?","steps":[{"t":"Tür içi rekabet","a":"aynı tür","d":"Aynı türün bireyleri tamamen aynı kaynağı kullandığından rekabet çok şiddetlidir."},{"t":"Türler arası rekabet","a":"farklı tür","d":"Farklı türler kaynakların yalnız bir kısmında çakışır, rekabet daha sınırlıdır."},{"t":"Sonuç","a":"niş ayrışması","d":"Şiddetli rekabet, türleri farklı niş kullanmaya iter; buna niş ayrışması denir."}],"ans":"Tür içi rekabet aynı niş yüzünden daha şiddetlidir; türler arası rekabet ise niş ayrışmasına yol açarak türlerin bir arada yaşamasını sağlar."},{"q":"Gause'un rekabetçi dışlama ilkesi (competitive exclusion) ne ifade eder?","steps":[{"t":"İlkenin tanımı","a":"aynı niş bir arada olmaz","d":"Aynı kaynağı tamamen aynı şekilde kullanan iki tür aynı yerde sürekli bir arada yaşayamaz."},{"t":"Sonuç","a":"biri dışlanır","d":"Daha verimli tür kaynağı ele geçirir, diğeri yerel olarak yok olur ya da göç eder."},{"t":"Kaçış yolu","a":"niş farklılaşması","d":"Türler kaynak kullanımını farklılaştırarak (niş ayrışması) bir arada kalabilir."}],"ans":"Rekabetçi dışlama ilkesine göre tam aynı nişi paylaşan iki tür uzun süre bir arada yaşayamaz; biri dışlanır ya da türler nişlerini farklılaştırır."},{"q":"Ko-evrim (birlikte evrim) kavramını av-avcı ilişkisi üzerinden açıklayınız.","steps":[{"t":"Avcı baskısı","a":"seçilim","d":"Avcılar en yavaş, en savunmasız avları yakalar; hızlı/savunmalı bireyler hayatta kalır."},{"t":"Avın evrimi","a":"savunma gelişir","d":"Zamanla avda hız, kamuflaj veya zehir gibi savunmalar gelişir."},{"t":"Avcının yanıtı","a":"karşı uyum","d":"Avcıda da daha keskin duyu, hız veya zehir direnci gelişir; iki tür birbirini şekillendirir."}],"ans":"Ko-evrimde av üzerindeki avcı baskısı savunma özelliklerini seçer, avcı da bunlara karşı uyum geliştirir; iki tür karşılıklı olarak birbirinin evrimini yönlendirir."},{"q":"Mutualizm ile parazitliğin sınırının her zaman keskin olmadığını bir örnekle açıklayınız.","steps":[{"t":"Koşula bağlı etki","a":"ortam değişir","d":"Bazı simbiyotik ilişkiler ortam koşullarına göre yararlı ya da zararlı hale gelebilir."},{"t":"Örnek","a":"bağırsak bakterileri","d":"Bağırsak bakterileri normalde sindirime yardım eder (mutualizm), bağışıklık zayıflayınca hastalık yapabilir (parazitlik)."},{"t":"Sonuç","a":"süreklilik","d":"Bu nedenle ilişkiler kesin kutular değil, bir süreklilik üzerinde yer alır."}],"ans":"İlişkiler koşula bağlı değişebilir; bağırsak bakterileri normalde mutualist iken konak zayıfladığında patojen (parazit) olabilir, yani sınır her zaman keskin değildir."},{"q":"Endoparazit ile ektoparazitin konak üzerindeki etkilerini ve uyumlarını karşılaştırınız.","steps":[{"t":"Endoparazit","a":"iç organda","d":"Tenya gibi iç parazitler bağırsakta yaşar; sindirim sistemi körelmiş, üreme yetenekleri çok gelişmiştir."},{"t":"Ektoparazit","a":"yüzeyde","d":"Bit, kene gibi dış parazitler yüzeyde yaşar; tutunma organları ve kan emici ağız yapıları gelişmiştir."},{"t":"Ortak etki","a":"konağa zarar","d":"İkisi de konaktan besin/kan alarak ona zarar verir, hastalık taşıyabilir."}],"ans":"Endoparazitler iç organlarda yaşayıp körelmiş sindirim ve güçlü üremeye uyum gösterir; ektoparazitler yüzeyde tutunma ve kan emme yapılarına sahiptir; her ikisi de konağa zarar verir."},{"q":"Bir mutualizm ilişkisi olan mikoriza (mantar-bitki kökü) ortaklığını madde alışverişi açısından açıklayınız.","steps":[{"t":"Mantarın katkısı","a":"su ve mineral","d":"Mantar hifleri kök yüzeyini genişleterek su ve mineral (özellikle fosfor) alımını artırır."},{"t":"Bitkinin katkısı","a":"organik besin","d":"Bitki fotosentezle ürettiği glikozu mantara aktarır."},{"t":"Sonuç","a":"karşılıklı yarar","d":"Madde alışverişiyle iki taraf da daha iyi beslenir; bu bir mutualizmdir."}],"ans":"Mikorizada mantar bitkiye su ve mineral sağlar, bitki mantara fotosentez ürünü organik besin verir; karşılıklı madde alışverişine dayanan bir mutualizmdir."},{"q":"Predasyonun ekosistemde tür çeşitliliğini koruyabildiğini 'anahtar taşı tür' (keystone) kavramıyla açıklayınız.","steps":[{"t":"Anahtar avcı","a":"baskın avı denetler","d":"Anahtar taşı avcı, ortamda baskınlaşma eğilimindeki türü avlayarak sayısını sınırlar."},{"t":"Rekabetin azalması","a":"yer açılır","d":"Baskın tür kontrol altında tutulunca zayıf rakipler de yaşam alanı bulur."},{"t":"Sonuç","a":"çeşitlilik artar","d":"Böylece tek türün her şeyi ele geçirmesi engellenir, tür çeşitliliği korunur."}],"ans":"Anahtar taşı avcı, baskınlaşacak avı denetleyerek rekabeti azaltır ve daha fazla türe yaşam alanı bırakır; böylece predasyon tür çeşitliliğini koruyabilir."},{"q":"Lotka-Volterra modelinde av ve avcı popülasyonlarının grafikte neden gecikmeli (faz farklı) dalgalandığını açıklayınız.","steps":[{"t":"Av artışı","a":"avcıdan önce","d":"Av bol olunca önce av sayısı yükselir."},{"t":"Avcı yanıtı","a":"gecikmeli artış","d":"Avcı, bol avla beslenip ürediği için biraz gecikmeyle artar."},{"t":"Çöküş sırası","a":"av önce düşer","d":"Çok avcı avı tüketince önce av azalır, ardından besinsiz kalan avcı azalır."}],"ans":"Avcı, av artışına ancak üreyerek gecikmeyle yanıt verdiği için iki eğri faz farkıyla dalgalanır; av zirvesini avcı zirvesi gecikmeli olarak izler."},{"q":"Komensalizm örneklerinde 'etkisiz' tarafın gerçekte hafifçe etkilenebileceği eleştirisi nedir?","steps":[{"t":"Klasik tanım","a":"(+ / 0)","d":"Komensalizmde bir tür yarar görür, diğeri etkilenmez kabul edilir."},{"t":"Gerçek durum","a":"hafif etki olabilir","d":"Örneğin dala yuva yapan kuş ağaca çok küçük bir yük veya yarar getirebilir."},{"t":"Sonuç","a":"yaklaşık nötr","d":"Etki ölçülemeyecek kadar küçük olduğunda pratikte 0 kabul edilir."}],"ans":"Saf nötr etki nadirdir; etkilenmeyen tarafta çoğu zaman çok küçük bir etki bulunur, ancak ihmal edilebilir düzeyde olduğu için komensalizm (+ / 0) kabul edilir."},{"q":"Çiçekli bitki ile tozlaştırıcı böcek arasındaki ko-evrimsel uyuma bir örnek veriniz.","steps":[{"t":"Bitkinin uyumu","a":"derin nektar","d":"Bazı orkidelerin nektarı çok derin bir borucukta bulunur."},{"t":"Böceğin uyumu","a":"uzun hortum","d":"Bu nektara ulaşan kelebek/güvelerde olağanüstü uzun bir emme hortumu gelişmiştir."},{"t":"Karşılıklı seçilim","a":"birlikte evrim","d":"Bitki daha derin nektarla en uygun tozlaştırıcıyı seçer, böcek de daha uzun hortumla buna uyar."}],"ans":"Derin nektarlı orkide ile uzun hortumlu güve örneğinde, bitki ve tozlaştırıcı birbirinin yapısını karşılıklı seçilimle şekillendirmiştir; bu bir ko-evrim örneğidir."},{"q":"Aynı kaynağı kullanan iki türün bir arada kalabilmesini sağlayan 'kaynak bölüşümü' (resource partitioning) nasıl işler?","steps":[{"t":"Çakışma sorunu","a":"aynı kaynak","d":"İki tür aynı besin veya alan için yarışırsa rekabet şiddetlenir."},{"t":"Bölüşüm","a":"farklı kullanım","d":"Türler kaynağı zaman, yer veya boyut bakımından farklı kullanarak çakışmayı azaltır."},{"t":"Örnek","a":"farklı dal yüksekliği","d":"Aynı ağaçta beslenen ötücü kuşların farklı dal yüksekliklerini kullanması gibi."}],"ans":"Kaynak bölüşümünde türler aynı kaynağı zaman, yer veya boyut bakımından farklı kullanarak rekabeti azaltır; böylece niş ayrışmasıyla bir arada yaşayabilirler."},{"q":"Bir parazitin konağını hemen öldürmemesi neden evrimsel olarak avantajlıdır?","steps":[{"t":"Konağın işlevi","a":"besin ve yaşam alanı","d":"Konak, parazit için hem sürekli besin kaynağı hem de yaşam ortamıdır."},{"t":"Erken ölüm","a":"parazite zarar","d":"Konak hemen ölürse parazit hem besin kaynağını hem üreme/yayılma fırsatını kaybeder."},{"t":"Seçilim","a":"ılımlı zarar","d":"Konağı yaşatan, daha az öldürücü parazit soyları daha çok yayılır ve seçilir."}],"ans":"Konak parazite sürekli besin ve yayılma fırsatı sağladığından, konağı yaşatan daha az öldürücü parazitler evrimsel olarak avantajlıdır ve doğal seçilimle çoğalır."},{"q":"Mutualizmin bazen 'aldatma' (cheating) ile bozulabileceğini bir örnekle açıklayınız.","steps":[{"t":"Normal mutualizm","a":"karşılıklı hizmet","d":"Çiçek nektar sunar, böcek de tozlaştırma hizmeti verir; iki taraf yarar görür."},{"t":"Aldatan taraf","a":"hizmet vermeden alır","d":"Bazı böcekler çiçeğin yanını delip nektarı çalar ama tozlaştırma yapmaz (nektar hırsızlığı)."},{"t":"Sonuç","a":"denge bozulur","d":"Hizmet vermeden yarar sağlayan aldatıcılar artarsa ortaklığın karşılıklı yararı zayıflar."}],"ans":"Nektar hırsızı böceklerin tozlaştırma yapmadan nektar çalması gibi durumlarda bir taraf hizmet vermeden yarar sağlar; bu aldatma, mutualizmin karşılıklı yarar dengesini bozabilir."},{"q":"Bir ekosistemde üst düzey avcının (apex predator) yok olmasının zincirleme etkisini (trofik kaskad) açıklayınız.","steps":[{"t":"Avcı yok","a":"otçul artar","d":"Üst avcı kaybolunca onun avladığı otçul tür hızla çoğalır."},{"t":"Bitki baskısı","a":"bitki azalır","d":"Aşırı çoğalan otçullar bitki örtüsünü ağır biçimde tüketir."},{"t":"Zincirleme etki","a":"tüm sistem etkilenir","d":"Bitki azalması toprağı, su kaynaklarını ve diğer türleri de etkiler; etki tüm besin ağına yayılır."}],"ans":"Üst düzey avcı yok olunca otçullar artar, bitki örtüsü tükenir ve etki besin ağı boyunca yayılır; bu yukarıdan aşağıya zincirleme etkiye trofik kaskad denir."},{"q":"Amensalizm ile rekabet arasındaki ayrımı etki yönü bakımından açıklayınız.","steps":[{"t":"Rekabet","a":"(− / −)","d":"Rekabette her iki tür de sınırlı kaynak yüzünden olumsuz etkilenir."},{"t":"Amensalizm","a":"(− / 0)","d":"Amensalizmde bir tür zarar görürken diğeri hiç etkilenmez."},{"t":"Ayrım noktası","a":"karşılıklılık","d":"Rekabette zarar karşılıklıdır; amensalizmde tek yönlüdür ve genelde kaynak yarışı değildir."}],"ans":"Rekabette zarar karşılıklıdır (− / −); amensalizmde ise zarar tek yönlüdür ve bir tür etkilenmez (− / 0); temel fark zararın karşılıklı olup olmamasıdır."}]}},"ureticiler":{"ilkokul":{"kolay":[{"q":"Üretici ne demektir? Bir örnek vererek açıkla.","steps":[{"t":"Kelimenin anlamı","a":"üreten canlı","d":"<b>Üretmek</b> bir şey yapmak demektir. Üretici de kendi besinini kendi yapan canlıdır."},{"t":"Örnek bul","a":"bitkiler","d":"Ağaçlar ve çimenler kendi besinini kendi yapar, bu yüzden üreticidir."}],"ans":"Üretici, kendi besinini kendisi yapan canlıdır; örneğin bitkiler üreticidir."},{"q":"Bitkiler besinini nereden alır?","steps":[{"t":"Hayvanlarla karşılaştır","a":"hayvan dışarıdan alır","d":"Hayvanlar besinini dışarıdan yiyerek alır, bitkiler ise almaz."},{"t":"Bitkinin yolu","a":"kendi yapar","d":"Bitkiler güneş ışığını kullanarak besinini kendi yapar."}],"ans":"Bitkiler besinini dışarıdan almaz, güneş ışığıyla kendi yapar."},{"q":"Üreticiler besin yapmak için en çok neye ihtiyaç duyar?","steps":[{"t":"Işık kaynağı","a":"Güneş","d":"Gökyüzündeki Güneş bitkilere ışık gönderen büyük kaynaktır."},{"t":"Bitkinin kullandığı","a":"güneş ışığı","d":"Bitkiler besin yapmak için güneş ışığını kullanır."}],"ans":"Üreticiler besin yapmak için güneş ışığına ihtiyaç duyar."},{"q":"Aşağıdaki canlılardan hangisi üreticidir: at, çimen, kedi?","steps":[{"t":"Hayvanları ele","a":"at ve kedi tüketir","d":"At ve kedi besinini dışarıdan yer, kendi yapamaz."},{"t":"Bitkiyi bul","a":"çimen","d":"Çimen bir bitkidir ve kendi besinini kendi yapar."}],"ans":"Çimen üreticidir çünkü kendi besinini kendisi yapar."},{"q":"Bir bahçedeki çiçek neden üretici sayılır?","steps":[{"t":"Çiçek bir bitkidir","a":"yeşildir","d":"Çiçekler yeşil yapraklı bitkilerdir."},{"t":"Besinini yapması","a":"kendi üretir","d":"Çiçek güneş ışığıyla kendi besinini ürettiği için üreticidir."}],"ans":"Çiçek bir bitki olup kendi besinini kendi ürettiği için üretici sayılır."}],"zor":[{"q":"Üreticiler olmasaydı ormandaki tavşanlar besinini nereden bulurdu?","steps":[{"t":"Tavşanın besini","a":"bitki yer","d":"Tavşanlar ot ve yaprak gibi bitkilerle beslenir."},{"t":"Üretici olmazsa","a":"bitki olmaz","d":"Üretici bitkiler olmasa ot ve yaprak da olmazdı."},{"t":"Sonuç","a":"besin bulamaz","d":"Yiyecek bitki kalmayınca tavşanlar aç kalırdı."}],"ans":"Üreticiler olmasaydı bitki kalmaz, otla beslenen tavşanlar besin bulamazdı."},{"q":"Bir bitkiyi karanlık bir kutuya koyarsak neden besin yapamaz?","steps":[{"t":"Bitkinin ihtiyacı","a":"ışık","d":"Bitki besin yapmak için güneş ışığına ihtiyaç duyar."},{"t":"Kutuda durum","a":"ışık yok","d":"Karanlık kutuda güneş ışığı olmadığı için bitki ışık alamaz."},{"t":"Sonuç","a":"besin yapamaz","d":"Işık olmayınca bitki kendi besinini yapamaz."}],"ans":"Karanlıkta güneş ışığı olmadığı için bitki kendi besinini yapamaz."},{"q":"Neden üreticilere ekosistemin 'temeli' denir?","steps":[{"t":"Üreticinin işi","a":"besin yapar","d":"Üreticiler besin üreten ilk canlılardır."},{"t":"Diğerlerinin bağlılığı","a":"hepsi bitkiye muhtaç","d":"Otçul hayvanlar bitkiyi, etçiller de o hayvanları yer."},{"t":"Sonuç","a":"besin oradan başlar","d":"Tüm canlıların besini en başta üreticilerden geldiği için temel onlardır."}],"ans":"Tüm canlıların besini en başta üreticilerden başladığı için üreticiler ekosistemin temelidir."},{"q":"Bir bitki büyürken topraktan ve havadan neler alarak besin yapar?","steps":[{"t":"Topraktan","a":"su","d":"Bitki kökleriyle topraktaki suyu emer."},{"t":"Havadan","a":"hava (gaz)","d":"Yapraklar havadaki gazı içeri alır."},{"t":"Birleştirme","a":"ışıkla besin","d":"Bitki su ile havayı güneş ışığıyla birleştirerek besin yapar."}],"ans":"Bitki topraktan su, havadan gaz alıp güneş ışığıyla bunları birleştirerek besin yapar."},{"q":"Denizdeki yeşil su yosunları da üretici midir? Neden?","steps":[{"t":"Renklerine bak","a":"yeşildir","d":"Su yosunları da bitkiler gibi yeşil renklidir."},{"t":"Besinini yapması","a":"kendi yapar","d":"Yeşil oldukları için güneş ışığıyla kendi besinini yapabilirler."},{"t":"Sonuç","a":"üreticidir","d":"Kendi besinini yaptıkları için su yosunları da üreticidir."}],"ans":"Evet; yeşil su yosunları da güneş ışığıyla kendi besinini yaptığı için üreticidir."}]},"ortaokul":{"kolay":[{"q":"Üreticilere bilimsel olarak başka hangi ad verilir?","steps":[{"t":"Kendi besinini yapma","a":"oto = kendi","d":"Kendi besinini üreten canlılara <b>ototrof</b> denir."},{"t":"Anlamı","a":"ototrof","d":"Ototrof 'kendi beslenen' demektir, yani üretici ile aynı anlama gelir."}],"ans":"Üreticilere bilimsel olarak ototrof (kendibeslek) adı verilir."},{"q":"Üreticiler besinini hangi olayla üretir?","steps":[{"t":"Işık kullanımı","a":"fotosentez","d":"Bitkiler güneş ışığını kullanarak fotosentez yapar."},{"t":"Sonuç","a":"besin üretilir","d":"Fotosentezle inorganik maddelerden organik besin üretilir."}],"ans":"Üreticiler besinini fotosentez olayıyla üretir."},{"q":"Bitki dışında fotosentez yapan üretici canlılara iki örnek veriniz.","steps":[{"t":"Sudaki üreticiler","a":"algler","d":"Su yosunları (algler) klorofil içerir ve fotosentez yapar."},{"t":"Bakteri grubu","a":"siyanobakteriler","d":"Mavi-yeşil bakteriler olan siyanobakteriler de fotosentez yapar."}],"ans":"Bitkilerin yanında algler (su yosunları) ve siyanobakteriler de üretici canlılardır."},{"q":"Üreticiler ekosisteme hangi enerjiyi sokar?","steps":[{"t":"Enerji kaynağı","a":"Güneş","d":"Üreticiler Güneş'ten gelen ışık enerjisini yakalar."},{"t":"Sonuç","a":"güneş enerjisi","d":"Bu güneş enerjisini besine çevirerek ekosisteme sokarlar."}],"ans":"Üreticiler, Güneş'ten gelen enerjiyi besine çevirerek ekosisteme sokar."},{"q":"Besin zincirinde üreticiler hangi sırada yer alır?","steps":[{"t":"Zincirin başı","a":"ilk halka","d":"Besin zinciri her zaman bir üreticiyle başlar."},{"t":"Sonraki halkalar","a":"tüketiciler","d":"Üreticiden sonra onunla beslenen tüketiciler gelir."}],"ans":"Üreticiler besin zincirinin ilk (en baştaki) halkasında yer alır."}],"zor":[{"q":"Ototrof ve heterotrof canlıları beslenme bakımından karşılaştırınız.","steps":[{"t":"Ototrof","a":"kendi üretir","d":"Ototroflar (üreticiler) inorganik maddeden kendi besinini üretir."},{"t":"Heterotrof","a":"dışarıdan alır","d":"Heterotroflar (tüketiciler) besinini hazır olarak dışarıdan alır."},{"t":"Sonuç","a":"üretme yeteneği","d":"Temel fark, ototrofun besin üretebilmesi, heterotrofun üretememesidir."}],"ans":"Ototroflar besinini kendi üretir, heterotroflar ise hazır besini dışarıdan alır."},{"q":"Üreticiler fotosentezde hangi ham maddeleri kullanıp hangi besini üretir?","steps":[{"t":"Ham maddeler","a":"su ve karbondioksit","d":"Üretici topraktan su (H₂O), havadan karbondioksit (CO₂) alır."},{"t":"Enerji","a":"güneş ışığı","d":"Bu maddeleri birleştirmek için güneş ışığı enerjisini kullanır."},{"t":"Üretilen besin","a":"glikoz","d":"Sonuçta glikoz adlı şeker (organik besin) ve oksijen oluşur."}],"ans":"Üreticiler su ve karbondioksiti güneş ışığıyla birleştirip glikoz (besin) ve oksijen üretir."},{"q":"Bazı bakteriler güneş ışığı olmadan nasıl besin üretebilir?","steps":[{"t":"Enerji sorunu","a":"ışık yok","d":"Yer altında veya derin sularda yaşayan bazı bakteriye güneş ışığı ulaşmaz."},{"t":"Farklı kaynak","a":"kimyasal enerji","d":"Bu bakteriler inorganik maddelerin kimyasal enerjisini kullanır."},{"t":"Olayın adı","a":"kemosentez","d":"Işık yerine kimyasal enerjiyle besin üretmeye kemosentez denir."}],"ans":"Bazı bakteriler ışık yerine inorganik maddelerin kimyasal enerjisini kullanarak kemosentezle besin üretir."},{"q":"Üreticiler azalırsa bir ekosistemdeki tüketiciler neden etkilenir?","steps":[{"t":"Tüketicinin bağlılığı","a":"besinini üreticiden alır","d":"Otçullar doğrudan, etçiller dolaylı olarak üreticiye bağlıdır."},{"t":"Üretici azalınca","a":"besin azalır","d":"Üretici azalırsa zincire giren besin ve enerji de azalır."},{"t":"Sonuç","a":"tüketici azalır","d":"Yeterli besin bulamayan tüketicilerin sayısı da düşer."}],"ans":"Üreticiler ekosisteme besin ve enerji sağladığı için azalmaları, tüm tüketicilerin besinsiz kalıp azalmasına yol açar."},{"q":"Bir göl ekosisteminde üreticilerin görevi nedir?","steps":[{"t":"Gölün üreticileri","a":"algler ve su bitkileri","d":"Gölde fotosentez yapan algler ve su bitkileri üreticidir."},{"t":"Yaptığı iş","a":"besin ve oksijen","d":"Bunlar güneş ışığıyla besin üretir ve suya oksijen verir."},{"t":"Sonuç","a":"yaşamı destekler","d":"Ürettikleri besin ve oksijen, göldeki balık ve diğer canlıları yaşatır."}],"ans":"Gölde algler ve su bitkileri üreticidir; besin ve oksijen üreterek tüm su canlılarının yaşamını destekler."}]},"lise":{"kolay":[{"q":"Üretici (ototrof) kavramını bilimsel olarak tanımlayınız.","steps":[{"t":"Madde dönüşümü","a":"inorganikten organik","d":"Üreticiler inorganik maddelerden (CO₂, H₂O) organik besin sentezler."},{"t":"Enerji kaynağı","a":"ışık veya kimyasal","d":"Bu sentez için enerjiyi ışıktan veya inorganik kimyasal tepkimelerden alır."}],"ans":"Üretici (ototrof), dış enerji kaynağı kullanarak inorganik maddelerden kendi organik besinini sentezleyen canlıdır."},{"q":"Ototroflar enerji kaynağına göre kaç gruba ayrılır?","steps":[{"t":"Birinci grup","a":"fotoototrof","d":"Enerjiyi ışıktan alan ototroflara fotoototrof denir (bitki, alg)."},{"t":"İkinci grup","a":"kemoototrof","d":"Enerjiyi kimyasal tepkimeden alan ototroflara kemoototrof denir."}],"ans":"Ototroflar fotoototroflar (ışık enerjili) ve kemoototroflar (kimyasal enerjili) olmak üzere iki gruba ayrılır."},{"q":"Karasal ekosistemlerin başlıca üreticileri hangileridir?","steps":[{"t":"Egemen grup","a":"yeşil bitkiler","d":"Karada üretimin büyük kısmını yeşil bitkiler (otlar, ağaçlar) yapar."},{"t":"Ortak özellik","a":"klorofil","d":"Bu bitkiler klorofil içerip fotosentez yapar."}],"ans":"Karasal ekosistemlerde başlıca üreticiler klorofil taşıyan yeşil bitkilerdir."},{"q":"Sucul ekosistemlerin başlıca üreticileri hangileridir?","steps":[{"t":"Mikroskobik üretici","a":"fitoplankton","d":"Sularda fotosentez yapan mikroskobik algler (fitoplankton) baskındır."},{"t":"Önemi","a":"oksijenin çoğu","d":"Fitoplankton, atmosferik oksijenin büyük bir bölümünü üretir."}],"ans":"Sucul ekosistemlerde başlıca üreticiler fitoplankton (mikroskobik algler) ve su bitkileridir."},{"q":"Üreticiler bir ekosisteme enerjiyi hangi biçimde sokar?","steps":[{"t":"Yakalanan enerji","a":"ışık enerjisi","d":"Üreticiler güneşin ışık (radyant) enerjisini yakalar."},{"t":"Dönüştürülen biçim","a":"kimyasal enerji","d":"Bu enerji organik moleküllerin bağlarında kimyasal enerjiye çevrilir."}],"ans":"Üreticiler güneşin ışık enerjisini organik moleküllerdeki kimyasal enerjiye çevirerek ekosisteme sokar."},{"q":"Fotosentetik üreticiler hangi pigment sayesinde ışığı soğurur?","steps":[{"t":"Ana pigment","a":"klorofil","d":"Fotosentezi yürüten temel pigment klorofildir."},{"t":"Görevi","a":"ışığı yakalar","d":"Klorofil, güneş ışığını soğurarak enerjiyi sürece aktarır."}],"ans":"Fotosentetik üreticiler ışığı esas olarak klorofil pigmenti sayesinde soğurur."},{"q":"Kemosentetik bakteriler enerjiyi nereden sağlar?","steps":[{"t":"Işık değil","a":"ışık kullanmaz","d":"Kemosentetik bakteriler enerji için güneş ışığını kullanmaz."},{"t":"Gerçek kaynak","a":"inorganik oksidasyon","d":"Enerjiyi amonyak, kükürt, demir gibi inorganik maddelerin oksidasyonundan alır."}],"ans":"Kemosentetik bakteriler enerjiyi inorganik maddelerin (amonyak, kükürt vb.) oksidasyonundan sağlar."},{"q":"Brüt birincil üretim (GPP) nedir?","steps":[{"t":"Anlamı","a":"toplam organik üretim","d":"GPP, üreticilerin fotosentezle ürettiği toplam organik madde miktarıdır."},{"t":"Kapsamı","a":"solunum dahil","d":"Bu değer, bitkinin kendi solunumunda harcadığı kısmı da içerir."}],"ans":"Brüt birincil üretim (GPP), üreticilerin fotosentezle ürettiği toplam organik madde miktarıdır."},{"q":"Net birincil üretim (NPP) ne anlama gelir?","steps":[{"t":"Brüt üretim","a":"GPP","d":"Önce üreticilerin ürettiği toplam organik madde (GPP) alınır."},{"t":"Solunum kaybı","a":"GPP − solunum","d":"Bitkinin solunumda harcadığı kısım GPP'den çıkarılır."}],"ans":"Net birincil üretim (NPP), brüt üretimden bitkinin solunum harcaması çıkarıldığında ekosisteme kalan organik madde miktarıdır (NPP = GPP − solunum)."},{"q":"Neden besin zincirleri her zaman bir üreticiyle başlar?","steps":[{"t":"Enerji girişi","a":"üretici sağlar","d":"Ekosisteme enerji ancak üreticiler aracılığıyla girer."},{"t":"Tüketicinin durumu","a":"hazır besin gerek","d":"Tüketiciler besin üretemez, hazır organik besine ihtiyaç duyar."}],"ans":"Ekosisteme enerji ve organik besin girişini yalnızca üreticiler sağladığı için besin zincirleri her zaman bir üreticiyle başlar."},{"q":"Siyanobakterilerin üretici olarak önemi nedir?","steps":[{"t":"Yaptığı iş","a":"fotosentez","d":"Siyanobakteriler klorofil içerip oksijenli fotosentez yapan prokaryotlardır."},{"t":"Katkısı","a":"oksijen ve besin","d":"Sucul ortamda bol besin ve oksijen üreterek ekosistemi besler."}],"ans":"Siyanobakteriler oksijenli fotosentez yapan üreticilerdir; sularda önemli miktarda besin ve oksijen sağlar."},{"q":"Üreticilerin enerji dönüşümündeki rolü neden 'kritik' kabul edilir?","steps":[{"t":"Tek giriş kapısı","a":"enerjiyi bağlar","d":"Güneş enerjisi ekosisteme yalnızca üreticiler üzerinden girer."},{"t":"Bağımlılık","a":"hepsi muhtaç","d":"Tüm tüketici ve ayrıştırıcılar dolaylı olarak bu enerjiye bağımlıdır."}],"ans":"Üreticiler güneş enerjisinin ekosisteme tek giriş kapısı olduğu ve tüm canlılar buna bağlı olduğu için kritik kabul edilir."},{"q":"Bir üretici ürettiği glikozu kendi yaşamı için nasıl kullanır?","steps":[{"t":"Enerji elde etme","a":"solunum","d":"Üretici glikozu hücresel solunumda parçalayarak ATP (enerji) üretir."},{"t":"Yapı ve depo","a":"nişasta, selüloz","d":"Fazla glikozu nişasta olarak depolar veya selüloz olarak yapıya katar."}],"ans":"Üretici ürettiği glikozu solunumda enerji için kullanır, fazlasını nişasta olarak depolar ve selüloz yapımında kullanır."},{"q":"Üreticiler ile ayrıştırıcılar arasındaki temel fark nedir?","steps":[{"t":"Üretici","a":"organik üretir","d":"Üreticiler inorganik maddeden organik besin sentezler."},{"t":"Ayrıştırıcı","a":"organik parçalar","d":"Ayrıştırıcılar ölü organik maddeyi parçalayıp inorganiğe çevirir."}],"ans":"Üreticiler inorganikten organik üretirken, ayrıştırıcılar organik maddeyi parçalayıp inorganiğe döndürür; beslenme yönleri terstir."},{"q":"Üreticilerin oksijen üretimindeki rolü nedir?","steps":[{"t":"Fotosentezin yan ürünü","a":"oksijen","d":"Fotosentezde suyun parçalanmasıyla oksijen açığa çıkar."},{"t":"Atmosfere katkı","a":"O₂ kaynağı","d":"Bu oksijen atmosfere verilir ve aerobik canlıların solunumunu sağlar."}],"ans":"Üreticiler fotosentez sırasında oksijen üreterek atmosferik oksijenin ana kaynağını oluşturur ve aerobik yaşamı destekler."}],"zor":[{"q":"Fotoototrof ve kemoototrof üreticileri enerji ve karbon kaynağı açısından karşılaştırınız.","steps":[{"t":"Karbon kaynağı","a":"ikisinde de CO₂","d":"Her iki grup da karbon kaynağı olarak inorganik CO₂ kullanır."},{"t":"Enerji farkı","a":"ışık vs kimyasal","d":"Fotoototrof enerjiyi ışıktan, kemoototrof inorganik oksidasyondan alır."},{"t":"Sonuç","a":"aynı amaç","d":"İkisi de aynı şekilde inorganikten organik besin üretir, yalnız enerji kaynakları farklıdır."}],"ans":"Her ikisi de karbonu CO₂'den alıp organik besin üretir; fotoototroflar ışık enerjisi, kemoototroflar inorganik maddelerin kimyasal enerjisini kullanır."},{"q":"Hidrotermal bacalardaki ekosistemler güneş ışığı olmadan nasıl varlığını sürdürür?","steps":[{"t":"Işık yokluğu","a":"derin okyanus","d":"Bu bacalar güneş ışığının ulaşamadığı okyanus derinliklerindedir."},{"t":"Üretici tipi","a":"kemosentetik bakteri","d":"Hidrojen sülfürü (H₂S) oksitleyen kemosentetik bakteriler besin üretir."},{"t":"Zincirin temeli","a":"kemosentez","d":"Bu bakteriler üretici olup tüm bacanın besin zincirini başlatır."}],"ans":"Hidrotermal bacalarda kemosentetik bakteriler hidrojen sülfürü oksitleyerek besin üretir; bu üreticiler ekosistemin güneşsiz besin zincirini başlatır."},{"q":"Net birincil üretim (NPP) ile ekosistemin taşıma kapasitesi arasındaki ilişkiyi açıklayınız.","steps":[{"t":"NPP anlamı","a":"tüketiciye kalan enerji","d":"NPP, üreticilerden tüketicilere aktarılabilecek organik madde miktarıdır."},{"t":"Besin tabanı","a":"enerji kaynağı","d":"Yüksek NPP, üst basamaklara daha çok enerji aktarılması demektir."},{"t":"Sonuç","a":"daha çok canlı","d":"Daha fazla enerji, ekosistemin daha çok tüketici barındırabilmesini sağlar."}],"ans":"NPP üreticilerden üst basamaklara aktarılabilen enerjiyi belirlediğinden, yüksek NPP ekosistemin daha fazla tüketici barındırabilmesi yani taşıma kapasitesinin artması anlamına gelir."},{"q":"Bir orman ekosisteminde GPP = 20.000 kJ/m²·yıl ve bitki solunumu 8.000 kJ/m²·yıl ise NPP kaç kJ/m²·yıl olur?","steps":[{"t":"Formül","a":"NPP = GPP − solunum","d":"Net üretim, brüt üretimden bitkinin kendi solunum harcaması çıkarılarak bulunur."},{"t":"Değerleri yerleştir","a":"20.000 − 8.000","d":"Verilen değerler formüle konur: 20.000 kJ − 8.000 kJ."},{"t":"Sonucu hesapla","a":"12.000 kJ","d":"Çıkarma yapıldığında 12.000 kJ/m²·yıl elde edilir."}],"ans":"NPP = 20.000 − 8.000 = 12.000 kJ/m²·yıl olur."},{"q":"Üreticilerin biyosferdeki karbon döngüsündeki rolünü açıklayınız.","steps":[{"t":"CO₂ tutulumu","a":"atmosferden çeker","d":"Üreticiler fotosentezle atmosferik CO₂'yi organik karbona bağlar."},{"t":"Aktarım","a":"besin zinciri","d":"Bu organik karbon beslenmeyle tüketicilere ve ayrıştırıcılara aktarılır."},{"t":"Geri dönüş","a":"solunum/ayrışma","d":"Solunum ve ayrışmayla karbon yeniden CO₂ olarak atmosfere döner."}],"ans":"Üreticiler atmosferik CO₂'yi organik karbona bağlayarak karbon döngüsünün ekosisteme giriş halkasını oluşturur; bu karbon zincir boyunca dolaşıp solunum ve ayrışmayla atmosfere döner."},{"q":"Enerji piramidinde üreticilerin neden en geniş tabanı oluşturduğunu açıklayınız.","steps":[{"t":"Enerji girişi","a":"en çok enerji üreticide","d":"Ekosisteme giren enerjinin tamamı önce üreticilerde toplanır."},{"t":"Aktarım kaybı","a":"%10 kuralı","d":"Bir basamaktan diğerine enerjinin yaklaşık %10'u aktarılır, gerisi ısı olarak kaybolur."},{"t":"Sonuç","a":"taban geniş","d":"En çok enerji ve biyokütle üreticide olduğu için piramidin tabanını oluştururlar."}],"ans":"Ekosisteme giren enerji önce üreticilerde toplandığı ve üst basamaklara yalnızca yaklaşık %10'u aktarıldığı için üreticiler enerji piramidinin en geniş tabanını oluşturur."},{"q":"Kemosentez ve fotosentez yapan üreticileri tepkimenin enerji kaynağı ve ürünleri açısından karşılaştırınız.","steps":[{"t":"Fotosentez","a":"ışık enerjisi","d":"Fotosentez yapan üreticiler enerjiyi ışıktan alır, ürün glikoz ve oksijendir."},{"t":"Kemosentez","a":"kimyasal enerji","d":"Kemosentetik bakteriler enerjiyi inorganik maddenin oksidasyonundan alır, organik madde üretir."},{"t":"Ortak nokta","a":"ototrof üretim","d":"İkisi de inorganik CO₂'den organik besin sentezleyen ototrof süreçtir."}],"ans":"İkisi de CO₂'den organik besin üreten ototrof süreçtir; fotosentez ışık enerjisi kullanıp O₂ üretirken, kemosentez inorganik oksidasyon enerjisini kullanır."},{"q":"Fitoplanktonun küresel oksijen üretimi ve iklim açısından önemini açıklayınız.","steps":[{"t":"Üretim kapasitesi","a":"oksijenin yarısı","d":"Okyanus fitoplanktonu, atmosferik oksijenin yaklaşık yarısını üretir."},{"t":"Karbon yutağı","a":"CO₂ tutar","d":"Fotosentezle büyük miktarda CO₂'yi organik karbona bağlar."},{"t":"İklim etkisi","a":"ısınmayı yavaşlatır","d":"CO₂'yi tutarak atmosferdeki sera gazını azaltır, iklimi etkiler."}],"ans":"Fitoplankton atmosferik oksijenin yaklaşık yarısını üretir ve fotosentezle büyük miktarda CO₂'yi bağlayarak hem küresel oksijen dengesinde hem de iklimin düzenlenmesinde kritik rol oynar."},{"q":"Üretici biyokütlesinin azalması bir ekosistemde neden zincirleme çöküşe yol açar?","steps":[{"t":"Enerji girişi azalır","a":"daha az besin","d":"Üretici azalınca ekosisteme giren toplam enerji ve organik besin düşer."},{"t":"Tüketiciler etkilenir","a":"birincil tüketici azalır","d":"Az besin nedeniyle önce otçullar, sonra onlarla beslenen etçiller azalır."},{"t":"Zincirleme etki","a":"tüm seviyeler çöker","d":"Her basamak bir altına bağlı olduğundan etki yukarı doğru zincirleme yayılır."}],"ans":"Üreticiler ekosisteme tek enerji girişini sağladığı için biyokütleleri azalınca giren besin düşer; bu, önce otçulları sonra üst tüketicileri etkileyerek tüm basamakların zincirleme çöküşüne yol açar."},{"q":"Büyük Oksijenlenme Olayı'nda üreticilerin rolünü açıklayınız.","steps":[{"t":"İlk üreticiler","a":"siyanobakteriler","d":"Erken dönemde siyanobakteriler oksijenli fotosentez yapan ilk üreticilerdi."},{"t":"Oksijen birikimi","a":"atmosferde O₂","d":"Ürettikleri oksijen okyanusu doyurduktan sonra atmosferde birikmeye başladı."},{"t":"Sonuç","a":"aerobik yaşam","d":"Bu oksijen artışı oksijenli solunum yapan canlıların evrimini olanaklı kıldı."}],"ans":"Oksijenli fotosentez yapan siyanobakteriler üretici olarak atmosferi oksijenle zenginleştirerek Büyük Oksijenlenme Olayı'nı başlatmış ve aerobik yaşamın gelişmesini sağlamıştır."},{"q":"Bir tarım alanında NPP'nin yüksek olması verim açısından neden istenir?","steps":[{"t":"NPP anlamı","a":"depolanan organik madde","d":"NPP, üreticide net olarak biriken ve kullanılabilen organik madde miktarıdır."},{"t":"Üründe karşılığı","a":"biyokütle artışı","d":"Yüksek NPP, bitkide daha çok biyokütle (tane, yaprak, meyve) birikmesi demektir."},{"t":"Sonuç","a":"yüksek verim","d":"Daha fazla biriken organik madde, hasat edilebilir ürün veriminin artması anlamına gelir."}],"ans":"NPP üreticide net biriken organik maddeyi gösterdiğinden, yüksek NPP daha çok biyokütle birikimi yani daha yüksek tarımsal verim anlamına geldiği için istenir."},{"q":"Üreticilerde fotosentez hızını sınırlayan faktörler birincil üretimi nasıl etkiler?","steps":[{"t":"Sınırlayıcı faktörler","a":"ışık, CO₂, su, sıcaklık","d":"Fotosentez hızı ışık, CO₂, su ve sıcaklık gibi faktörlerle sınırlanır."},{"t":"Etkisi","a":"GPP belirler","d":"En kıt faktör fotosentez hızını, dolayısıyla brüt üretimi (GPP) belirler."},{"t":"Sonuç","a":"NPP de değişir","d":"GPP düşünce ekosisteme aktarılan net üretim (NPP) de azalır."}],"ans":"Işık, CO₂, su ve sıcaklık gibi sınırlayıcı faktörler fotosentez hızını belirler; en kıt faktör brüt üretimi (GPP) sınırladığında ekosisteme aktarılan net birincil üretim de azalır."},{"q":"Bir ototrofun 'birincil üretici' olarak adlandırılmasının ekolojik anlamı nedir?","steps":[{"t":"Birincil sözcüğü","a":"ilk üretim","d":"'Birincil' üretim, ekosistemdeki ilk ve temel organik madde üretimini ifade eder."},{"t":"Trofik konum","a":"birinci basamak","d":"Birincil üretici, besin zincirinin birinci trofik basamağında yer alır."},{"t":"Sonuç","a":"enerjinin kaynağı","d":"Üst basamakların tüm enerjisi bu birincil üretimden türer."}],"ans":"Bir ototrofun 'birincil üretici' denmesi, ekosistemde ilk organik madde üretimini gerçekleştirip besin zincirinin birinci trofik basamağını oluşturması ve üst basamakların enerjisinin temelini sağlaması anlamına gelir."},{"q":"Klorofil dışındaki yardımcı pigmentlerin üreticilerin üretim verimine katkısını açıklayınız.","steps":[{"t":"Yardımcı pigmentler","a":"karotenoit, fikobilin","d":"Üreticiler karotenoit ve fikobilin gibi yardımcı pigmentler de taşır."},{"t":"İşlevi","a":"farklı dalga boyu","d":"Bu pigmentler klorofilin soğuramadığı dalga boylarındaki ışığı yakalar."},{"t":"Sonuç","a":"daha çok enerji","d":"Yakalanan ek ışık enerjisi klorofile aktarılır, fotosentez verimi artar."}],"ans":"Karotenoit ve fikobilin gibi yardımcı pigmentler klorofilin yakalayamadığı dalga boylarındaki ışığı soğurup enerjiyi klorofile aktararak üreticilerin ışık kullanımını ve birincil üretim verimini artırır."},{"q":"Üreticiler olmasaydı Dünya'da enerji akışının neden duracağını termodinamik açıdan açıklayınız.","steps":[{"t":"Enerji girişi","a":"güneşi bağlar","d":"Üreticiler güneşin ışık enerjisini canlıların kullanabileceği kimyasal enerjiye çevirir."},{"t":"Tek yönlü akış","a":"enerji ısı olarak kaybolur","d":"Enerji her basamakta bir kısmı ısıya dönüşerek tek yönlü akar ve geri dönmez."},{"t":"Sonuç","a":"giriş kesilir","d":"Üretici olmadan yeni enerji girişi olmaz, mevcut enerji ısı olarak tükenir ve akış durur."}],"ans":"Enerji ekosistemde tek yönlü akar ve her basamakta bir kısmı ısı olarak kaybolduğundan sürekli yeni giriş gerekir; üreticiler bu girişi sağlayan tek halka olduğu için onlar olmadan enerji akışı durur ve yaşam sürdürülemez."}]}}};
